 FUNCTION GET_LISTA_PARAMETOS(P_SQL CLOB) RETURN VARCHAR2 IS
    V_SQL CLOB;
    V_POSI NUMBER(22);
    V_POSF NUMBER(22);
    V_RETORNO VARCHAR2(1000);
    V_PARAM VARCHAR2(100);
    V_VIRGULA VARCHAR2(1);
  BEGIN
    V_SQL     := P_SQL;
    V_RETORNO := '';
    V_VIRGULA := '';
    LOOP
      V_POSI := INSTR(V_SQL,':');
      IF V_POSI = 0 THEN
        EXIT;
      END IF;
      V_POSI     := V_POSI + 1;
      V_POSF     := INSTR(V_SQL,' ',V_POSI);
      V_PARAM    := SUBSTR(V_SQL,V_POSI,V_POSF - V_POSI);
      V_PARAM    := REPLACE(V_PARAM,CHR(10),'');
    V_PARAM    := REPLACE(V_PARAM,CHR(13),'');
      V_PARAM    := REPLACE(V_PARAM,')','');
      V_PARAM    := REPLACE(V_PARAM,',','');
      V_PARAM    := TRIM(V_PARAM);

      IF NOT V_PARAM LIKE 'MI:SS%' THEN
        V_RETORNO  := V_RETORNO || V_VIRGULA || V_PARAM;
        V_VIRGULA  := ',';
      END IF;

      V_POSF     := V_POSF + 1;
      V_SQL      := SUBSTR(V_SQL,V_POSF,LENGTH(V_SQL));
    END LOOP;

    RETURN TRIM(V_RETORNO);
  END;

  PROCEDURE OPEN_CURSOR_FOR_V_SQL IS
    VLISTA_PARAMETROS VARCHAR2(1000);
  BEGIN
    VLISTA_PARAMETROS := GET_LISTA_PARAMETOS(V_SQL);

    CASE VLISTA_PARAMETROS
      WHEN 'DATAINI,DATAFIM'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI2,DATAFIM2'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI2,DATAFIM2'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM, P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI3,DATAFIM3'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM;
      WHEN 'DATAFIM3,DATAFIM3,DATAINI,DATAFIM,DATAINI2,DATAFIM2'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAFIM,P_DATAFIM,P_DATAFIM,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI,DATAFIM'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI,DATAFIM,DATAINI2,DATAFIM2'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI2,DATAFIM2,DATAINI3,DATAFIM3'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI2,DATAFIM2,DATAINI3,DATAFIM3'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI3,DATAFIM3'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI3,DATAFIM3,DATAINI6,DATAFIM6'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,VLVENDA,VLVENDA'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,VALOR_VENDA,VALOR_VENDA;
      WHEN 'DATAINI,DATAFIM,DATAINI3,DATAFIM3,VLVENDA,VLVENDA'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,VALOR_VENDA,VALOR_VENDA;
      WHEN 'DATAINI2,DATAFIM2,DATAINI3,DATAFIM3,DATAINI3,DATAFIM3'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI3,DATAFIM3,DATAINI3,DATAFIM3'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI,DATAFIM,DATAINI3,DATAFIM3,DATAINI3,DATAFIM3'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI,DATAFIM,DATAINI,DATAFIM,DATAINI,DATAFIM'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI2,DATAFIM2,DATAINI3,DATAFIM3,DATAINI3,DATAFIM3'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI,DATAFIM,DATAINI2,DATAFIM2,DATAINI3,DATAFIM3,DATAINI3,DATAFIM3'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
--      WHEN 'DATAINI,DATAFIM,DATAINI2,DATAFIM2,DATAINI3,DATAFIM3,DATAINI3,DATAFIM3'
  --      THEN OPEN L_CURSOR FOR to_char(V_SQL) USING P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAFIM,DATAFIM,DATAINI,DATAFIM,DATAINI,DATAFIM,DATAINI,DATAFIM'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAFIM,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAFIM3,DATAFIM3,DATAINI2,DATAFIM2,DATAINI3,DATAFIM3,DATAINI4,DATAFIM4'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAFIM,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;
      WHEN 'DATAFIM3,DATAFIM3,DATAINI,DATAFIM,DATAINI2,DATAFIM2,DATAINI3,DATAFIM3,DATAINI4,DATAFIM4'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAFIM,P_DATAFIM,P_DATAFIM,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM,P_DATAINI,P_DATAFIM;        
      WHEN 'DATAINI,DATAFIM,DATAINI2,DATAFIM2,DATAINI,DATAFIM'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM, P_DATAINI,P_DATAFIM, P_DATAINI, P_DATAFIM;
      WHEN 'DATAINI,DATAFIM,DATAINI2,DATAFIM2,DATAINI3,DATAFIM3,DATAINI,DATAFIM'
        THEN OPEN L_CURSOR FOR TO_CHAR(V_SQL) USING P_DATAINI,P_DATAFIM, P_DATAINI,P_DATAFIM, P_DATAINI, P_DATAINI, P_DATAINI,P_DATAFIM;         
      ELSE
        RAISE_APPLICATION_ERROR(-20000,'ERRO AO ABRIR O CURSOR, LISTA DE PARAMETROS: ''' || VLISTA_PARAMETROS || '''');
    END CASE;
  END;

--Habilitar debug
--PRAGMA AUTONOMOUS_TRANSACTION;
BEGIN
 V_SQL := '';
 --V_DESDCARTAOFECHCARGA := '';

 IF P_TIPOVENDA10 = 0
   THEN
    V_SQL_CONDVENDA := ' NVL(VENDAS.CONDVENDA, -1) IN (1, 5, -1, 7, 9, 11, 14) ';
    V_SQL_CODFISCAL := ' VENDAS.CODFISCAL NOT IN (522, 622, 722, 532, 632, 732)';
   ELSE
    V_SQL_CONDVENDA := ' NVL(VENDAS.CONDVENDA, -1) IN (1, 5, -1, 7, 9, 11, 14, 10)';
    V_SQL_CODFISCAL := '  VENDAS.CODFISCAL NOT IN (532, 632, 732) ';
   END IF;

  -- RETORNA O SQL DA VIEW: VIEW_VENDAS_RESUMO_FATURAMENTO
  SELECT F_GETSQL_VIEW_FATURAMENTO(P_DATAINI,
                                   P_DATAFIM,
                                   P_CODFILIAL,
                                   V_SQL_CONDVENDA,
                                   V_SQL_CODFISCAL)
  INTO V_SQL_GERAL
  FROM DUAL;

    /*
    Trecho transforma a string de filtro de filial a ser passada para as novas
    funções abaixo do mesmo modo como é passada para essa função pela rotina.
    */
    IF P_CODFILIAL IS NULL THEN
      VSQLCODFILIAL := P_CODFILIAL;
    ELSE
      VSQLCODFILIAL := REPLACE(P_CODFILIAL, '''', '');
      VSQLCODFILIAL := REPLACE(P_CODFILIAL, ', ', ''', ''');
      VSQLCODFILIAL := REPLACE(P_CODFILIAL, ',', ''',''');
      VSQLCODFILIAL := '''''' || VSQLCODFILIAL || '''''';

      IF INSTR(P_CODFILIAL, '''') <= 0 THEN
        VSQLCODFILIAL := '''' || VSQLCODFILIAL || '''';
      END IF;
    END IF;

 -- retorna TABLE da view: VIEW_DEVOL_RESUMO_FATURAMENTO
  V_SQL_VIEW_DEVOL := 'TABLE(CAST(RET_TABLE_VIEW_DEVOLUCAO(TO_DATE( ''' || TO_CHAR(P_DATAINI, 'DD/MM/YYYY') || ''' , ''DD/MM/YYYY''),
                               TO_DATE( ''' || TO_CHAR(P_DATAFIM, 'DD/MM/YYYY') || ''' , ''DD/MM/YYYY''),
                               '||CASE WHEN NVL(P_CODFILIAL, '99') = '99' THEN 'NULL' ELSE VSQLCODFILIAL END||') AS TABELA_VIEW_DEVOLUCAO))';

 -- retorna TABLE da view: VIEW_DEVOL_RESUMO_FATURAVULSA
  V_SQL_VIEW_DEVOLAVULSA := 'TABLE(CAST(RET_TABLE_VIEW_DEVOLAVULSA(TO_DATE( ''' || TO_CHAR(P_DATAINI, 'DD/MM/YYYY') || ''' , ''DD/MM/YYYY''),
                                       TO_DATE( ''' || TO_CHAR(P_DATAFIM, 'DD/MM/YYYY') || ''' , ''DD/MM/YYYY''),
                                     '||CASE WHEN NVL(P_CODFILIAL, '99') = '99' THEN 'NULL' ELSE VSQLCODFILIAL END||') AS TABELA_VIEW_DEVOLAVULSA))';

  IF P_CONSIDERACOBRANCATITULOS = 1 THEN
    V_SQLTITULOS :=' (SELECT SUM(PCPREST.VALOR)
                        FROM PCPREST
                       WHERE CASE WHEN EXISTS (SELECT 1 FROM PCCOB WHERE PCPREST.CODCOB = PCCOB.CODCOB AND PCCOB.CARTAO = ''S'') AND PCPREST.VPAGO = 0 THEN ''DESD'' ELSE PCPREST.CODCOB END NOT IN (''BNF'', ''BNFT'', ''BNFR'', ''BNFN'', ''BNTR'',''BNRP'', ''DEVT'', ''DEVP'', ''DESD'')
                         AND PCPREST.DTCANCEL IS NULL
                         AND PCPREST.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA) ';
  ELSE
    V_SQLTITULOS := ' (PCNFSAID.VLTOTGER) ';
  END IF;

 IF P_CONSIDTIPOFJ = 0 AND P_CONSIDCONSUMIDORFINAL = 0 AND P_CONSIDISENTO = 0 AND P_CONSIDISENTA = 0
 THEN
  VERIFICAPF := FALSE;
 ELSE
  VERIFICAPF := TRUE;
 END IF;

 SELECT DESDCARTAOFECHCARGA INTO V_DESDCARTAOFECHCARGA FROM PCCONSUM;

 IF P_CONSIDERA_APLIC_VERBA = 'S' THEN
   V_SUBSELECTVERBA := ' (SELECT NVL(SUM(NVL(A.VLVERBACMV,0)* NVL(I.QT,0)), 0)  FROM PCAPLICVERBAPEDI A, PCPEDI I WHERE A.NUMPED  = VENDAS.NUMPED AND   A.CODPROD = VENDAS.CODPROD AND A.NUMPED = I.NUMPED AND A.CODPROD = I.CODPROD AND I.NUMPED = VENDAS.NUMPED AND I.CODPROD = VENDAS.CODPROD AND A.NUMSEQPED = VENDAS.NUMSEQ AND I.NUMSEQ = VENDAS.NUMSEQ)';
   V_VLVERBACMV := ' VENDAS.VLVERBACMV ';
   V_VLVERBACMVCLI := ' VENDAS.VLVERBACMVCLI '; 
 ELSE 
   V_SUBSELECTVERBA := ' 0 ';
   V_VLVERBACMV := ' 0 ';
   V_VLVERBACMVCLI := ' 0 ' ;
 END IF;

 CASE
  WHEN P_TIPOPESQUISA = 1
  THEN
   -- Consulta por Supervisor
   V_SQL :=
    'SELECT PCSUPERV.CODSUPERVISOR CODIGO, NVL(PCSUPERV.CODGERENTE,0) CODIGO2,NULL CONDVENDA, NULL  CODFILIAL, NULL  NUMREGIAO, NULL  CODUSUR,
     NULL  NOMEUSUR, NULL  UF, NULL  DTSAIDA, SUBSTR(PCSUPERV.NOME, 1, 40) DESCRICAO, NULL EMBALAGEM, NULL NUMNOTA, NULL DTCANCEL, NULL CODEPTO,
     NULL CODSEC, NULL CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL, NULL CODAUXILIAR, NULL PESOLIQ, NULL NUMPR, NULL PERCVENDA, NULL PERCLUCRO,
     NULL PERCMETA, NULL VLVENDAPF, NULL VLVENDAPJ, NULL PERCVENDAPF, NULL PERCVENDAPJ, NULL PERCPARTTOTAL, (DECODE(SUM(TOTAL.PESOBRUTO),0,0,
     (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(TOTAL.VLDEVOLAVULSAI))/ SUM(TOTAL.PESOBRUTO))) VLPESOTRANSP, SUM(TOTAL.VLDEVOLUCAO) VLDEVOLUCAO,
     SUM(TOTAL.VLDEVOLAVULSAI) VLDEVOLAVULSAI, SUM(TOTAL.VLDEVCMVAVULSAI) VLDEVCMVAVULSAI, SUM(TOTAL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, SUM(TOTAL.VLCMVDEVOL)
     VLCMVDEVOL, SUM(TOTAL.DEVOLTAB) DEVOLTAB, NVL(COUNT(DISTINCT TOTAL.CONTADOR), 0) CONTADOR, NVL(COUNT(DISTINCT TOTAL.QTCLIPOS), 0) QTCLIPOS,
     COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO, SUM(TOTAL.QTCLIENTE) QTCLIENTE, DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) /
     SUM(TOTAL.VLVENDA)) NUMDIAS, SUM(TOTAL.VLVENDA) VLVENDA, SUM(DISTINCT TOTAL.VALORTOTALNOTA) VALORTOTALNOTA, SUM(TOTAL.QTVENDA) QTVENDA,
     SUM(TOTAL.VLATEND) VLATEND, SUM(TOTAL.VLCUSTOFIN) VLCUSTOFIN, NULL CUSTOFINEST, SUM(TOTAL.VLCUSTOREAL) VLCUSTOREAL, SUM(TOTAL.VLESTDISP) VLESTDISP,
     AVG(TOTAL.CUSTOMEDFIN) CUSTOMEDFIN, AVG(TOTAL.CUSTOMEDREAL) CUSTOMEDREAL, SUM(TOTAL.VLTABELA) VLTABELA, SUM(TOTAL.PESOBRUTO) PESOBRUTO,
     SUM(TOTAL.VLBONIFIC) VLBONIFIC, NULL VLOUTRASDESP, NULL VLMEDBONIFIC, NULL QTBONIFIC, DECODE(SUM(TOTAL.VLTABELA), 0, 0, ((SUM(TOTAL.VLVENDA) -
     SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100) PERCDESC, DECODE(SUM(TOTAL.VLTABELA), 0, 0, ((SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) )) VALORDESC,
     (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(VLDEVOLAVULSAI)) VLLIQUIDO, MAX(NVL((SELECT SUM(NVL(PCMETASUP.VLVENDAPREV, 0))
     FROM PCMETASUP WHERE PCMETASUP.CODSUPERVISOR = TOTAL.CODSUPERVISOR';

   IF P_CODFILIAL IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCMETASUP.CODFILIAL IN (' || P_CODFILIAL || ')';
   END IF;

   --Filtros incluidos na rotina 111

   IF P_FILTROCODGERENTE IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCMETASUP.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';

   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN

       V_SQL := V_SQL || ' AND
                     PCMETASUP.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
   END IF;

   -- Fim dos filtros

   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCMETASUP.DATA BETWEEN :DATAINI and :DATAFIM';
   END IF;

   V_SQL := V_SQL || '), 0)) VLMETA,
                   SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA) VLFLEX, ';

   V_SQL := V_SQL || ' (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLCUSTOFIN) - SUM(TOTAL.VLDEVOLUCAO) - SUM(VLDEVOLAVULSAI) +
                     SUM(TOTAL.VLCMVDEVOL) + SUM(VLDEVCMVAVULSAI)) VLLUCRO, ';

   V_SQL :=
    V_SQL
    || ' DECODE(SUM(TOTAL.PRAZOMEDIO),0,0, SUM(TOTAL.PRAZOMEDIO) / SUM(TOTAL.VENDA_SEMDESCONTO)) PRAZOMEDIO, NULL PRAZOADICIONAL,
         DECODE(SUM(TOTAL.PESOBRUTO), 0, 0, (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO)) VLMEDIOKG,
         NULL CODCLIPRINC, NULL CLIENTEPRINC, NULL QTDEVOLUCAO, NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS,
         NULL SERIE, NULL CNPJ, NULL INSC, NULL CIDADE, NULL DESCSECAO, NULL DESCDEPTO, SUM(TOTAL.VLREPASSE) VLREPASSE,
         SUM(TOTAL.VLCMVDEVOLBONIF) VLCMVDEVOLBONIF, SUM(TOTAL.VLCMVANTESAPLVERBA) VLCMVANTESAPLVERBA, (SUM(TOTAL.VLLUCROANTESAPLVERBA) -
         SUM(TOTAL.VLDEVOLUCAO) - SUM(VLDEVOLAVULSAI) + SUM(TOTAL.VLCMVDEVOL) + SUM(VLDEVCMVAVULSAI)) VLLUCROANTESAPLVERBA,
         NULL PERCLUCROANTESAPLVERBA FROM (     SELECT ';

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' VENDAS.CODSUPERVISOR, 0 VLDEVOLAVULSAI, 0 VLDEVCMVAVULSAI, VENDAS.NUMTRANSVENDA CONTADOR, VENDAS.CODCLI QTCLIPOS,
                          VENDAS.CODPROD QTMIXPRODUTO,';
   ELSE
    V_SQL := V_SQL || ' VENDAS.CODSUPERVMOV CODSUPERVISOR, 0 VLDEVOLAVULSAI, 0 VLDEVCMVAVULSAI, VENDAS.NUMTRANSVENDA CONTADOR,
                          VENDAS.CODCLI QTCLIPOS,
                        VENDAS.CODPRODMOV QTMIXPRODUTO,';
   END IF;

   V_SQL :=
    V_SQL
    || ' 0 VLDEVOLUCAO, 0 VLDEVOLBONIFIC, 0 VLCMVDEVOL, 0 DEVOLTAB, ROUND(DECODE(SUM(VENDAS.VLVENDA),0,0,SUM(VENDAS.PRAZOMEDIO *
    VENDAS.VLVENDA)/SUM(VENDAS.VLVENDA)),2) NUMDIAS, DECODE(SUM(VENDAS.VLVENDA), 0, 0, SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA)) PRAZOMEDIO, SUM(VENDAS.VLVENDA) AS VENDA_SEMDESCONTO, ';

   IF P_DESCST = 0
   THEN
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA) VLVENDA, '
       || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
       || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

       IF P_CODFILIAL IS NOT NULL
       THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
       END IF;

       IF P_DATAINI IS NOT NULL
       THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
       END IF;

       V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN) VLCUSTOFIN,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB) VLCUSTOFIN,';
      END IF;

      V_SQL := V_SQL || 'SUM(VENDAS.VLATEND) VLATEND,
                                   SUM(VENDAS.VLCUSTOREAL) VLCUSTOREAL,
                                   SUM(VENDAS.VLTABELA) VLTABELA,';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || 'SUM(VENDAS.VLBONIFIC) VLBONIFIC,';
      ELSE
       V_SQL := V_SQL || 'SUM(VENDAS.VLBONIFIC2) VLBONIFIC,';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || '  ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE) VLVENDA, '
       || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
       || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

       IF P_CODFILIAL IS NOT NULL
       THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
       END IF;

       IF P_DATAINI IS NOT NULL
       THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
       END IF;

       V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE) VLCUSTOFIN,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE) VLCUSTOFIN,';
      END IF;

      V_SQL :=
       V_SQL
       || 'SUM(VENDAS.VLATEND - VENDAS.VLREPASSE) VLATEND,
                                   SUM(VENDAS.VLCUSTOREAL - VENDAS.VLREPASSE) VLCUSTOREAL,
                                   SUM(VENDAS.VLTABELA - VENDAS.VLREPASSE) VLTABELA,';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || 'SUM(VENDAS.VLBONIFIC) VLBONIFIC,';
      ELSE
       V_SQL := V_SQL || 'SUM(VENDAS.VLBONIFIC2) VLBONIFIC,';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     END IF;
    ELSIF P_DESCIPI = 1
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI) VLVENDA, '
       || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
       || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

       IF P_CODFILIAL IS NOT NULL
       THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
       END IF;

       IF P_DATAINI IS NOT NULL
       THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
       END IF;

       V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI) VLCUSTOFIN,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC)) VLCUSTOFIN,';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND - VENDAS.VLIPI) VLATEND,
                             SUM(VENDAS.VLCUSTOREAL - VENDAS.VLIPI) VLCUSTOREAL,
                             SUM(VENDAS.VLTABELA - VENDAS.VLIPI) VLTABELA,';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || 'SUM(VENDAS.VLBONIFIC - ( VENDAS.VLIPIBONIFIC)) VLBONIFIC,';
      ELSE
       V_SQL := V_SQL || 'SUM(VENDAS.VLBONIFIC2 - ( VENDAS.VLIPIBONIFIC)) VLBONIFIC,';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLIPI - (VENDAS.VLCUSTOFIN - VENDAS.VLIPI + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - (VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI - VENDAS.VLREPASSE) VLVENDA, '
       || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
       || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

       IF P_CODFILIAL IS NOT NULL
       THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
       END IF;

       IF P_DATAINI IS NOT NULL
       THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
       END IF;

       V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOFIN,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLCUSTOFIN,';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND - VENDAS.VLIPI - VENDAS.VLREPASSE) VLATEND,
                             SUM(VENDAS.VLCUSTOREAL - VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOREAL,
                             SUM(VENDAS.VLTABELA - VENDAS.VLIPI - VENDAS.VLREPASSE) VLTABELA,';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || 'SUM(VENDAS.VLBONIFIC - (VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLBONIFIC,';
      ELSE
       V_SQL := V_SQL || 'SUM(VENDAS.VLBONIFIC2 - (VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLBONIFIC,';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLIPI - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFIN - VENDAS.VLIPI - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' +
                                           ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE +
                                           ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE +
                                           ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     END IF;
    END IF;
   ELSE
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO) VLVENDA, '
       || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
       || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

       IF P_CODFILIAL IS NOT NULL
       THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
       END IF;

       IF P_DATAINI IS NOT NULL
       THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
       END IF;

       V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO) VLCUSTOFIN,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC)) VLCUSTOFIN,';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND -  VENDAS.ICMSRETIDO) VLATEND,
                             SUM(VENDAS.VLCUSTOREAL -  VENDAS.ICMSRETIDO) VLCUSTOREAL,
                             SUM(VENDAS.VLTABELA -  VENDAS.ICMSRETIDO) VLTABELA,';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || 'SUM(DECODE(VENDAS.VLBONIFIC,0,VENDAS.VLBONIFIC,VENDAS.VLBONIFIC - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC))) VLBONIFIC,';
      ELSE
       V_SQL := V_SQL || 'SUM(DECODE(VENDAS.VLBONIFIC2,0,VENDAS.VLBONIFIC2,VENDAS.VLBONIFIC2 - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC))) VLBONIFIC,';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - (VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) + ' || V_VLVERBACMV || ' +
                                          ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) +
                                           ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLVENDA, '
       || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
       || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

       IF P_CODFILIAL IS NOT NULL
       THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
       END IF;

       IF P_DATAINI IS NOT NULL
       THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
       END IF;

       V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLCUSTOFIN,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - VENDAS.VLREPASSE) VLCUSTOFIN,';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND -  VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLATEND,
                             SUM(VENDAS.VLCUSTOREAL -  VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLCUSTOREAL,
                             SUM(VENDAS.VLTABELA -  VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLTABELA,';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || 'SUM(DECODE(VENDAS.VLBONIFIC,0,VENDAS.VLBONIFIC,VENDAS.VLBONIFIC - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC))) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || 'SUM(DECODE(VENDAS.VLBONIFIC2,0,VENDAS.VLBONIFIC2,VENDAS.VLBONIFIC2 - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC))) VLBONIFIC, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' +
                                          ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' +
                                          ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - VENDAS.VLREPASSE +
                                          ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - VENDAS.VLREPASSE +
                                           ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     END IF;
    ELSIF P_DESCIPI = 1
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI) VLVENDA, '
       || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
       || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

       IF P_CODFILIAL IS NOT NULL
       THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
       END IF;

       IF P_DATAINI IS NOT NULL
       THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
       END IF;

       V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '
                     SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO -
                         VENDAS.VLIPI) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || '
                     SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC)) VLCUSTOFIN, ';
      END IF;

      V_SQL :=
       V_SQL
       || '
                     SUM(VENDAS.VLATEND - VENDAS.ICMSRETIDO - VENDAS.VLIPI)
                     VLATEND, SUM(VENDAS.VLCUSTOREAL - VENDAS.ICMSRETIDO -
                                  VENDAS.VLIPI) VLCUSTOREAL,
                     SUM(VENDAS.VLTABELA - VENDAS.ICMSRETIDO - VENDAS.VLIPI)
                     VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL :=
        V_SQL
        || '
                     SUM(DECODE(VENDAS.VLBONIFIC,
                                0,
                                VENDAS.VLBONIFIC,
                                VENDAS.VLBONIFIC - (VENDAS.ICMSRETIDO +
                                VENDAS.ICMSRETIDOBONIFIC) - VENDAS.VLIPI))
                     VLBONIFIC, ';
      ELSE
       V_SQL :=
        V_SQL
        || '
                     SUM(DECODE(VENDAS.VLBONIFIC2,
                                0,
                                VENDAS.VLBONIFIC2,
                                VENDAS.VLBONIFIC2 -
                                (VENDAS.ICMSRETIDO +
                                VENDAS.ICMSRETIDOBONIFIC) - VENDAS.VLIPI))
                     VLBONIFIC, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO - VENDAS.VLIPI + ' || V_VLVERBACMV || ' +
                                          ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI - (VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO - VENDAS.VLIPI + ' || V_VLVERBACMV || ' +
                                           ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) -
                                          (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - (VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) -
                                          (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '
                     SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO -
                         VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || '
                     SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL :=
       V_SQL
       || '
                     SUM(VENDAS.VLATEND - VENDAS.ICMSRETIDO - VENDAS.VLIPI -
                         VENDAS.VLREPASSE) VLATEND,
                     SUM(VENDAS.VLCUSTOREAL - VENDAS.ICMSRETIDO -
                         VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOREAL,
                     SUM(VENDAS.VLTABELA - VENDAS.ICMSRETIDO - VENDAS.VLIPI -
                         VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL :=
        V_SQL
        || '
                     SUM(DECODE(VENDAS.VLBONIFIC,
                                0,
                                VENDAS.VLBONIFIC,
                                VENDAS.VLBONIFIC -
                                (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) -
                                (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) -
                                VENDAS.VLREPASSE)) VLBONIFIC, ';
      ELSE
       V_SQL :=
        V_SQL
        || '
                     SUM(DECODE(VENDAS.VLBONIFIC2,
                                0,
                                VENDAS.VLBONIFIC2,
                                VENDAS.VLBONIFIC2 -
                                (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) -
                                (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) -
                                VENDAS.VLREPASSE)) VLBONIFIC, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO -
                                          VENDAS.VLIPI - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO -
                                           VENDAS.VLIPI - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) -
                                          (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) -
                                          (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     END IF;
    END IF;
   END IF;

   V_SQL :=
    V_SQL
    || ' SUM(VENDAS.QTVENDA) QTVENDA,
                     COUNT(DISTINCT VENDAS.QTCLIENTE) QTCLIENTE,
                     SUM(VENDAS.VLESTDISP) VLESTDISP, AVG(VENDAS.CUSTOFIN)
                     CUSTOMEDFIN, AVG(VENDAS.CUSTOREAL) CUSTOMEDREAL, ';

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' SUM(VENDAS.PESOBRUTO)
                     PESOBRUTO, SUM(VENDAS.VLREPASSE) VLREPASSE ';
   ELSE
    V_SQL := V_SQL || ' SUM(VENDAS.PESOBRUTOMOV)
                     PESOBRUTO, SUM(VENDAS.VLREPASSE) VLREPASSE ';
   END IF;

   V_SQL := V_SQL || ', 0 VLCMVDEVOLBONIF
                     FROM((' || V_SQL_GERAL ||')) VENDAS WHERE
                     1 = 1 ';

   IF P_CODFILIAL IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND
                     VENDAS.CODFILIAL IN (' || P_CODFILIAL || ')
                     ';
   END IF;

   --Filtros incluidos na rotina 111

   IF P_FILTROCODGERENTE IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     END IF;
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVMOV IN (' || P_FILTROCODSUPERVISOR || ')';
     END IF;
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODUSUR IN (' || P_FILTROCODUSUR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODUSURMOV IN (' || P_FILTROCODUSUR || ')';
     END IF;
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODFORNEC IN (' || P_FILTROCODFORNEC || ')';
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODFORNECPRINC  IN (' || P_FILTROCODFORNECPRINC || ')';
   END IF;

   -- Fim dos filtros


   IF P_CODGERENTE <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     END IF;
   END IF;

   IF P_CODSUPERVISOR <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVISOR = ' || P_CODSUPERVISOR;
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVMOV = ' || P_CODSUPERVISOR;
     END IF;
   END IF;

   IF P_CODRCA <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODUSUR = ' || P_CODRCA;
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODUSURMOV = ' || P_CODRCA;
     END IF;
   END IF;

   IF P_CODFORNEC <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND VENDAS.CODFORNEC = ' || P_CODFORNEC;
     ELSE
       V_SQL := V_SQL || ' AND VENDAS.CODFORNECMOV = ' || P_CODFORNEC;
     END IF;
   END IF;

   IF P_CODFORNECPRINC <> 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODFORNECPRINC = ' || P_CODFORNECPRINC;
   END IF;

   IF P_CODMARCA <> 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODMARCA = ' || P_CODMARCA;
   END IF;

   IF P_CODLINHAPROD <> 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODLINHAPROD = ' || P_CODLINHAPROD;
   END IF;

   IF P_CONSIDERANOTASAPROVADAS = 1
   THEN
    V_SQL := V_SQL || ' AND VENDAS.ESPECIE = ''NF''
                        AND VENDAS.SITUACAONFE in (100, 150) ';
   END IF;

   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND VENDAS.DTSAIDA BETWEEN :DATAINI2 and
                     :DATAFIM2
                     AND VENDAS.QTBONIFIC >= 0
                     ';
   END IF;

   IF P_TIPOVENDA10 = 0
   THEN
    V_SQL := V_SQL || ' AND NVL(VENDAS.CONDVENDA, -1) IN (1, 5, -1, 7, 9, 11, 14) ';
    V_SQL := V_SQL || ' AND VENDAS.CODFISCAL NOT IN
                     (522, 622, 722, 532, 632, 732)
                     ';
   ELSE
    V_SQL := V_SQL || ' AND
                     NVL(VENDAS.CONDVENDA, -1) IN (1, 5, -1, 7, 9, 11, 14, 10)
                     ';
    V_SQL := V_SQL || ' AND
                     VENDAS.CODFISCAL NOT IN (532, 632, 732)
                     ';
   END IF;

   IF P_CONDVENDA IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND
                     NVL(VENDAS.CONDVENDA, 0) IN (' || P_CONDVENDA || ')
                     ';
   END IF;

   IF P_ORIGEMPED IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND
                     VENDAS.ORIGEMPED = ''' || P_ORIGEMPED || '''';
   END IF;

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' GROUP BY
                     VENDAS.CODSUPERVISOR, VENDAS.NUMTRANSVENDA, VENDAS.CODCLI, VENDAS.CODPROD ';
   ELSE
    V_SQL := V_SQL || ' GROUP BY
                     VENDAS.CODSUPERVMOV, VENDAS.NUMTRANSVENDA, VENDAS.CODCLI, VENDAS.CODPRODMOV   ';
   END IF;

   IF P_DEVOLUCAO = 1
   THEN
    V_SQL := V_SQL || ' UNION ALL ';

    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' SELECT DEVOL.CODSUPERVISOR, ';
    ELSE
     V_SQL := V_SQL || ' SELECT DEVOL.CODSUPERVMOV CODSUPERVISOR, ';
    END IF;

    V_SQL := V_SQL || ' 0 VLDEVOLAVULSAI, 0 VLDEVCMVAVULSAI, NULL CONTADOR, NULL QTCLIPOS, NULL QTMIXPRODUTO, ';

    IF P_DESCST = 0
    THEN
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB) DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLREPASSE) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - DEVOL.VLREPASSE) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLREPASSE) DEVOLTAB, ';
      END IF;
     ELSIF P_DESCIPI = 1
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLIPI) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLIPI) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLIPI) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLIPI) DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLIPI - DEVOL.VLREPASSE) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - DEVOL.VLREPASSE - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLIPI - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLIPI - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLIPI - DEVOL.VLREPASSE) DEVOLTAB, ';
      END IF;
     END IF;
    ELSE
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLST) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLST) VLCMVDEVOL, ';
       ELSE
