      CASE WHEN(TOTAL.CODPLPAG = 99) AND (MAX(TOTAL.PMVENDAS) = MAX(TOTAL.PMDEVOL)) THEN SUM(NVL(TOTAL.VLDEVOLUCAO, 0)) WHEN(TOTAL.CODPLPAG = 99) AND
      (MAX(TOTAL.PMVENDAS) <> MAX(TOTAL.PMDEVOL)) THEN 0 WHEN(TOTAL.CODPLPAG <> 99) THEN SUM(NVL(TOTAL.VLDEVOLUCAO, 0)) END VLDEVOLUCAO, NULL VLDEVOLAVULSAI,
      NULL VLDEVCMVAVULSAI, SUM(NVL(TOTAL.VLDEVOLBONIFIC, 0)) VLDEVOLBONIFIC, CASE WHEN(TOTAL.CODPLPAG = 99) AND (MAX(TOTAL.PMVENDAS) = MAX(TOTAL.PMDEVOL)) THEN
