      ,COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO, NULL QTCLIENTE, DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) NUMDIAS, SUM(TOTAL.VLVENDA) VLVENDA, SUM(DISTINCT TOTAL.VALORTOTALNOTA) VALORTOTALNOTA, SUM(TOTAL.QTVENDA) QTVENDA,
