      ((SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100) PERCDESC, (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) VALORDESC,
      (SUM(TOTAL.VLVENDA) - (CASE WHEN(TOTAL.CODPLPAG = 99) AND (MAX(TOTAL.PMVENDAS) = MAX(TOTAL.PMDEVOL)) THEN SUM(NVL(TOTAL.VLDEVOLUCAO, 0))
      WHEN(TOTAL.CODPLPAG = 99) AND (MAX(TOTAL.PMVENDAS) <> MAX(TOTAL.PMDEVOL)) THEN 0 WHEN(TOTAL.CODPLPAG <> 99) THEN SUM(NVL(TOTAL.VLDEVOLUCAO, 0)) END)) VLLIQUIDO, NULL VLMETA,
