       V_SQL := V_SQL || ' AND AVULSA.NUMTRANSVENDA  = ' || P_NUMTRANSVENDA;
   END IF;


   IF P_NUMNOTA > 0
    THEN
     V_SQL := V_SQL || ' AND AVULSA.NUMNOTA = ' || P_NUMNOTA;
    END IF;

    IF P_CODFORNECPRINC > 0 THEN
      IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND AVULSA.CODFORNEC IN ( SELECT PCFORNEC.CODFORNEC FROM PCFORNEC WHERE NVL(PCFORNEC.CODFORNECPRINC, PCFORNEC.CODFORNEC) = ' || P_CODFORNECPRINC || ')';
      ELSE
        V_SQL := V_SQL || ' AND AVULSA.CODFORNECMOV IN ( SELECT PCFORNEC.CODFORNEC FROM PCFORNEC WHERE NVL(PCFORNEC.CODFORNECPRINC, PCFORNEC.CODFORNEC) = ' || P_CODFORNECPRINC || ')';
      END IF;
    END IF;

    IF P_CODEPTO > 0
    THEN
      V_SQL := V_SQL || ' AND AVULSA.CODEPTO = ' || P_CODEPTO;
    END IF;

    IF P_NUMNOTA > 0
    THEN
     V_SQL := V_SQL || ' AND AVULSA.NUMNOTA = ' || P_NUMNOTA;
    END IF;

  IF P_SUPERVMOV = 0 THEN
      V_SQL :=
       V_SQL
       || ' GROUP BY AVULSA.CODPROD, AVULSA.CODCLI, AVULSA.CODUSUR, AVULSA.DESCRICAO, AVULSA.EMBALAGEM, AVULSA.NUMORIGINAL, AVULSA.CODAUXILIAR,
AVULSA.ESTENT, AVULSA.CLIENTE, AVULSA.CGCENT, AVULSA.MUNICENT, AVULSA.IEENT, AVULSA.CODSEC, AVULSA.CODCATEGORIA,
AVULSA.CODSUBCATEGORIA, AVULSA.CODEPTO ';
    ELSE
      V_SQL :=
       V_SQL
       || ' GROUP BY AVULSA.CODPROD, AVULSA.CODCLI, AVULSA.CODUSURMOV, AVULSA.DESCRICAO, AVULSA.EMBALAGEM, AVULSA.NUMORIGINAL, AVULSA.CODAUXILIAR,
AVULSA.ESTENT, AVULSA.CLIENTE, AVULSA.CGCENT, AVULSA.MUNICENT, AVULSA.IEENT, AVULSA.CODSEC, AVULSA.CODCATEGORIA,
AVULSA.CODSUBCATEGORIA, AVULSA.CODEPTO ';
    END IF;


    -- DEVOLUÇÃO AVULSA - FIM

   END IF;

   V_SQL := V_SQL || ') TOTAL, PCSECAO, PCDEPTO ';
   --IF P_CODFORNEC IS NOT NULL THEN
   V_SQL := V_SQL || ', PCUSUARI ';
   --END IF;
   V_SQL := V_SQL || ' WHERE 1 = 1 ';
   --IF P_CODFORNEC IS NOT NULL THEN
   V_SQL := V_SQL || ' AND TOTAL.CODUSUR = PCUSUARI.CODUSUR(+) ';
   --END IF;
   V_SQL :=
    V_SQL
    || ' AND total.CODSEC = PCSECAO.CODSEC(+) AND total.CODEPTO = PCSECAO.CODEPTO(+)
  AND PCSECAO.CODEPTO = PCDEPTO.CODEPTO(+)
GROUP BY TOTAL.CODPROD, total.DESCRICAO, total.EMBALAGEM, total.CODEPTO,
total.CODSEC, TOTAL.CODCATEGORIA, TOTAL.CODSUBCATEGORIA, total.NUMORIGINAL, total.CODAUXILIAR, PCSECAO.DESCRICAO, PCDEPTO.DESCRICAO ';

   /*IF P_CODFORNEC IS NOT NULL THEN
     V_SQL := V_SQL || ', TOTAL.CODUSUR, PCUSUARI.NOME ';
   END IF;*/
   IF P_CODCLI IS NOT NULL
   THEN
    V_SQL := V_SQL || ', TOTAL.CODCLI, total.CLIENTE, total.CGCENT, total.IEENT, total.MUNICENT, total.ESTENT ';
   END IF;

   V_SQL := V_SQL || ' ORDER BY VLVENDA DESC ';
  WHEN P_TIPOPESQUISA = 4
  THEN
   -- Consulta por Evolução
   V_SQL :=
    ' SELECT NULL CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL, NULL NUMREGIAO, NULL CODUSUR, NULL NOMEUSUR, NULL UF, TOTAL.DTSAIDA,
      DECODE(TO_CHAR(TOTAL.DTSAIDA, ''D''), 1, ''Domingo'', 2, ''Segunda - Feira'', 3, ''Terça - Feira'', 4, ''Quarta - Feira'', 5,
      ''Quinta - Feira'', 6, ''Sexta - Feira'', 7, ''Sábado'') DESCRICAO, NULL EMBALAGEM, NULL NUMNOTA, NULL DTCANCEL, NULL CODEPTO, NULL CODSEC,
      NULL CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL, NULL CODAUXILIAR, NULL PESOLIQ, NULL NUMPR, NULL PERCVENDA, NULL PERCLUCRO, NULL PERCMETA,
      NULL VLVENDAPF, NULL VLVENDAPJ, NULL PERCVENDAPF, NULL PERCVENDAPJ, NULL PERCPARTTOTAL, (DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
      SUM(TOTAL.VLDEVOLUCAO) - SUM(TOTAL.VLDEVOLAVULSAI)) / SUM(TOTAL.PESOBRUTO))) VLPESOTRANSP, SUM(TOTAL.VLDEVOLUCAO) VLDEVOLUCAO,
      SUM(TOTAL.VLDEVOLAVULSAI) VLDEVOLAVULSAI, SUM(TOTAL.VLDEVCMVAVULSAI) VLDEVCMVAVULSAI, SUM(TOTAL.VLDEVOLBONIFIC) VLDEVOLBONIFIC,
      SUM(TOTAL.VLCMVDEVOL) VLCMVDEVOL, SUM(TOTAL.DEVOLTAB) DEVOLTAB, NVL(COUNT(DISTINCT TOTAL.CONTADOR), 0) CONTADOR ,NVL(COUNT(DISTINCT TOTAL.QTCLIPOS), 0) QTCLIPOS,
      COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO, NULL QTCLIENTE, DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) NUMDIAS,
      SUM(TOTAL.VLVENDA) VLVENDA, SUM(DISTINCT TOTAL.VALORTOTALNOTA) VALORTOTALNOTA, SUM(TOTAL.QTVENDA) QTVENDA, SUM(TOTAL.VLATEND) VLATEND,
      SUM(TOTAL.VLCUSTOFIN) VLCUSTOFIN, NULL CUSTOFINEST, SUM(TOTAL.VLCUSTOREAL) VLCUSTOREAL, SUM(TOTAL.VLESTDISP) VLESTDISP, AVG(TOTAL.CUSTOMEDFIN) CUSTOMEDFIN,
      AVG(TOTAL.CUSTOMEDREAL) CUSTOMEDREAL, SUM(TOTAL.VLTABELA) VLTABELA, SUM(TOTAL.PESOBRUTO) PESOBRUTO, SUM(TOTAL.VLBONIFIC) VLBONIFIC, NULL VLOUTRASDESP,
      NULL VLMEDBONIFIC, NULL QTBONIFIC, DECODE(SUM(TOTAL.VLTABELA), 0, -100,((SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100) PERCDESC,
      (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) VALORDESC, (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(TOTAL.VLDEVOLAVULSAI)) VLLIQUIDO, NULL VLMETA,
      SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA) VLFLEX, ';

   V_SQL := V_SQL || '(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLCUSTOFIN) - SUM(TOTAL.VLDEVOLUCAO) - SUM(VLDEVOLAVULSAI) + SUM(TOTAL.VLCMVDEVOL) + SUM(VLDEVCMVAVULSAI)) VLLUCRO, ';

   V_SQL :=
    V_SQL
    || ' DECODE(SUM(TOTAL.PRAZOMEDIO),0,0, SUM(TOTAL.PRAZOMEDIO) / SUM(TOTAL.VENDA_SEMDESCONTO)) PRAZOMEDIO, NULL PRAZOADICIONAL, DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
           SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO)) VLMEDIOKG, NULL CODCLIPRINC, NULL CLIENTEPRINC, NULL QTDEVOLUCAO,
         NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS, NULL SERIE, NULL CNPJ, NULL INSC, NULL CIDADE, NULL DESCSECAO,
         NULL DESCDEPTO, SUM(TOTAL.VLREPASSE) VLREPASSE, SUM(TOTAL.VLCMVDEVOLBONIF) VLCMVDEVOLBONIF, SUM(TOTAL.VLCMVANTESAPLVERBA) VLCMVANTESAPLVERBA,
         (SUM(TOTAL.VLLUCROANTESAPLVERBA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(VLDEVOLAVULSAI) + SUM(TOTAL.VLCMVDEVOL) + SUM(VLDEVCMVAVULSAI)) VLLUCROANTESAPLVERBA,
         NULL PERCLUCROANTESAPLVERBA FROM(';
   V_SQL :=
    V_SQL
    || ' SELECT TO_DATE(VENDAS.DTSAIDA, ''DD/MM/YYYY  HH24:MI:SS'') DTSAIDA, 0 VLDEVOLAVULSAI, 0 VLDEVCMVAVULSAI,  VENDAS.NUMTRANSVENDA CONTADOR,
                  VENDAS.CODCLI QTCLIPOS, VENDAS.CODPROD QTMIXPRODUTO, 0 VLDEVOLUCAO, 0 VLDEVOLBONIFIC, 0 VLCMVDEVOL, 0 DEVOLTAB,
            ROUND(DECODE(SUM(VENDAS.VLVENDA), 0, 0, SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA) / SUM(VENDAS.VLVENDA)), 2) NUMDIAS,
            DECODE(SUM(VENDAS.VLVENDA), 0, 0, SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA)) PRAZOMEDIO, SUM(VENDAS.VLVENDA) AS VENDA_SEMDESCONTO, ';

   IF P_DESCST = 0
   THEN
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND) VLATEND, SUM(VENDAS.VLCUSTOREAL) VLCUSTOREAL, SUM(VENDAS.VLTABELA) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2) VLBONIFIC, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND - VENDAS.VLREPASSE) VLATEND, SUM(VENDAS.VLCUSTOREAL - VENDAS.VLREPASSE) VLCUSTOREAL, SUM(VENDAS.VLTABELA - VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - VENDAS.VLREPASSE) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2 - VENDAS.VLREPASSE) VLBONIFIC, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     END IF;
    ELSIF P_DESCIPI = 1
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC)) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND - VENDAS.VLIPI) VLATEND, SUM(VENDAS.VLCUSTOREAL - VENDAS.VLIPI) VLCUSTOREAL, SUM(VENDAS.VLTABELA - VENDAS.VLIPI) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - (VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2 - (VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLBONIFIC, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLIPI - (VENDAS.VLCUSTOFIN - VENDAS.VLIPI + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) + ' || V_VLVERBACMV || ' +
                                          ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - (VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) + ' || V_VLVERBACMV || ' +
                                           ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ';

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND - VENDAS.VLIPI - VENDAS.VLREPASSE) VLATEND, SUM(VENDAS.VLCUSTOREAL -
                   VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOREAL, SUM(VENDAS.VLTABELA - VENDAS.VLIPI - VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - (VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2 - (VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLBONIFIC, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' +
                                          ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLIPI - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFIN - VENDAS.VLIPI - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' +
                                           ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE +
                                          ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFINB + - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE +
                                           ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     END IF;
    END IF;
   ELSE
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO) VLCUSTOFIN, ';
