   END IF;

   V_SQL := V_SQL || ') TOTAL GROUP BY TOTAL.UF ORDER BY VLVENDA DESC ';
  WHEN P_TIPOPESQUISA = 6
  THEN
   -- Consulta por UF - Venda Externa
   V_SQL :=
    ' SELECT NULL CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL, NULL NUMREGIAO, NULL CODUSUR, NULL NOMEUSUR, TOTAL.UF UF, NULL DTSAIDA,
      TOTAL.UF DESCRICAO, NULL EMBALAGEM, NULL NUMNOTA, NULL DTCANCEL, NULL CODEPTO, NULL CODSEC, NULL CODCATEGORIA, NULL CODSUBCATEGORIA,
      NULL NUMORIGINAL, NULL CODAUXILIAR, NULL PESOLIQ, NULL NUMPR, NULL PERCVENDA, NULL PERCLUCRO, NULL PERCMETA, SUM(TOTAL.VLVENDAPF) VLVENDAPF,
      SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLVENDAPF) VLVENDAPJ, NULL PERCVENDAPF, NULL PERCVENDAPJ, NULL PERCPARTTOTAL, (DECODE(SUM(TOTAL.PESOBRUTO),
      0, 0,(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO))) VLPESOTRANSP, SUM(TOTAL.VLDEVOLUCAO) VLDEVOLUCAO, NULL VLDEVOLAVULSAI,
      NULL VLDEVCMVAVULSAI, SUM(TOTAL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, SUM(TOTAL.VLCMVDEVOL) VLCMVDEVOL, SUM(TOTAL.DEVOLTAB) DEVOLTAB,
      NVL(COUNT(DISTINCT TOTAL.CONTADOR), 0) CONTADOR ,NVL(COUNT(DISTINCT TOTAL.QTCLIPOS), 0) QTCLIPOS, COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO,
      NULL QTCLIENTE, DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) NUMDIAS, SUM(TOTAL.VLVENDA) VLVENDA,
      SUM(DISTINCT TOTAL.VALORTOTALNOTA) VALORTOTALNOTA, SUM(TOTAL.QTVENDA) QTVENDA, SUM(TOTAL.VLATEND) VLATEND, SUM(TOTAL.VLCUSTOFIN) VLCUSTOFIN,
      NULL CUSTOFINEST, SUM(TOTAL.VLCUSTOREAL) VLCUSTOREAL, SUM(TOTAL.VLESTDISP) VLESTDISP, AVG(TOTAL.CUSTOMEDFIN) CUSTOMEDFIN, AVG(TOTAL.CUSTOMEDREAL) CUSTOMEDREAL,
      SUM(TOTAL.VLTABELA) VLTABELA, SUM(TOTAL.PESOBRUTO) PESOBRUTO, SUM(TOTAL.VLBONIFIC) VLBONIFIC, NULL VLOUTRASDESP, NULL VLMEDBONIFIC, NULL QTBONIFIC,
      DECODE(SUM(TOTAL.VLTABELA), 0, -100,((SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100) PERCDESC, (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) VALORDESC,
      (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO)) VLLIQUIDO, NULL VLMETA, SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA) VLFLEX, ';

   V_SQL := V_SQL || '(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLCUSTOFIN) - SUM(TOTAL.VLDEVOLUCAO) + SUM(TOTAL.VLCMVDEVOL)) VLLUCRO, ';

   V_SQL :=
    V_SQL
    || ' DECODE(SUM(TOTAL.PRAZOMEDIO),0,0, SUM(TOTAL.PRAZOMEDIO) / SUM(TOTAL.VENDA_SEMDESCONTO)) PRAZOMEDIO, NULL PRAZOADICIONAL, DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
            SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO)) VLMEDIOKG, NULL CODCLIPRINC, NULL CLIENTEPRINC, NULL QTDEVOLUCAO,
         NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS, NULL SERIE, NULL CNPJ, NULL INSC, NULL CIDADE,
         NULL DESCSECAO, NULL DESCDEPTO, SUM(TOTAL.VLREPASSE) VLREPASSE, SUM(TOTAL.VLCMVDEVOLBONIF) VLCMVDEVOLBONIF, SUM(TOTAL.VLCMVANTESAPLVERBA) VLCMVANTESAPLVERBA,
         (SUM(TOTAL.VLLUCROANTESAPLVERBA) - SUM(TOTAL.VLDEVOLUCAO) + SUM(TOTAL.VLCMVDEVOL)) VLLUCROANTESAPLVERBA, NULL PERCLUCROANTESAPLVERBA FROM(';

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' SELECT VENDAS.UF, VENDAS.NUMTRANSVENDA CONTADOR, VENDAS.CODCLI QTCLIPOS, VENDAS.CODPROD QTMIXPRODUTO, ';
   ELSE
    V_SQL := V_SQL || ' SELECT VENDAS.UFMOV UF, VENDAS.NUMTRANSVENDA CONTADOR, VENDAS.CODCLI QTCLIPOS, VENDAS.CODPRODMOV QTMIXPRODUTO, ';
   END IF;

   V_SQL :=
    V_SQL
    || ' 0 VLDEVOLUCAO, 0 VLDEVOLBONIFIC, 0 VLCMVDEVOL, 0 DEVOLTAB, ROUND(DECODE(SUM(VENDAS.VLVENDA), 0, 0,
         SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA) / SUM(VENDAS.VLVENDA)), 2) NUMDIAS, DECODE(SUM(VENDAS.VLVENDA), 0, 0,
         SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA)) PRAZOMEDIO, SUM(VENDAS.VLVENDA) AS VENDA_SEMDESCONTO, ';

   IF P_DESCST = 0
   THEN
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND) VLATEND, SUM(VENDAS.VLCUSTOREAL) VLCUSTOREAL, SUM(VENDAS.VLTABELA) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2) VLBONIFIC, ';
      END IF;

      IF VERIFICAPF = TRUE
      THEN
       V_SQL := V_SQL || ' SUM(DECODE((CASE ';

       IF P_CONSIDTIPOFJ = 1
       THEN
        V_SQL := V_SQL || ' WHEN(PCCLIENT.TIPOFJ = ''F'') THEN ''S''';
       END IF;

       IF P_CONSIDCONSUMIDORFINAL = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.CONSUMIDORFINAL, ''N'') = ''S'') THEN ''S''';
       END IF;

       IF P_CONSIDISENTO = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTO'') THEN ''S''';
       END IF;

       IF P_CONSIDISENTA = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTA'') THEN ''S''';
       END IF;

       V_SQL := V_SQL || ' ELSE ''N'' END), ''S'', VENDAS.VLVENDA, 0)) VLVENDAPF, ';
      ELSE
       V_SQL := V_SQL || ' 0 VLVENDAPF, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE) VLVENDA, '
       || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
       || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

       IF P_CODFILIAL IS NOT NULL
       THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
       END IF;

       IF P_DATAINI IS NOT NULL
       THEN
