                                          (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE) VLATEND,
             SUM(VENDAS.VLCUSTOREAL - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL :=
        V_SQL
        || ' SUM(DECODE(VENDAS.VLBONIFIC, 0, VENDAS.VLBONIFIC, VENDAS.VLBONIFIC - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) -
             (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE)) VLBONIFIC, ';
      ELSE
       V_SQL :=
        V_SQL
        || ' SUM(DECODE(VENDAS.VLBONIFIC2, 0, VENDAS.VLBONIFIC2, VENDAS.VLBONIFIC2 - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) -
             (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE)) VLBONIFIC, ';
      END IF;

      IF VERIFICAPF = TRUE
      THEN
       V_SQL := V_SQL || ' SUM(DECODE((CASE ';

       IF P_CONSIDTIPOFJ = 1
       THEN
        V_SQL := V_SQL || ' WHEN(PCCLIENT.TIPOFJ = ''F'') THEN ''S''';
       END IF;

       IF P_CONSIDCONSUMIDORFINAL = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.CONSUMIDORFINAL, ''N'') = ''S'') THEN ''S''';
       END IF;

       IF P_CONSIDISENTO = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTO'') THEN ''S''';
       END IF;

       IF P_CONSIDISENTA = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTA'') THEN ''S''';
       END IF;

       V_SQL := V_SQL || ' ELSE ''N'' END), ''S'', VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE, 0)) VLVENDAPF, ';
      ELSE
       V_SQL := V_SQL || ' 0 VLVENDAPF, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE +
                                          ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE +
                                           ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) -
                                          (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) -
                                           (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     END IF;
    END IF;
   END IF;

   V_SQL := V_SQL || ' SUM(VENDAS.QTVENDA) QTVENDA, SUM(VENDAS.VLESTDISP) VLESTDISP, AVG(VENDAS.CUSTOFIN) CUSTOMEDFIN, AVG(VENDAS.CUSTOREAL) CUSTOMEDREAL, ';

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' SUM(VENDAS.PESOBRUTO) PESOBRUTO ';
   ELSE
    V_SQL := V_SQL || ' SUM(VENDAS.PESOBRUTOMOV) PESOBRUTO ';
   END IF;

   V_SQL :=
    V_SQL
    || ', SUM(VENDAS.VLREPASSE) VLREPASSE, 0 VLCMVDEVOLBONIF
         FROM((' || V_SQL_GERAL ||')) VENDAS, PCCLIENT
         WHERE VENDAS.CODCLI = PCCLIENT.CODCLI AND NVL(VENDAS.ORIGEMPED, ''W'') <> ''B''';

   IF P_CODFILIAL IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND VENDAS.CODFILIAL IN (' || P_CODFILIAL || ') ';
   END IF;

   --Filtros incluidos na rotina 111

   IF P_FILTROCODGERENTE IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     END IF;
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVMOV IN (' || P_FILTROCODSUPERVISOR || ')';
     END IF;
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODUSUR IN (' || P_FILTROCODUSUR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODUSURMOV IN (' || P_FILTROCODUSUR || ')';
     END IF;
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODFORNEC IN (' || P_FILTROCODFORNEC || ')';
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODFORNECPRINC  IN (' || P_FILTROCODFORNECPRINC || ')';
   END IF;

   -- Fim dos filtros


   IF P_CODGERENTE <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     END IF;
   END IF;

   IF P_CODSUPERVISOR <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVISOR = ' || P_CODSUPERVISOR;
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVMOV = ' || P_CODSUPERVISOR;
     END IF;
   END IF;

   IF P_CODRCA <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODUSUR = ' || P_CODRCA;
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODUSURMOV = ' || P_CODRCA;
     END IF;
   END IF;

   IF P_CODFORNEC <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND VENDAS.CODFORNEC = ' || P_CODFORNEC;
     ELSE
       V_SQL := V_SQL || ' AND VENDAS.CODFORNECMOV = ' || P_CODFORNEC;
     END IF;
   END IF;

   IF P_CODFORNECPRINC <> 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODFORNECPRINC = ' || P_CODFORNECPRINC;
   END IF;

   IF P_CODMARCA <> 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODMARCA = ' || P_CODMARCA;
   END IF;

   IF P_CODLINHAPROD <> 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODLINHAPROD = ' || P_CODLINHAPROD;
   END IF;


   IF P_CONSIDERANOTASAPROVADAS = 1
   THEN
    V_SQL := V_SQL || ' AND VENDAS.ESPECIE = ''NF''
                        AND VENDAS.SITUACAONFE in (100, 150) ';
   END IF;

   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND VENDAS.DTSAIDA BETWEEN :DATAINI2 and :DATAFIM2
    AND VENDAS.QTBONIFIC >= 0 ';
   END IF;

   IF P_TIPOVENDA10 = 0
   THEN
    V_SQL := V_SQL || ' AND NVL(VENDAS.CONDVENDA, -1) IN (1, 5, -1, 7, 9, 11, 14) ';
    V_SQL := V_SQL || ' AND VENDAS.CODFISCAL NOT IN (522, 622, 722, 532, 632, 732) ';
   ELSE
    V_SQL := V_SQL || ' AND NVL(VENDAS.CONDVENDA, -1) IN (1, 5, -1, 7, 9, 11, 14, 10) ';
    V_SQL := V_SQL || ' AND VENDAS.CODFISCAL NOT IN (532, 632, 732) ';
   END IF;

   IF P_CONDVENDA IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND NVL(VENDAS.CONDVENDA, 0) IN (' || P_CONDVENDA || ') ';
   END IF;

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' GROUP BY VENDAS.UF, VENDAS.NUMTRANSVENDA, VENDAS.CODCLI, VENDAS.CODPROD ';
   ELSE
    V_SQL := V_SQL || ' GROUP BY VENDAS.UFMOV, VENDAS.NUMTRANSVENDA, VENDAS.CODCLI, VENDAS.CODPRODMOV ';
   END IF;

   IF P_DEVOLUCAO = 1
   THEN
    V_SQL := V_SQL || ' UNION ALL ';

    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' SELECT DEVOL.ESTENT UF, ';
    ELSE
     V_SQL := V_SQL || ' SELECT DEVOL.UFMOV UF, ';
    END IF;

    V_SQL := V_SQL || ' NULL CONTADOR, NULL QTCLIPOS, NULL QTMIXPRODUTO, ';

    IF P_DESCST = 0
    THEN
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB) DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLREPASSE) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - DEVOL.VLREPASSE) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLREPASSE) DEVOLTAB, ';
      END IF;
     ELSIF P_DESCIPI = 1
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLIPI) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLIPI) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLIPI) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLIPI) DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLIPI - DEVOL.VLREPASSE) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - DEVOL.VLREPASSE - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLIPI - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLIPI - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLIPI - DEVOL.VLREPASSE) DEVOLTAB, ';
      END IF;
     END IF;
    ELSE
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLST) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLST) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLST) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLST) DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLST - DEVOL.VLREPASSE) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - DEVOL.VLREPASSE - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLST - DEVOL.VLREPASSE) DEVOLTAB, ';
      END IF;
     ELSIF P_DESCIPI = 1
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLST - DEVOL.VLIPI) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - VLIPI_BONIF - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - VLIPI_BONIF - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLIPI) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLIPI) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLST - DEVOL.VLIPI) DEVOLTAB, ';
      ELSE
       V_SQL :=
        V_SQL
        || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLST - DEVOL.VLIPI - DEVOL.VLREPASSE) VLDEVOLUCAO,';

        IF P_DESCVLTABELA = 0
        THEN
         V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE - VLIPI_BONIF - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
        ELSE
         V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - DEVOL.VLREPASSE - VLIPI_BONIF - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
        END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLIPI - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLIPI - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLST - DEVOL.VLIPI - DEVOL.VLREPASSE) DEVOLTAB, ';
      END IF;
     END IF;
    END IF;

    V_SQL :=
     V_SQL
     || ' 0 NUMDIAS, 0 PRAZOMEDIO, 0 AS VENDA_SEMDESCONTO, 0 VLVENDA, -1 VALORTOTALNOTA, 0 VLCUSTOFIN, 0 VLATEND,
              0 VLCUSTOREAL, 0 VLTABELA, 0 VLBONIFIC, 0 VLVENDAPF, 0 VLCMVANTESAPLVERBA, 0 VLLUCROANTESAPLVERBA, 0 QTVENDA, 0 VLESTDISP, 0 CUSTOMEDFIN, 0 CUSTOMEDREAL, ';

    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' SUM(DEVOL.TOTPESO) * -1 PESOBRUTO ';
    ELSE
     V_SQL := V_SQL || ' SUM(DEVOL.TOTPESOMOV) * -1 PESOBRUTO ';
    END IF;

    V_SQL := V_SQL || ', SUM(DEVOL.VLREPASSE) VLREPASSE, SUM(VLCMVDEVOLBONIF) VLCMVDEVOLBONIF

           FROM ( '||V_SQL_VIEW_DEVOL||' ) DEVOL WHERE NVL(DEVOL.ORIGEMPED, ''W'') <> ''B''';

    IF P_CODFILIAL IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND DEVOL.CODFILIAL IN (' || P_CODFILIAL || ') ';
    END IF;

   --Filtros incluidos na rotina 111

   IF P_FILTROCODGERENTE IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     END IF;
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVMOV IN (' || P_FILTROCODSUPERVISOR || ')';
     END IF;
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODUSUR IN (' || P_FILTROCODUSUR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODUSURMOV IN (' || P_FILTROCODUSUR || ')';
     END IF;
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODFORNEC IN (' || P_FILTROCODFORNEC || ')';
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODFORNECPRINC  IN (' || P_FILTROCODFORNECPRINC || ')';
   END IF;

   -- Fim dos filtros


    IF P_CODGERENTE <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     END IF;
    END IF;

    IF P_CODSUPERVISOR <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVISOR = ' || P_CODSUPERVISOR;
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVMOV = ' || P_CODSUPERVISOR;
     END IF;
    END IF;

    IF P_CODRCA <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODUSUR = ' || P_CODRCA;
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODUSURMOV = ' || P_CODRCA;
     END IF;
    END IF;

    IF P_CODFORNEC <> 0 THEN
      IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND DEVOL.CODFORNEC = ' || P_CODFORNEC;
      ELSE
        V_SQL := V_SQL || ' AND DEVOL.CODFORNECMOV = ' || P_CODFORNEC;
      END IF;
    END IF;

    IF P_CODFORNECPRINC <> 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODFORNECPRINC = ' || P_CODFORNECPRINC;
    END IF;

    IF P_CODMARCA <> 0 THEN
       V_SQL := V_SQL || ' AND
                      DEVOL.CODMARCA = ' || P_CODMARCA;
    END IF;

    IF P_CODLINHAPROD <> 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODLINHAPROD = ' || P_CODLINHAPROD;
    END IF;

    IF P_DATAINI IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND DEVOL.DTENT BETWEEN :DATAINI3 and :DATAFIM3 ';
    END IF;
  IF P_CONSIDERANOTASAPROVADAS = 1 THEN
        V_SQL := V_SQL || ' AND DEVOL.ESPECIE = ''NF''
                        AND DEVOL.SITUACAONFE in (100, 150)  ';
  END IF;

    IF P_TIPOVENDA10 = 0
    THEN
     IF P_CONSIDERARDEVOLTV8 = 0
     THEN
      --P_CONSIDERARDEVOLTV8 = 0 NÃ¿O RETORNA AS DEVOLUCOES TV8, QUANDO FOR 1 RETORNA TV8
      V_SQL := V_SQL || ' AND DEVOL.CONDVENDA NOT IN (4, 8, 10, 13, 20, 98, 99) ';
     ELSE
      V_SQL :=
       V_SQL
       || ' AND ((DEVOL.CONDVENDA NOT IN (4, 8, 10, 13, 20, 98, 99) AND (TEMVENDATV8 IS NOT NULL))
               OR (DEVOL.CONDVENDA NOT IN (4, 10, 13, 20, 98, 99) AND (TEMVENDATV8 IS NULL))) ';
     END IF;
    ELSE
     IF P_CONSIDERARDEVOLTV8 = 0
     THEN
      V_SQL := V_SQL || ' AND DEVOL.CONDVENDA NOT IN (4, 8, 13, 20, 98, 99) ';
     ELSE
      V_SQL :=
       V_SQL || ' AND ((DEVOL.CONDVENDA NOT IN (4, 8, 13, 20, 98, 99) AND (TEMVENDATV8 IS NOT NULL)) OR
                (DEVOL.CONDVENDA NOT IN (4, 13, 20, 98, 99) AND (TEMVENDATV8 IS NULL))) ';
     END IF;
    END IF;

    IF P_CONDVENDA IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND DEVOL.CONDVENDA IN (' || P_CONDVENDA || ') ';
    END IF;

    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' GROUP BY DEVOL.ESTENT ';
    ELSE
     V_SQL := V_SQL || ' GROUP BY DEVOL.UFMOV ';
    END IF;
   END IF;

   V_SQL := V_SQL || ') TOTAL

             GROUP BY TOTAL.UF ORDER BY VLVENDA DESC ';
  WHEN P_TIPOPESQUISA = 7
  THEN
   -- Consulta por Regiao
   V_SQL :=
    ' SELECT TOTAL.NUMREGIAO CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL, TOTAL.NUMREGIAO NUMREGIAO,
               NULL CODUSUR, NULL NOMEUSUR, NULL UF, NULL DTSAIDA, PCREGIAO.REGIAO DESCRICAO, NULL EMBALAGEM, NULL NUMNOTA,
        NULL DTCANCEL, NULL CODEPTO, NULL CODSEC, NULL CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL, NULL CODAUXILIAR, NULL PESOLIQ, NULL NUMPR,
        NULL PERCVENDA, NULL PERCLUCRO, NULL PERCMETA, SUM(TOTAL.VLVENDAPF) VLVENDAPF, SUM(TOTAL.VLVENDA) -
        SUM(TOTAL.VLVENDAPF) VLVENDAPJ, NULL PERCVENDAPF, NULL PERCVENDAPJ, NULL PERCPARTTOTAL,
        (DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(TOTAL.VLDEVOLAVULSAI)) / SUM(TOTAL.PESOBRUTO))) VLPESOTRANSP,
        SUM(TOTAL.VLDEVOLUCAO) VLDEVOLUCAO, SUM(TOTAL.VLDEVOLAVULSAI) VLDEVOLAVULSAI, SUM(TOTAL.VLDEVCMVAVULSAI) VLDEVCMVAVULSAI,
        SUM(TOTAL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, SUM(TOTAL.VLCMVDEVOL) VLCMVDEVOL, SUM(TOTAL.DEVOLTAB) DEVOLTAB,
        NVL(COUNT(DISTINCT TOTAL.CONTADOR), 0) CONTADOR ,NVL(COUNT(DISTINCT TOTAL.QTCLIPOS), 0) QTCLIPOS,COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO, NULL QTCLIENTE, DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) NUMDIAS,
        SUM(TOTAL.VLVENDA) VLVENDA, SUM(DISTINCT TOTAL.VALORTOTALNOTA) VALORTOTALNOTA,
        SUM(TOTAL.QTVENDA) QTVENDA, SUM(TOTAL.VLATEND) VLATEND, SUM(TOTAL.VLCUSTOFIN) VLCUSTOFIN, NULL CUSTOFINEST,
        SUM(TOTAL.VLCUSTOREAL) VLCUSTOREAL, SUM(TOTAL.VLESTDISP) VLESTDISP, AVG(TOTAL.CUSTOMEDFIN) CUSTOMEDFIN,
        AVG(TOTAL.CUSTOMEDREAL) CUSTOMEDREAL, SUM(TOTAL.VLTABELA) VLTABELA, SUM(TOTAL.PESOBRUTO) PESOBRUTO,
        SUM(TOTAL.VLBONIFIC) VLBONIFIC, NULL VLOUTRASDESP, NULL VLMEDBONIFIC, NULL QTBONIFIC,
        DECODE(SUM(TOTAL.VLTABELA), 0, -100,((SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100) PERCDESC, (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) VALORDESC,
        (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(TOTAL.VLDEVOLAVULSAI)) VLLIQUIDO, NULL VLMETA,
        SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA) VLFLEX, ';

   V_SQL := V_SQL || '(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLCUSTOFIN) - SUM(TOTAL.VLDEVOLUCAO) - SUM(VLDEVOLAVULSAI) +
         SUM(TOTAL.VLCMVDEVOL) + SUM(VLDEVCMVAVULSAI)) VLLUCRO, ';

   V_SQL :=
    V_SQL
    || ' DECODE(SUM(TOTAL.PRAZOMEDIO),0,0, SUM(TOTAL.PRAZOMEDIO) / SUM(TOTAL.VENDA_SEMDESCONTO)) PRAZOMEDIO, NULL PRAZOADICIONAL, DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
         SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO)) VLMEDIOKG, NULL CODCLIPRINC, NULL CLIENTEPRINC,
         NULL QTDEVOLUCAO, NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS, NULL SERIE, NULL CNPJ,
         NULL INSC, NULL CIDADE, NULL DESCSECAO, NULL DESCDEPTO, SUM(TOTAL.VLREPASSE) VLREPASSE,
         SUM(TOTAL.VLCMVDEVOLBONIF) VLCMVDEVOLBONIF, SUM(TOTAL.VLCMVANTESAPLVERBA) VLCMVANTESAPLVERBA,
         (SUM(TOTAL.VLLUCROANTESAPLVERBA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(VLDEVOLAVULSAI) + SUM(TOTAL.VLCMVDEVOL) + SUM(VLDEVCMVAVULSAI)) VLLUCROANTESAPLVERBA,
         NULL PERCLUCROANTESAPLVERBA FROM(';

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' SELECT VENDAS.NUMREGIAO,
                             0 VLDEVOLAVULSAI,
                 0 VLDEVCMVAVULSAI,
                 VENDAS.NUMTRANSVENDA CONTADOR,
                               VENDAS.CODCLI QTCLIPOS,
                 VENDAS.CODPROD QTMIXPRODUTO, ';
   ELSE
    V_SQL := V_SQL || ' SELECT VENDAS.NUMREGIAOMOV NUMREGIAO,
                             0 VLDEVOLAVULSAI,
                 0 VLDEVCMVAVULSAI,
                 VENDAS.NUMTRANSVENDA CONTADOR,
                               VENDAS.CODCLI QTCLIPOS,
                 VENDAS.CODPRODMOV QTMIXPRODUTO, ';
   END IF;

   V_SQL :=
    V_SQL
    || ' 0 VLDEVOLUCAO, 0 VLDEVOLBONIFIC, 0 VLCMVDEVOL, 0 DEVOLTAB,
         DECODE(SUM(VENDAS.VLVENDA), 0, 0, ROUND(SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA) / SUM(VENDAS.VLVENDA), 2)) NUMDIAS,
         DECODE(SUM(VENDAS.VLVENDA), 0, 0, SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA)) PRAZOMEDIO, SUM(VENDAS.VLVENDA) AS VENDA_SEMDESCONTO, ';

   IF P_DESCST = 0
   THEN
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND) VLATEND, SUM(VENDAS.VLCUSTOREAL) VLCUSTOREAL, SUM(VENDAS.VLTABELA) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2) VLBONIFIC, ';
      END IF;

      IF VERIFICAPF = TRUE
      THEN
       V_SQL := V_SQL || ' SUM(DECODE((CASE ';

       IF P_CONSIDTIPOFJ = 1
       THEN
        V_SQL := V_SQL || ' WHEN(PCCLIENT.TIPOFJ = ''F'') THEN ''S''';
       END IF;

       IF P_CONSIDCONSUMIDORFINAL = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.CONSUMIDORFINAL, ''N'') = ''S'') THEN ''S''';
       END IF;

       IF P_CONSIDISENTO = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTO'') THEN ''S''';
       END IF;

       IF P_CONSIDISENTA = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTA'') THEN ''S''';
       END IF;

       V_SQL := V_SQL || ' ELSE ''N'' END), ''S'', VENDAS.VLVENDA, 0)) VLVENDAPF, ';
      ELSE
       V_SQL := V_SQL || ' 0 VLVENDAPF, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ';

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND - VENDAS.VLREPASSE) VLATEND, SUM(VENDAS.VLCUSTOREAL - VENDAS.VLREPASSE) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - VENDAS.VLREPASSE) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2 - VENDAS.VLREPASSE) VLBONIFIC, ';
      END IF;

      IF VERIFICAPF = TRUE
      THEN
       V_SQL := V_SQL || ' SUM(DECODE((CASE ';

       IF P_CONSIDTIPOFJ = 1
       THEN
        V_SQL := V_SQL || ' WHEN(PCCLIENT.TIPOFJ = ''F'') THEN ''S''';
       END IF;

       IF P_CONSIDCONSUMIDORFINAL = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.CONSUMIDORFINAL, ''N'') = ''S'') THEN ''S''';
       END IF;

       IF P_CONSIDISENTO = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTO'') THEN ''S''';
       END IF;

       IF P_CONSIDISENTA = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTA'') THEN ''S''';
       END IF;

       V_SQL := V_SQL || ' ELSE ''N'' END), ''S'', VENDAS.VLVENDA - VENDAS.VLREPASSE, 0)) VLVENDAPF, ';
      ELSE
       V_SQL := V_SQL || ' 0 VLVENDAPF, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     END IF;
    ELSIF P_DESCIPI = 1
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC)) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND - VENDAS.VLIPI) VLATEND, SUM(VENDAS.VLCUSTOREAL - VENDAS.VLIPI) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.VLIPI) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - (VENDAS.VLIPIBONIFIC)) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2 - (VENDAS.VLIPIBONIFIC)) VLBONIFIC, ';
      END IF;

      IF VERIFICAPF = TRUE
      THEN
       V_SQL := V_SQL || ' SUM(DECODE((CASE ';

       IF P_CONSIDTIPOFJ = 1
       THEN
        V_SQL := V_SQL || ' WHEN(PCCLIENT.TIPOFJ = ''F'') THEN ''S''';
       END IF;

       IF P_CONSIDCONSUMIDORFINAL = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.CONSUMIDORFINAL, ''N'') = ''S'') THEN ''S''';
       END IF;

       IF P_CONSIDISENTO = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTO'') THEN ''S''';
       END IF;

       IF P_CONSIDISENTA = 1
       THEN
        V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTA'') THEN ''S''';
       END IF;

       V_SQL := V_SQL || ' ELSE ''N'' END), ''S'', VENDAS.VLVENDA - VENDAS.VLIPI, 0)) VLVENDAPF, ';
      ELSE
       V_SQL := V_SQL || ' 0 VLVENDAPF, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLIPI - (VENDAS.VLCUSTOFIN - VENDAS.VLIPI + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) + ' || V_VLVERBACMV || ' +
                                          ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - (VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) + ' || V_VLVERBACMV || ' +
                                           ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND - VENDAS.VLIPI - VENDAS.VLREPASSE) VLATEND,
           SUM(VENDAS.VLCUSTOREAL - VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.VLIPI - VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
