     ELSE
      V_SQL :=
       V_SQL || ' AND ((DEVOL.CONDVENDA NOT IN (4, 8, 10, 13, 20, 98, 99) AND (TEMVENDATV8 IS NOT NULL))
           OR (DEVOL.CONDVENDA NOT IN (4, 10, 13, 20, 98, 99) AND (TEMVENDATV8 IS NULL))) ';
     END IF;
    ELSE
     IF P_CONSIDERARDEVOLTV8 = 0
     THEN
      V_SQL := V_SQL || ' AND DEVOL.CONDVENDA NOT IN (4, 8, 13, 20, 98, 99) ';
     ELSE
      V_SQL := V_SQL || ' AND ((DEVOL.CONDVENDA NOT IN (4, 8, 13, 20, 98, 99) AND (TEMVENDATV8 IS NOT NULL))
           OR (DEVOL.CONDVENDA NOT IN (4, 13, 20, 98, 99) AND (TEMVENDATV8 IS NULL))) ';
     END IF;
    END IF;

    IF P_CONDVENDA IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND DEVOL.CONDVENDA IN (' || P_CONDVENDA || ') ';
    END IF;

    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' GROUP BY DEVOL.CODATIV ';
    ELSE
     V_SQL := V_SQL || ' GROUP BY DEVOL.CODATIVMOV ';
    END IF;

    V_SQL := V_SQL || ' UNION ALL SELECT AVULSA.CODATIV,  ';

    IF P_DESCST = 0
    THEN
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || '
                                   SUM(AVULSA.VLTOTAL) VLDEVOLAVULSAI,
                                   SUM(AVULSA.VLDEVCMVAVULSAI) VLDEVCMVAVULSAI,                    ';
      ELSE
       V_SQL :=
        V_SQL
        || '
                                   SUM(AVULSA.VLTOTAL - AVULSA.VLREPASSE) VLDEVOLAVULSAI,
                                   SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLREPASSE) VLDEVCMVAVULSAI,                   ';
      END IF;
     ELSIF P_DESCIPI = 1
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLIPI) VLDEVOLAVULSAI,
               SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLIPI) VLDEVCMVAVULSAI,    ';
      ELSE
       V_SQL :=
        V_SQL
        || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLIPI - AVULSA.VLREPASSE) VLDEVOLAVULSAI,
               SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLIPI - AVULSA.VLREPASSE) VLDEVCMVAVULSAI, ';
      END IF;
     END IF;
    ELSE
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL :=
        V_SQL
        || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLST) VLDEVOLAVULSAI,
                             SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST) VLDEVCMVAVULSAI,               ';
      ELSE
       V_SQL :=
        V_SQL
        || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLST - AVULSA.VLREPASSE) VLDEVOLAVULSAI,
               SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLREPASSE) VLDEVCMVAVULSAI, ';
      END IF;
     ELSIF P_DESCIPI = 1
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL :=
        V_SQL
        || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLST - AVULSA.VLIPI) VLDEVOLAVULSAI,
                             SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLIPI) VLDEVCMVAVULSAI,               ';
      ELSE
       V_SQL :=
        V_SQL
        || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLST - AVULSA.VLIPI - AVULSA.VLREPASSE) VLDEVOLAVULSAI,
                             SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLIPI - AVULSA.VLREPASSE) VLDEVCMVAVULSAI,               ';
      END IF;
     END IF;
    END IF;

    V_SQL :=
     V_SQL
     || '
                             NULL CONTADOR, NULL QTCLIPOS, NULL QTMIXPRODUTO, 0 VLDEVOLUCAO,
         0 VLDEVOLBONIFIC, 0 VLCMVDEVOL, 0 DEVOLTAB, 0 QTCLIENTE, 0 NUMDIAS, 0 PRAZOMEDIO, 0 AS VENDA_SEMDESCONTO,
         0 VLVENDA, -1 VALORTOTALNOTA, 0 VLCUSTOFIN, 0 VLATEND, 0 VLCUSTOREAL,
         0 VLTABELA, 0 VLBONIFIC, 0 VLCMVANTESAPLVERBA,
         0 VLLUCROANTESAPLVERBA, 0 QTVENDA, 0 VLESTDISP, 0 CUSTOMEDFIN, 0 CUSTOMEDREAL,
         0 PESOBRUTO, 0 VLREPASSE, 0 VLCMVDEVOLBONIF  FROM(('||V_SQL_VIEW_DEVOLAVULSA||')) AVULSA
         WHERE 1 = 1 ';

    IF P_CODFILIAL IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND AVULSA.CODFILIAL IN (' || P_CODFILIAL || ') ';
    END IF;

    --Filtros incluidos na rotina 111 - devolucao avulsa

   IF P_FILTROCODGERENTE IS NOT NULL THEN
    IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';


     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';

     END IF;
   END IF;

   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
       IF P_SUPERVMOV = 0 THEN
         V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';

     ELSE
        V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVMOV IN (' || P_FILTROCODSUPERVISOR || ')';
     END IF;
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSUR IN (' || P_FILTROCODUSUR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSURMOV IN (' || P_FILTROCODUSUR || ')';
     END IF;
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND AVULSA.CODFORNEC IN (' || P_FILTROCODFORNEC || ')';
      ELSE
        V_SQL := V_SQL || ' AND AVULSA.CODFORNECMOV IN (' || P_FILTROCODFORNEC || ')';
      END IF;
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODFORNECPRINC  IN (' || P_FILTROCODFORNECPRINC || ')';
   END IF;

   -- Fim dos filtros

    IF P_CODGERENTE <> 0 THEN
      IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND
                 AVULSA.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';

     ELSE
       V_SQL := V_SQL || ' AND
                 AVULSA.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     END IF;
    END IF;

    IF P_CODSUPERVISOR <> 0 THEN
       IF P_SUPERVMOV = 0 THEN
         V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVISOR = ' || P_CODSUPERVISOR;

     ELSE
        V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVMOV = ' || P_CODSUPERVISOR;
     END IF;
    END IF;

    IF P_CODRCA <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSUR = ' || P_CODRCA;
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSURMOV  = ' || P_CODRCA;
     END IF;
    END IF;

    IF P_CODFORNEC <> 0 THEN
      IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND AVULSA.CODFORNEC = ' || P_CODFORNEC;
      ELSE
        V_SQL := V_SQL || ' AND AVULSA.CODFORNECMOV = ' || P_CODFORNEC;
      END IF;
    END IF;

    IF P_CODFORNECPRINC <> 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODFORNECPRINC = ' || P_CODFORNECPRINC;
    END IF;

    IF P_CODMARCA <> 0 THEN
       V_SQL := V_SQL || ' AND
                      AVULSA.CODMARCA = ' || P_CODMARCA;
    END IF;

    IF P_CODLINHAPROD <> 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODLINHAPROD = ' || P_CODLINHAPROD;
    END IF;

    IF P_DATAINI IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND AVULSA.DTENT BETWEEN :DATAINI3 and :DATAFIM3 ';
    END IF;

    V_SQL := V_SQL || ' GROUP BY AVULSA.CODATIV ';
   END IF;

   V_SQL := V_SQL || ') TOTAL, PCATIVI WHERE PCATIVI.CODATIV = TOTAL.CODATIV
         GROUP BY TOTAL.CODATIV, PCATIVI.RAMO ORDER BY VLVENDA DESC ';
  WHEN P_TIPOPESQUISA = 14
  THEN
   -- Canceladas
   V_SQL :=
    ' SELECT NVL(PCNFSAID.CODFUNCCANCEL, 0) CODIGO, NULL CODIGO2,
    NULL CONDVENDA, NULL CODFILIAL, NULL NUMREGIAO, NULL CODUSUR, NULL NOMEUSUR,
    NULL UF, TO_DATE(PCNFSAID.DTSAIDA, ''DD/MM/YYYY  HH24:MI:SS'') DTSAIDA, SUBSTR(PCEMPR.NOME, 1, 40) DESCRICAO, NULL EMBALAGEM,
    NVL(PCNFSAID.NUMNOTA, 0) NUMNOTA, TO_DATE(PCNFSAID.DTCANCEL, ''DD/MM/YYYY  HH24:MI:SS'') DTCANCEL,
    NULL CODEPTO, NULL CODSEC,NULL CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL, NULL CODAUXILIAR, NULL PESOLIQ, NULL NUMPR,
    NULL PERCVENDA, NULL PERCLUCRO, NULL PERCMETA, NULL VLVENDAPF, NULL VLVENDAPJ, NULL PERCVENDAPF,
    NULL PERCVENDAPJ, NULL PERCPARTTOTAL, NULL VLPESOTRANSP, NULL VLDEVOLUCAO, NULL VLDEVOLAVULSAI,
    NULL VLDEVCMVAVULSAI, NULL VLDEVOLBONIFIC, NULL VLCMVDEVOL, NULL DEVOLTAB, COUNT(*) CONTADOR,
    NULL QTCLIPOS, NULL QTMIXPRODUTO, NULL QTCLIENTE, NULL NUMDIAS, NULL VLVENDA, -1 VALORTOTALNOTA, NULL QTVENDA,
    NULL VLATEND, NULL VLCUSTOFIN, NULL CUSTOFINEST, NULL VLCUSTOREAL, NULL VLESTDISP, NULL CUSTOMEDFIN,
    NULL CUSTOMEDREAL, NULL VLTABELA, NULL PESOBRUTO, NULL VLBONIFIC, NULL VLOUTRASDESP, NULL VLMEDBONIFIC,
    NULL QTBONIFIC, NULL PERCDESC, NULL VALORDESC, NULL VLLIQUIDO, NULL VLMETA, NULL VLFLEX, NULL VLLUCRO, NULL PRAZOMEDIO,
    NULL PRAZOADICIONAL, NULL VLMEDIOKG, NULL CODCLIPRINC, NULL CLIENTEPRINC, NULL QTDEVOLUCAO, NULL NUMTRANSVENDA,
    NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS, NULL SERIE, NULL CNPJ, NULL INSC, NULL CIDADE, NULL DESCSECAO,
    NULL DESCDEPTO, 0 VLREPASSE, 0 VLCMVDEVOLBONIF, 0 VLCMVANTESAPLVERBA, 0 VLLUCROANTESAPLVERBA, NULL PERCLUCROANTESAPLVERBA
    FROM PCNFSAID, PCEMPR
    WHERE 1 = 1 AND PCNFSAID.CODFUNCCANCEL = PCEMPR.MATRICULA
    AND NVL(PCNFSAID.TIPOVENDA, ''X'') NOT IN (''SR'', ''DF'') AND NVL(PCNFSAID.ESPECIE, ''X'') NOT IN (''CE'', ''CO'') ';

   IF P_CODFILIAL IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.CODFILIAL IN (' || P_CODFILIAL || ') ';
   END IF;

   --Filtros incluidos na rotina 111

   IF P_FILTROCODGERENTE IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCNFSAID.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCNFSAID.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCNFSAID.CODUSUR IN (' || P_FILTROCODUSUR || ')';
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     EXISTS(SELECT PCMOV.CODPROD FROM PCMOV, PCPRODUT WHERE PCMOV.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA
                              AND  PCMOV.CODPROD = PCPRODUT.CODPROD AND PCPRODUT.CODFORNEC IN (' || P_FILTROCODFORNEC || ') )';
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     EXISTS(SELECT PCMOV.CODPROD FROM PCMOV, PCPRODUT WHERE PCMOV.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA
                               AND PCMOV.CODPROD = PCPRODUT.CODPROD
                               AND PCPRODUT.CODFORNEC IN ( SELECT PCFORNEC.CODFORNEC FROM PCFORNEC
                                                            WHERE NVL(PCFORNEC.CODFORNECPRINC, PCFORNEC.CODFORNEC) IN (' || P_FILTROCODFORNECPRINC || ') ) )';
   END IF;

   -- Fim dos filtros

   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.DTSAIDA BETWEEN :DATAINI and :DATAFIM
                   AND PCNFSAID.CODFISCAL <> 0 ';
   END IF;

   IF P_CONSIDERANOTASAPROVADAS = 1
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.ESPECIE = ''NF''
                        AND PCNFSAID.SITUACAONFE in (100, 150)  ';
   END IF;

   IF P_DESCONSIDERARCLIVINCFORNEC = 1
   THEN
    V_SQL :=
     V_SQL
     || ' AND PCNFSAID.CODCLI NOT IN (SELECT DISTINCT F.CODCLI
                                                          FROM PCFORNEC F
                                                         WHERE F.CODCLI IS NOT NULL)';
   END IF;

   IF P_TIPOVENDA10 = 0
   THEN
    V_SQL := V_SQL || ' AND NVL(PCNFSAID.CONDVENDA, 0) NOT IN (4, 8, 10, 13, 20, 98, 99) ';
    V_SQL := V_SQL || ' AND PCNFSAID.CODFISCAL NOT IN (522, 622, 722, 532, 632, 732) ';
   ELSE
    V_SQL := V_SQL || ' AND NVL(PCNFSAID.CONDVENDA, 0) NOT IN (4, 8, 13, 20, 98, 99) ';
    V_SQL := V_SQL || ' AND PCNFSAID.CODFISCAL NOT IN (532, 632, 732) ';
   END IF;

   IF P_CONDVENDA IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.CONDVENDA IN (' || P_CONDVENDA || ') ';
   END IF;

   V_SQL := V_SQL || ' GROUP BY PCNFSAID.CODFUNCCANCEL, TO_DATE(PCNFSAID.DTSAIDA, ''DD/MM/YYYY  HH24:MI:SS''), PCEMPR.NOME, nvl(PCNFSAID.NUMNOTA, 0),
         TO_DATE(PCNFSAID.DTCANCEL, ''DD/MM/YYYY  HH24:MI:SS'') ORDER BY TO_DATE(PCNFSAID.DTSAIDA, ''DD/MM/YYYY  HH24:MI:SS''), NUMNOTA ';
  WHEN P_TIPOPESQUISA = 15
  THEN
   -- Consulta por fornecedor
   V_SQL :=
    ' SELECT TOTAL.CODFORNEC CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL, NULL NUMREGIAO,
    TOTAL.CODFORNECPRINC CODUSUR, SUBSTR(TOTAL.FORNECPRINC, 1, 40) NOMEUSUR, NULL UF, NULL DTSAIDA,
    SUBSTR(PCFORNEC.FORNECEDOR, 1, 40) DESCRICAO, NULL EMBALAGEM, NULL NUMNOTA, NULL DTCANCEL,
    NULL CODEPTO, NULL CODSEC,NULL CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL, NULL CODAUXILIAR, NULL PESOLIQ, NULL NUMPR,
    NULL PERCVENDA, NULL PERCLUCRO, NULL PERCMETA, NULL VLVENDAPF, NULL VLVENDAPJ, NULL PERCVENDAPF,
    NULL PERCVENDAPJ, NULL PERCPARTTOTAL, ROUND((DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
    SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO))), 6) VLPESOTRANSP, SUM(TOTAL.VLDEVOLUCAO) VLDEVOLUCAO,
    SUM(TOTAL.VLDEVOLAVULSAI) VLDEVOLAVULSAI, SUM(TOTAL.VLDEVCMVAVULSAI) VLDEVCMVAVULSAI, SUM(TOTAL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, SUM(TOTAL.VLCMVDEVOL) VLCMVDEVOL,
    SUM(TOTAL.DEVOLTAB) DEVOLTAB, NVL(COUNT(DISTINCT TOTAL.CONTADOR), 0) CONTADOR ,NVL(COUNT(DISTINCT TOTAL.QTCLIPOS), 0) QTCLIPOS,
    COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO, NULL QTCLIENTE,
    DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) NUMDIAS, SUM(TOTAL.VLVENDA) VLVENDA, SUM(TOTAL.VALORTOTALNOTA) VALORTOTALNOTA,
    SUM(TOTAL.QTVENDA) QTVENDA, SUM(TOTAL.VLATEND) VLATEND, SUM(TOTAL.VLCUSTOFIN) VLCUSTOFIN, NULL CUSTOFINEST,
    SUM(TOTAL.VLCUSTOREAL) VLCUSTOREAL, SUM(TOTAL.VLESTDISP) VLESTDISP, ROUND(AVG(TOTAL.CUSTOMEDFIN), 6) CUSTOMEDFIN,
    ROUND(AVG(TOTAL.CUSTOMEDREAL), 6) CUSTOMEDREAL, SUM(TOTAL.VLTABELA) VLTABELA, SUM(TOTAL.PESOBRUTO) PESOBRUTO,
    SUM(TOTAL.VLBONIFIC) VLBONIFIC, NULL VLOUTRASDESP, SUM(DECODE(TOTAL.QTBONIFIC, 0, 0, TOTAL.VLBONIFIC / TOTAL.QTBONIFIC)) VLMEDBONIFIC,
    SUM(TOTAL.QTBONIFIC) QTBONIFIC,
    ROUND(DECODE(SUM(TOTAL.VLTABELA), 0, -100,((SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100), 6) PERCDESC,
    (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) VALORDESC,
    (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(TOTAL.VLDEVOLAVULSAI)) VLLIQUIDO, NULL VLMETA, SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA) VLFLEX, ';

   V_SQL := V_SQL || '(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLCUSTOFIN) - SUM(TOTAL.VLDEVOLUCAO) - SUM(TOTAL.VLDEVOLAVULSAI) + SUM(TOTAL.VLDEVCMVAVULSAI) + SUM(TOTAL.VLCMVDEVOL)) VLLUCRO, ';

   V_SQL :=
    V_SQL
    || ' DECODE(SUM(TOTAL.PRAZOMEDIO),0,0, SUM(TOTAL.PRAZOMEDIO) / SUM(TOTAL.VENDA_SEMDESCONTO)) PRAZOMEDIO, NULL PRAZOADICIONAL, DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
         SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO)) VLMEDIOKG, NULL CODCLIPRINC, PCFORNEC.FANTASIA CLIENTEPRINC, NULL QTDEVOLUCAO,
         NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS, NULL SERIE, NULL CNPJ, NULL INSC, NULL CIDADE,
         NULL DESCSECAO, NULL DESCDEPTO, SUM(TOTAL.VLREPASSE) VLREPASSE, SUM(TOTAL.VLCMVDEVOLBONIF) VLCMVDEVOLBONIF,
         SUM(TOTAL.VLCMVANTESAPLVERBA) VLCMVANTESAPLVERBA, (SUM(TOTAL.VLLUCROANTESAPLVERBA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(VLDEVOLAVULSAI) +
         SUM(TOTAL.VLCMVDEVOL) + SUM(VLDEVCMVAVULSAI)) VLLUCROANTESAPLVERBA,
         NULL PERCLUCROANTESAPLVERBA FROM(';

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' SELECT VENDAS.CODFORNEC, VENDAS.NUMTRANSVENDA CONTADOR,  VENDAS.CODCLI QTCLIPOS, VENDAS.CODPROD QTMIXPRODUTO, ';
   ELSE
    V_SQL := V_SQL || ' SELECT VENDAS.CODFORNECMOV CODFORNEC, VENDAS.NUMTRANSVENDA CONTADOR, VENDAS.CODCLI QTCLIPOS, VENDAS.CODPRODMOV QTMIXPRODUTO, ';
   END IF;

   V_SQL :=
    V_SQL
    || ' VENDAS.CODFORNECPRINC, VENDAS.FORNECPRINC, 0 VLDEVOLUCAO, 0 VLDEVOLBONIFIC, 0 VLCMVDEVOL, 0 DEVOLTAB, ROUND(DECODE(SUM(VENDAS.VLVENDA), 0, 0,
         SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA) / SUM(VENDAS.VLVENDA)), 2) NUMDIAS, DECODE(SUM(VENDAS.VLVENDA), 0, 0,
         SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA)) PRAZOMEDIO, SUM(VENDAS.VLVENDA) AS VENDA_SEMDESCONTO, ';

   IF P_DESCST = 0
   THEN
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND) VLATEND, SUM(VENDAS.VLCUSTOREAL) VLCUSTOREAL, SUM(VENDAS.VLTABELA) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2) VLBONIFIC, ';
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
