        V_SQL
        || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLIPI - AVULSA.VLREPASSE) VLDEVOLAVULSAI,
               SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLIPI - AVULSA.VLREPASSE) VLDEVCMVAVULSAI, ';
      END IF;
     END IF;
    ELSE
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL :=
        V_SQL
        || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLST) VLDEVOLAVULSAI,
                             SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST) VLDEVCMVAVULSAI,               ';
      ELSE
       V_SQL :=
        V_SQL
        || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLST - AVULSA.VLREPASSE) VLDEVOLAVULSAI,
               SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLREPASSE) VLDEVCMVAVULSAI, ';
      END IF;
     ELSIF P_DESCIPI = 1
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL :=
        V_SQL
        || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLST - AVULSA.VLIPI) VLDEVOLAVULSAI,
                             SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLIPI) VLDEVCMVAVULSAI,               ';
      ELSE
       V_SQL :=
        V_SQL
        || '
                             SUM(AVULSA.VLTOTAL - AVULSA.VLST - AVULSA.VLIPI - AVULSA.VLREPASSE) VLDEVOLAVULSAI,
                             SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLIPI - AVULSA.VLREPASSE) VLDEVCMVAVULSAI,               ';
      END IF;
     END IF;
    END IF;

    V_SQL := V_SQL || '   0 VLREPASSE, 0 VLCMVDEVOLBONIF
                      FROM ('||V_SQL_VIEW_DEVOLAVULSA||') AVULSA WHERE 1 = 1 ';

    IF P_CODFILIAL IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND AVULSA.CODFILIAL IN (' || P_CODFILIAL || ') ';
    END IF;

    --Filtros incluidos na rotina 111 - devolucao avulsa

   IF P_FILTROCODGERENTE IS NOT NULL THEN
      IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';


     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';

     END IF;
   END IF;

   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
       IF P_SUPERVMOV = 0 THEN
         V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';

     ELSE
        V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVMOV IN (' || P_FILTROCODSUPERVISOR || ')';
     END IF;
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSUR IN (' || P_FILTROCODUSUR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSURMOV IN (' || P_FILTROCODUSUR || ')';
     END IF;
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
      IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND AVULSA.CODFORNEC IN (' || P_FILTROCODFORNEC || ')';
      ELSE
        V_SQL := V_SQL || ' AND AVULSA.CODFORNECMOV IN (' || P_FILTROCODFORNEC || ')';
      END IF;
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODFORNECPRINC  IN (' || P_FILTROCODFORNECPRINC || ')';
   END IF;

   -- Fim dos filtros
    IF P_CODGERENTE <> 0 THEN
      IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND
                 AVULSA.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';

     ELSE
       V_SQL := V_SQL || ' AND
                 AVULSA.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     END IF;
    END IF;

    IF P_CODSUPERVISOR <> 0 THEN
       IF P_SUPERVMOV = 0 THEN
         V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVISOR = ' || P_CODSUPERVISOR;

     ELSE
        V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVMOV = ' || P_CODSUPERVISOR;
     END IF;
    END IF;

    IF P_CODRCA <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSUR = ' || P_CODRCA;
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSURMOV  = ' || P_CODRCA;
     END IF;
    END IF;

    IF P_CODFORNEC <> 0 THEN
      IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND AVULSA.CODFORNEC = ' || P_CODFORNEC;
      ELSE
        V_SQL := V_SQL || ' AND AVULSA.CODFORNECMOV = ' || P_CODFORNEC;
      END IF;
    END IF;

    IF P_CODFORNECPRINC <> 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODFORNECPRINC = ' || P_CODFORNECPRINC;
    END IF;

    IF P_CODMARCA <> 0 THEN
       V_SQL := V_SQL || ' AND
                      AVULSA.CODMARCA = ' || P_CODMARCA;
    END IF;

    IF P_CODLINHAPROD <> 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODLINHAPROD = ' || P_CODLINHAPROD;
    END IF;

    IF P_DATAINI IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND AVULSA.DTENT BETWEEN :DATAINI4 and :DATAFIM4 ';
    END IF;

    IF P_DESCONSIDERARCLIVINCFORNEC = 1
    THEN
     V_SQL :=
      V_SQL
      || ' AND AVULSA.CODCLI NOT IN (SELECT DISTINCT F.CODCLI
                                                      FROM PCFORNEC F
                                                     WHERE F.CODCLI IS NOT NULL)';
    END IF;
   END IF;

   V_SQL := V_SQL || ') TOTAL ';
  -----------------------------------------------------Início Consulta por RCA
  WHEN P_TIPOPESQUISA = 22
  THEN
   -- Consulta por RCA

   V_SQL :=
    ' SELECT TOTAL.CODSUPERVISOR CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL, NULL NUMREGIAO,
    TOTAL.CODUSUR CODUSUR, SUBSTR(PCUSUARI.NOME, 1, 40) NOMEUSUR, NULL UF, NULL DTSAIDA, SUBSTR(PCSUPERV.NOME, 1, 40) DESCRICAO,
    NULL EMBALAGEM, NULL NUMNOTA, NULL DTCANCEL, NULL CODEPTO, NULL CODSEC,NULL CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL, NULL CODAUXILIAR, NULL PESOLIQ,
    NULL NUMPR, NULL PERCVENDA, NULL PERCLUCRO, NULL PERCMETA, ';

   IF P_UF IS NULL
   THEN
    V_SQL := V_SQL || ' NULL VLVENDAPF, NULL VLVENDAPJ, NULL PERCVENDAPF, NULL PERCVENDAPJ, ';
   ELSE
    V_SQL :=
     V_SQL
     || ' SUM(TOTAL.VLVENDAPF) VLVENDAPF, SUM(TOTAL.VLVENDA) - SUM(NVL(TOTAL.VLVENDAPF, 0)) VLVENDAPJ,
         SUM(DECODE(TOTAL.VLVENDA, 0, 0,(NVL(TOTAL.VLVENDAPF, 0) / TOTAL.VLVENDA) * 100)) PERCVENDAPF,
         SUM(DECODE(TOTAL.VLVENDA, 0, 0,((TOTAL.VLVENDA - NVL(TOTAL.VLVENDAPF, 0)) / TOTAL.VLVENDA) * 100)) PERCVENDAPJ, ';
   END IF;

   V_SQL :=
    V_SQL
    || ' NULL PERCPARTTOTAL,(DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO) -
         SUM(TOTAL.VLDEVOLAVULSAI)) / SUM(TOTAL.PESOBRUTO))) VLPESOTRANSP, SUM(TOTAL.VLDEVOLUCAO) VLDEVOLUCAO,
         SUM(TOTAL.VLDEVOLAVULSAI) VLDEVOLAVULSAI, SUM(TOTAL.VLDEVCMVAVULSAI) VLDEVCMVAVULSAI, SUM(TOTAL.VLDEVOLBONIFIC) VLDEVOLBONIFIC,
         SUM(TOTAL.VLCMVDEVOL) VLCMVDEVOL, SUM(TOTAL.DEVOLTAB) DEVOLTAB, NVL(COUNT(DISTINCT TOTAL.CONTADOR), 0) CONTADOR ,NVL(COUNT(DISTINCT TOTAL.QTCLIPOS), 0) QTCLIPOS,
         COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO,
         NULL QTCLIENTE, DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) NUMDIAS, SUM(TOTAL.VLVENDA) VLVENDA,
         (SUM(TOTAL.VALORTOTALNOTA)) VALORTOTALNOTA, SUM(TOTAL.QTVENDA) QTVENDA,
         SUM(TOTAL.VLATEND) VLATEND, SUM(TOTAL.VLCUSTOFIN) VLCUSTOFIN, NULL CUSTOFINEST, SUM(TOTAL.VLCUSTOREAL) VLCUSTOREAL,
         SUM(TOTAL.VLESTDISP) VLESTDISP, AVG(TOTAL.CUSTOMEDFIN) CUSTOMEDFIN, AVG(TOTAL.CUSTOMEDREAL) CUSTOMEDREAL,
         SUM(TOTAL.VLTABELA) VLTABELA, SUM(TOTAL.PESOBRUTO) PESOBRUTO, SUM(TOTAL.VLBONIFIC) VLBONIFIC, NULL VLOUTRASDESP,
         NULL VLMEDBONIFIC, NULL QTBONIFIC, DECODE(SUM(TOTAL.VLTABELA), 0, -100,((SUM(TOTAL.VLVENDA) -
         SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100) PERCDESC, (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) VALORDESC,
         (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(TOTAL.VLDEVOLAVULSAI)) VLLIQUIDO, MAX(NVL((SELECT SUM(NVL(PCMETARCA.VLVENDAPREV, 0)) FROM PCMETARCA
         WHERE PCMETARCA.CODUSUR = TOTAL.CODUSUR ';

   IF P_CODFILIAL IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCMETARCA.CODFILIAL IN (' || P_CODFILIAL || ') ';
   END IF;

   --Filtros incluidos na rotina 111

   IF P_FILTROCODGERENTE IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCMETARCA.CODUSUR IN ( SELECT PCUSUARI.CODUSUR FROM PCUSUARI, PCSUPERV
                                             WHERE PCUSUARI.CODSUPERVISOR = PCSUPERV.CODSUPERVISOR
                                               AND PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCMETARCA.CODUSUR IN ( SELECT PCUSUARI.CODUSUR FROM PCUSUARI
                                             WHERE PCUSUARI.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ') )';

   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     PCMETARCA.CODUSUR IN (' || P_FILTROCODUSUR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     TOTAL.CODUSUR IN (' || P_FILTROCODUSUR || ')';
     END IF;
   END IF;

   -- Fim dos filtros

   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCMETARCA.DATA BETWEEN :DATAINI and :DATAFIM ';
   END IF;

   V_SQL := V_SQL || '), 0)) VLMETA, SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA) VLFLEX, ';

   V_SQL := V_SQL || '(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLCUSTOFIN) - SUM(TOTAL.VLDEVOLUCAO) - SUM(VLDEVOLAVULSAI) +
         SUM(TOTAL.VLCMVDEVOL) + SUM(VLDEVCMVAVULSAI)) VLLUCRO, ';

   V_SQL :=
    V_SQL
    || ' DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.PRAZOMEDIO) / SUM(TOTAL.VLVENDA)) PRAZOMEDIO, NULL PRAZOADICIONAL, DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
         SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO)) VLMEDIOKG, NULL CODCLIPRINC, NULL CLIENTEPRINC, NULL QTDEVOLUCAO,
         NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS, NULL SERIE, NULL CNPJ, NULL INSC, NULL CIDADE,
         NULL DESCSECAO, NULL DESCDEPTO, SUM(TOTAL.VLREPASSE) VLREPASSE, SUM(TOTAL.VLCMVDEVOLBONIF) VLCMVDEVOLBONIF,
         SUM(TOTAL.VLCMVANTESAPLVERBA) VLCMVANTESAPLVERBA, (SUM(TOTAL.VLLUCROANTESAPLVERBA) - SUM(TOTAL.VLDEVOLUCAO) -
         SUM(VLDEVOLAVULSAI) + SUM(TOTAL.VLCMVDEVOL) + SUM(VLDEVCMVAVULSAI)) VLLUCROANTESAPLVERBA,
         NULL PERCLUCROANTESAPLVERBA
         FROM(SELECT COUNT(1) AS DIVIDIVALORTOTAL, 0 CONDVENDA, ';

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' VENDAS.CODUSUR,
                      VENDAS.CODSUPERVISOR,
            0 VLDEVOLAVULSAI,
            0 VLDEVCMVAVULSAI,
            VENDAS.NUMTRANSVENDA CONTADOR,
                        VENDAS.CODCLI QTCLIPOS,
                    VENDAS.CODPROD QTMIXPRODUTO, ';
   ELSE
    V_SQL := V_SQL || ' VENDAS.CODUSURMOV CODUSUR,
                      VENDAS.CODSUPERVMOV CODSUPERVISOR,
            0 VLDEVOLAVULSAI,
            0 VLDEVCMVAVULSAI,
            VENDAS.NUMTRANSVENDA CONTADOR,
                        VENDAS.CODCLI QTCLIPOS,
            VENDAS.CODPRODMOV QTMIXPRODUTO, ';
   END IF;

   V_SQL :=
    V_SQL
    || ' 0 VLDEVOLUCAO, 0 VLDEVOLBONIFIC, 0 VLCMVDEVOL, 0 DEVOLTAB,
         ROUND(DECODE(SUM(VENDAS.VLVENDA), 0, 0, SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA) / SUM(VENDAS.VLVENDA)), 2) NUMDIAS,
         DECODE(SUM(VENDAS.VLVENDA), 0, 0, SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA)) PRAZOMEDIO, SUM(VENDAS.VLVENDA) AS VENDA_SEMDESCONTO, ';

   V_SQL := V_SQL || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
   || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

   IF P_CODFILIAL IS NOT NULL
   THEN
    V_SQL := V_SQL ||
      ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
   END IF;

   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
   END IF;

   V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL))/((SELECT COUNT(DISTINCT CODPROD) FROM PCMOV A WHERE A.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA)) AS VALORTOTALNOTA, ';

   IF P_DESCST = 0
   THEN
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA) VLVENDA,
                                 ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND) VLATEND, SUM(VENDAS.VLCUSTOREAL) VLCUSTOREAL, SUM(VENDAS.VLTABELA) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2) VLBONIFIC, ';
      END IF;

      IF P_UF IS NOT NULL
      THEN
       IF VERIFICAPF = TRUE
       THEN
        V_SQL := V_SQL || ' SUM(DECODE((CASE ';

        IF P_CONSIDTIPOFJ = 1
        THEN
         V_SQL := V_SQL || ' WHEN(PCCLIENT.TIPOFJ = ''F'') THEN ''S''';
        END IF;

        IF P_CONSIDCONSUMIDORFINAL = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.CONSUMIDORFINAL, ''N'') = ''S'') THEN ''S''';
        END IF;

        IF P_CONSIDISENTO = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTO'') THEN ''S''';
        END IF;

        IF P_CONSIDISENTA = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTA'') THEN ''S''';
        END IF;

        V_SQL := V_SQL || ' ELSE ''N'' END), ''S'', VENDAS.VLVENDA, 0)) VLVENDAPF, ';
       ELSE
        V_SQL := V_SQL || ' 0 VLVENDAPF, ';
       END IF;
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                  ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE) VLVENDA,';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND - VENDAS.VLREPASSE) VLATEND, SUM(VENDAS.VLCUSTOREAL - VENDAS.VLREPASSE) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - VENDAS.VLREPASSE) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2 - VENDAS.VLREPASSE) VLBONIFIC, ';
      END IF;

      IF P_UF IS NOT NULL
      THEN
       IF VERIFICAPF = TRUE
       THEN
        V_SQL := V_SQL || ' SUM(DECODE((CASE ';

        IF P_CONSIDTIPOFJ = 1
        THEN
         V_SQL := V_SQL || ' WHEN(PCCLIENT.TIPOFJ = ''F'') THEN ''S''';
        END IF;

        IF P_CONSIDCONSUMIDORFINAL = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.CONSUMIDORFINAL, ''N'') = ''S'') THEN ''S''';
        END IF;

        IF P_CONSIDISENTO = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTO'') THEN ''S''';
        END IF;

        IF P_CONSIDISENTA = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTA'') THEN ''S''';
        END IF;

        V_SQL := V_SQL || ' ELSE ''N'' END), ''S'', VENDAS.VLVENDA - VENDAS.VLREPASSE, 0)) VLVENDAPF, ';
       ELSE
        V_SQL := V_SQL || ' 0 VLVENDAPF, ';
       END IF;
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     END IF;
    ELSIF P_DESCIPI = 1
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI) VLVENDA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC)) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND - VENDAS.VLIPI) VLATEND, SUM(VENDAS.VLCUSTOREAL - VENDAS.VLIPI) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.VLIPI) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - (VENDAS.VLIPIBONIFIC)) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - (VENDAS.VLIPIBONIFIC)) VLBONIFIC, ';
      END IF;

      IF P_UF IS NOT NULL
      THEN
       IF VERIFICAPF = TRUE
       THEN
        V_SQL := V_SQL || ' SUM(DECODE((CASE ';

        IF P_CONSIDTIPOFJ = 1
        THEN
         V_SQL := V_SQL || ' WHEN(PCCLIENT.TIPOFJ = ''F'') THEN ''S''';
        END IF;

        IF P_CONSIDCONSUMIDORFINAL = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.CONSUMIDORFINAL, ''N'') = ''S'') THEN ''S''';
        END IF;

