   V_SQL := V_SQL || ' GROUP BY TOTAL.CODSUPERVISOR, TOTAL.CODUSUR, PCUSUARI.NOME, PCSUPERV.NOME
         ORDER BY TOTAL.CODSUPERVISOR, TOTAL.CODUSUR, VLVENDA DESC ';

