  TO_DATE(VENDAS.DTCANCEL, ''DD/MM/YYYY HH24:MI:SS'') DTCANCEL,
    NULL CODEPTO, NULL CODSEC, NULL CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL, NULL CODAUXILIAR, NULL PESOLIQ, NULL NUMPR, NULL PERCVENDA,
