         WHERE N.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA AND NVL(N.TIPOFJ, VENDAS.TIPOFJ) = ''F'')) CONTADOR,
         NULL QTCLIPOS, NULL QTMIXPRODUTO,  COUNT(DISTINCT(SELECT VENDAS.CODCLI FROM PCNFSAID N WHERE N.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA
         AND NVL(N.TIPOFJ, VENDAS.TIPOFJ) = ''F'')) QTCLIENTE, ';
   ELSE
    V_SQL := V_SQL || ' NULL CONTADOR, NULL QTCLIPOS, NULL QTMIXPRODUTO, NULL QTCLIENTE, ';
   END IF;

   V_SQL := V_SQL || ' NULL NUMDIAS, ';

   IF V_SQL3 IS NOT NULL
   THEN
    IF P_DESCST = 0
    THEN
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA) VLVENDA, '
       || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
       || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

       IF P_CODFILIAL IS NOT NULL
       THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
       END IF;

       IF P_DATAINI IS NOT NULL
       THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
       END IF;

       V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE) VLVENDA, '
       || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
       || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

       IF P_CODFILIAL IS NOT NULL
       THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
       END IF;

       IF P_DATAINI IS NOT NULL
       THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
       END IF;

       V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';
      END IF;
     ELSE
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI) VLVENDA, '
