      END IF;
     END IF;
    END IF;
   ELSE
    V_SQL := V_SQL || ' NULL VLVENDA, -1 VALORTOTALNOTA, ';
   END IF;

   V_SQL := V_SQL || ' NULL QTVENDA, NULL VLATEND, ';

   IF P_DESCST = 0
   THEN
