    USING P_DATAINI
        , P_DATAFIM;


   VLVENDATOT := NVL(VLVENDATOT,0);

   V_SQL :=
    ' SELECT NULL CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL, NULL NUMREGIAO, NULL CODUSUR,
    NULL NOMEUSUR, NULL UF, NULL DTSAIDA, TOTAL.DESCRICAO, NULL EMBALAGEM, NULL NUMNOTA, NULL DTCANCEL,
