      V_SQL := V_SQL || ' DECODE(SUM(TOTAL.PRAZOMEDIO),0,0, SUM(TOTAL.PRAZOMEDIO) / SUM(TOTAL.VLVENDA)) PRAZOMEDIO, ';
    ELSE
      V_SQL := V_SQL || ' DECODE(SUM(TOTAL.VLVENDA), 0, 0, SUM(NOTA.PRAZOMEDIO * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) PRAZOMEDIO, ';
    END IF;

     V_SQL := V_SQL || ' NULL PRAZOADICIONAL, NULL VLMEDIOKG, NULL CODCLIPRINC,
