           THEN
            V_SQL := V_SQL || ' SUM((((CASE WHEN (SELECT TIPOVLVENDA FROM PCPARAMPLANOVOO) = ''DEDUZIRFRETE'' THEN
                                              PCNFSAID.VLTOTGER - PCNFSAID.VLFRETE
                                            WHEN (SELECT TIPOVLVENDA FROM PCPARAMPLANOVOO) = ''DEDUZIROUTRASDESP'' THEN
                                              PCNFSAID.VLTOTGER - PCNFSAID.VLOUTRASDESP
                                            WHEN (SELECT TIPOVLVENDA FROM PCPARAMPLANOVOO) = ''DEDUZIRAMBOS'' THEN
                                              PCNFSAID.VLTOTGER - PCNFSAID.VLFRETE - PCNFSAID.VLOUTRASDESP
                                            ELSE
                                              PCNFSAID.VLTOTGER
                                            END) - NVL(PCNFSAID.ICMSRETIDO, 0)) / ' || REPLACE(TO_CHAR(NVL(VLVENDATOT, 1)), ',', '.') || ') * 100) PERCVENDA, ';
           ELSE
            V_SQL := V_SQL || ' SUM(((PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0)) / ' || REPLACE(TO_CHAR(NVL(VLVENDATOT, 1)), ',', '.') || ') * 100) PERCVENDA, ';
           END IF;
          ELSE
           V_SQL := V_SQL || ' 0 PERCVENDA, ';
          END IF;
         ELSE
          IF VLVENDATOT > 0
          THEN
           IF P_CODEMITENTE IS NOT NULL
           THEN
            V_SQL :=
             V_SQL
             || ' SUM((((CASE WHEN (SELECT TIPOVLVENDA FROM PCPARAMPLANOVOO) = ''DEDUZIRFRETE'' THEN
                                              PCNFSAID.VLTOTGER - PCNFSAID.VLFRETE
                                            WHEN (SELECT TIPOVLVENDA FROM PCPARAMPLANOVOO) = ''DEDUZIROUTRASDESP'' THEN
                                              PCNFSAID.VLTOTGER - PCNFSAID.VLOUTRASDESP
