             || ' SUM(((PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) -
                 (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT) * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
                 FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) / '
