                                            END) - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0)) / ' || REPLACE(TO_CHAR(NVL(VLVENDATOT, 1)), ',', '.') || ') * 100) PERCVENDA, ';
           ELSE
            V_SQL := V_SQL || ' SUM(((PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0)) / ' || REPLACE(TO_CHAR(NVL(VLVENDATOT, 1)), ',', '.') || ') * 100) PERCVENDA, ';
           END IF;
          ELSE
           V_SQL := V_SQL || ' 0 PERCVENDA, ';
          END IF;
         ELSE
