                                            ELSE
                                              PCNFSAID.VLTOTGER
                                            END) - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0)) VLVENDA,
                             MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF WHERE NF.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA)) AS VALORTOTALNOTA, ';
          ELSE
           V_SQL :=
            V_SQL
            || ' SUM((CASE WHEN (SELECT TIPOVLVENDA FROM PCPARAMPLANOVOO) = ''DEDUZIRFRETE'' THEN
                                              PCNFSAID.VLTOTGER - PCNFSAID.VLFRETE
                                            WHEN (SELECT TIPOVLVENDA FROM PCPARAMPLANOVOO) = ''DEDUZIROUTRASDESP'' THEN
                                              PCNFSAID.VLTOTGER - PCNFSAID.VLOUTRASDESP
                                            WHEN (SELECT TIPOVLVENDA FROM PCPARAMPLANOVOO) = ''DEDUZIRAMBOS'' THEN
                                              PCNFSAID.VLTOTGER - PCNFSAID.VLFRETE - PCNFSAID.VLOUTRASDESP
                                            ELSE
                                              PCNFSAID.VLTOTGER
                                            END) - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0) -
                 (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT) * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
                 FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) VLVENDA,
                             MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF WHERE NF.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA)) AS VALORTOTALNOTA, ';
          END IF;
         END IF;
        END IF;
       ELSE
        IF P_DESCST = 0
        THEN
         IF P_DESCIPI = 0
         THEN
          IF P_DESCVLREPASSE = 0
          THEN
           V_SQL :=
            V_SQL || ' SUM(PCNFSAID.VLTOTGER) VLVENDA,
                                     MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF WHERE NF.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA)) AS VALORTOTALNOTA, ';
          ELSE
           V_SQL :=
            V_SQL
            || ' SUM(PCNFSAID.VLTOTGER-
                 (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT) * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
                 FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) VLVENDA,
                             MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF WHERE NF.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA)) AS VALORTOTALNOTA, ';
          END IF;
         ELSE
