          IF P_DESCVLREPASSE = 0
          THEN
           V_SQL :=
            V_SQL
            || ' SUM(PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0)) VLVENDA,
                             MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF WHERE NF.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA)) AS VALORTOTALNOTA, ';
          ELSE
           V_SQL :=
            V_SQL
            || ' SUM(PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) -
                 (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT) * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
                 FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) VLVENDA,
                             MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF WHERE NF.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA)) AS VALORTOTALNOTA, ';
          END IF;
         ELSE
          IF P_DESCVLREPASSE = 0
          THEN
           V_SQL :=
            V_SQL
            || ' SUM(PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0)) VLVENDA,
                             MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF WHERE NF.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA)) AS VALORTOTALNOTA, ';
          ELSE
           V_SQL :=
            V_SQL
            || ' SUM(PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0) -
                 (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT) * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
                 FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) VLVENDA,
                             MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF WHERE NF.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA)) AS VALORTOTALNOTA, ';
          END IF;
         END IF;
        END IF;
       END IF;

       V_SQL := V_SQL || ' SUM(NVL(PCNFSAID.VLBONIFIC, 0)) VLBONIFIC, ';

       IF P_CODEMITENTE IS NOT NULL
       THEN
        V_SQL := V_SQL || ' 0 PRAZOMEDIO ';
       ELSE
        V_SQL := V_SQL || ' SUM(NVL(PCNFSAID.VLTOTGER,0) * NVL(PCNFSAID.PRAZOMEDIO,0)) PRAZOMEDIO ';
       END IF;

       V_SQL := V_SQL || ' FROM PCNFSAID, PCPEDC, PCUSUARI, PCPLPAG, PCCLIENT, ';



       V_SQL := V_SQL || ' PCCOB
                        WHERE PCNFSAID.CODCOB = PCCOB.CODCOB
                          AND PCNFSAID.CODCOB NOT IN (''BNF'', ''BNFT'', ''BNFR'', ''BNFN'', ''BNTR'', ''BNRP'', ''DEVT'', ''DEVP'', ''DESD'')';

   ELSE

       V_SQL := V_SQL || ' SUM(PCPREST.VALOR) / ' ||  REPLACE(TO_CHAR(NVL(VLVENDATOT, 1)), ',', '.') || ' * 100 PERCVENDA,
                              COUNT(PCNFSAID.NUMTRANSVENDA) CONTADOR,
                              0 VLDEVOLUCAO,
                              0 VLDEVOLBONIFIC,
                              0 VLCMVDEVOL,
                              0 DEVOLTAB,
                              SUM(PCPREST.VALOR) VLVENDA,
                              MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF WHERE NF.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA)) AS VALORTOTALNOTA,
                              0 VLBONIFIC, ';
        IF P_CODEMITENTE IS NOT NULL THEN
          V_SQL := V_SQL || ' 0 PRAZOMEDIO ';
        ELSE
          V_SQL := V_SQL ||' DECODE(SUM(PCPREST.VALOR),
                                     0,
                                     0,
                                     SUM(PCNFSAID.PRAZOMEDIO * PCPREST.VALOR) / SUM(PCPREST.VALOR)) PRAZOMEDIO ';
       END IF;
      
    	V_SQL := V_SQL || '  ,PCNFSAID.NUMTRANSVENDA ';
	   
        V_SQL := V_SQL ||'    FROM PCNFSAID, PCPEDC, PCUSUARI, PCPLPAG, PCCLIENT, PCPREST, PCCOB
                       WHERE PCPREST.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA
                         AND PCPREST.CODCOB = PCCOB.CODCOB ';
       IF (V_DESDCARTAOFECHCARGA = 'N') AND (P_CODEMITENTE IS NULL) AND P_CONSIDERACOBRANCATITULOS = 1 THEN
         V_SQL := V_SQL || ' AND CASE WHEN PCCOB.CARTAO = ''S'' AND PCPREST.VPAGO = 0 THEN ''DESD'' ELSE PCPREST.CODCOB END NOT IN (''BNF'', ''BNFT'', ''BNFR'', ''BNFN'', ''BNTR'',''BNRP'', ''DEVT'', ''DEVP'', ''DESD'') ';
       ELSE
         V_SQL := V_SQL || ' AND PCPREST.CODCOB NOT IN (''BNF'', ''BNFT'', ''BNFR'', ''BNFN'', ''BNTR'', ''BNRP'', ''DEVT'', ''DEVP'', ''DESD'') ';
       END IF;
   END IF;


   IF P_CODEMITENTE IS NOT NULL
