    V_SQL :=
     V_SQL
     || ' AND PCNFSAID.NUMPED = PCPEDC.NUMPED(+)
         AND PCNFSAID.DTCANCEL IS NULL
         AND NVL(PCNFSAID.TIPOVENDA, ''X'') NOT IN (''SR'', ''DF'') ';
   ELSE
    V_SQL :=
     V_SQL
     || ' AND PCNFSAID.NUMPED = PCPEDC.NUMPED(+)
         AND PCNFSAID.DTCANCEL IS NULL
         AND NVL(PCNFSAID.TIPOVENDA, ''X'') NOT IN (''SR'', ''DF'') ';
   END IF;

   IF P_CONSIDERANOTASAPROVADAS = 1
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.ESPECIE = ''NF''
                        AND PCNFSAID.SITUACAONFE in (100, 150)  ';
   END IF;

   V_SQL :=
    V_SQL
    || ' AND PCNFSAID.CODUSUR = PCUSUARI.CODUSUR
         AND PCNFSAID.CODPLPAG = PCPLPAG.CODPLPAG(+)
         AND PCNFSAID.CODCLI = PCCLIENT.CODCLI
               AND NVL(PCNFSAID.TIPOVENDA, ''X'') NOT IN (''SR'', ''DF'')         ';


   IF P_CODFILIAL IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.CODFILIAL IN (' || P_CODFILIAL || ') ';
   END IF;

   --Filtros incluidos na rotina 111

   IF P_FILTROCODGERENTE IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCNFSAID.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCNFSAID.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCNFSAID.CODUSUR IN (' || P_FILTROCODUSUR || ')';
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     EXISTS(SELECT PCMOV.CODPROD FROM PCMOV, PCPRODUT WHERE PCMOV.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA
                              AND  PCMOV.CODPROD = PCPRODUT.CODPROD AND PCPRODUT.CODFORNEC IN (' || P_FILTROCODFORNEC || ') )';
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     EXISTS(SELECT PCMOV.CODPROD FROM PCMOV, PCPRODUT WHERE PCMOV.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA
                               AND PCMOV.CODPROD = PCPRODUT.CODPROD
                               AND PCPRODUT.CODFORNEC IN ( SELECT PCFORNEC.CODFORNEC FROM PCFORNEC
                                                            WHERE NVL(PCFORNEC.CODFORNECPRINC, PCFORNEC.CODFORNEC) IN (' || P_FILTROCODFORNECPRINC || ') ) )';
   END IF;

   -- Fim dos filtros

   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.DTSAIDA BETWEEN :DATAINI and :DATAFIM
                   AND PCNFSAID.CODFISCAL <> 0 ';
   END IF;

   IF P_ORIGEMPED IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCPEDC.ORIGEMPED = ''' || P_ORIGEMPED || '''';
   END IF;

   IF P_TIPOVENDA10 = 0
   THEN
    V_SQL := V_SQL || ' AND NVL(PCNFSAID.CONDVENDA, 0) NOT IN (4, 8, 10, 13, 20, 98, 99)
         AND PCNFSAID.CODFISCAL NOT IN (522, 622, 722, 532, 632, 732) ';
   ELSE
    V_SQL := V_SQL || ' AND NVL(PCNFSAID.CONDVENDA, 0) NOT IN (4, 8, 13, 20, 98, 99)
         AND PCNFSAID.CODFISCAL NOT IN (532, 632, 732) ';
   END IF;

