   V_SQL := V_SQL || ' GROUP BY TO_DATE(S.DTSAIDA, ''DD/MM/YYYY  HH24:MI:SS''), S.CODFILIAL, s.NUMTRANSVENDA UNION ALL ';

   IF P_DESCST = 0
   THEN
