           (SELECT MIN(DATA) FROM PCDATAS DT WHERE DT.DATA >= PCMOV.DTMOV AND DT.DIAUTIL = ''S'') END DTSAIDA,
           NULL VLVENDA, -1 VALORTOTALNOTA, SUM(PCMOV.QT * (NVL(PCMOV.PUNIT, 0) - NVL(PCMOV.VLIPI, 0) - NVL(PCMOV.VLREPASSE, 0))) VLTABELA,
           PCMOV.CODFILIAL, SUM(PCMOV.VLREPASSE * PCMOV.QT) VLREPASSE FROM PCNFENT, PCMOV ';
