           SUM(PCMOV.QT * (NVL(PCMOV.PUNIT, 0) - NVL(PCMOV.ST, 0))) VLTABELA, PCMOV.CODFILIAL, SUM(PCMOV.VLREPASSE * PCMOV.QT) VLREPASSE FROM PCNFENT,
