           DTSAIDA, NULL VLVENDA, -1 VALORTOTALNOTA, SUM(PCMOV.QT * (NVL(PCMOV.PUNIT, 0) - NVL(PCMOV.ST, 0) - NVL(PCMOV.VLIPI, 0))) VLTABELA,
