           SUM(PCMOV.QT * (NVL(PCMOV.PUNIT, 0) - NVL(PCMOV.ST, 0) - NVL(PCMOV.VLIPI, 0) - NVL(PCMOV.VLREPASSE, 0))) VLTABELA, PCMOV.CODFILIAL,
