      V_SQL2 :=
       ' SELECT SUM('|| V_SQLTITULOS ||' - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0) -
      (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
      FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) FROM PCNFSAID
      WHERE PCNFSAID.DTCANCEL IS NULL
      AND PCNFSAID.CODCOB NOT IN (''BNF'', ''BNFT'', ''BNFR'', ''BNFN'', ''BNTR'', ''BNRP'', ''DEVT'', ''DEVP'', ''DESD'')
            AND NVL(PCNFSAID.TIPOVENDA, ''X'') NOT IN (''SR'', ''DF'')      ';

      IF P_TIPOVENDA10 = 0
      THEN
       V_SQL2 := V_SQL2 || ' AND PCNFSAID.CODFISCAL NOT IN (522, 622, 722, 532, 632, 732) ';
      ELSE
       V_SQL2 := V_SQL2 || ' AND PCNFSAID.CODFISCAL NOT IN (532, 632, 732) ';
      END IF;
     END IF;
    END IF;
   END IF;

   IF P_CONSIDERANOTASAPROVADAS = 1
   THEN
    V_SQL2 := V_SQL2 || ' AND PCNFSAID.ESPECIE = ''NF''
                        AND PCNFSAID.SITUACAONFE in (100, 150)  ';
   END IF;

   IF P_CODFILIAL IS NOT NULL
   THEN
    V_SQL2 := V_SQL2 || ' AND PCNFSAID.CODFILIAL IN (' || P_CODFILIAL || ') ';
   END IF;

   --Filtros incluidos na rotina 111

   IF P_FILTROCODGERENTE IS NOT NULL THEN
       V_SQL2 := V_SQL2 || ' AND
                     PCNFSAID.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
       V_SQL2 := V_SQL2 || ' AND
                     PCNFSAID.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
       V_SQL2 := V_SQL2 || ' AND
                     PCNFSAID.CODUSUR IN (' || P_FILTROCODUSUR || ')';
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       V_SQL2 := V_SQL2 || ' AND
                     EXISTS(SELECT PCMOV.CODPROD FROM PCMOV, PCPRODUT WHERE PCMOV.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA
                              AND  PCMOV.CODPROD = PCPRODUT.CODPROD AND PCPRODUT.CODFORNEC IN (' || P_FILTROCODFORNEC || ') )';
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL2 := V_SQL2 || ' AND
                     EXISTS(SELECT PCMOV.CODPROD FROM PCMOV, PCPRODUT WHERE PCMOV.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA
                               AND PCMOV.CODPROD = PCPRODUT.CODPROD
                               AND PCPRODUT.CODFORNEC IN ( SELECT PCFORNEC.CODFORNEC FROM PCFORNEC
                                                            WHERE NVL(PCFORNEC.CODFORNECPRINC, PCFORNEC.CODFORNEC) IN (' || P_FILTROCODFORNECPRINC || ') ) )';
   END IF;

   -- Fim dos filtros

   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL2 := V_SQL2 || ' AND PCNFSAID.DTSAIDA BETWEEN :DATAINI and :DATAFIM
                    AND NVL(PCNFSAID.TIPOVENDA, ''X'') NOT IN (''SR'', ''DF'')          ';
   END IF;

   IF P_TIPOVENDA10 = 0
   THEN
    V_SQL2 := V_SQL2 || ' AND NVL(PCNFSAID.CONDVENDA, 0) NOT IN (4, 8, 10, 13, 20, 98, 99)
          AND PCNFSAID.CODFISCAL NOT IN (522, 622, 722, 532, 632, 732) ';
   ELSE
    V_SQL2 := V_SQL2 || ' AND NVL(PCNFSAID.CONDVENDA, 0) NOT IN (4, 8, 13, 20, 98, 99)
          AND PCNFSAID.CODFISCAL NOT IN (532, 632, 732) ';
   END IF;

   IF P_CONDVENDA IS NOT NULL
   THEN
    V_SQL2 := V_SQL2 || ' AND PCNFSAID.CONDVENDA IN (' || P_CONDVENDA || ') ';
   END IF;

   EXECUTE IMMEDIATE TO_CHAR(V_SQL2)
    INTO VLTITULO
    USING P_DATAINI
        , P_DATAFIM;

   -- Verificando total de venda
   V_SQL3 := ' SELECT ';

   IF P_DESCST = 0
   THEN
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL3 := V_SQL3 || ' SUM(VENDAS.VLVENDA) VLVENDA ';
     ELSE
      V_SQL3 := V_SQL3 || ' SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE) VLVENDA ';
     END IF;
    ELSIF P_DESCIPI = 1
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL3 := V_SQL3 || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI) VLVENDA ';
     ELSE
      V_SQL3 := V_SQL3 || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI - VENDAS.VLREPASSE) VLVENDA ';
     END IF;
    END IF;
   ELSE
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL3 := V_SQL3 || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO) VLVENDA ';
     ELSE
      V_SQL3 := V_SQL3 || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLVENDA ';
     END IF;
    ELSIF P_DESCIPI = 1
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL3 := V_SQL3 || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI) VLVENDA ';
     ELSE
      V_SQL3 := V_SQL3 || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE) VLVENDA ';
     END IF;
    END IF;
   END IF;

   V_SQL3 := V_SQL3 || ' FROM((' || V_SQL_GERAL ||')) VENDAS WHERE 1 = 1 ';

   IF P_CODFILIAL IS NOT NULL
   THEN
    V_SQL3 := V_SQL3 || ' AND VENDAS.CODFILIAL IN (' || P_CODFILIAL || ') ';
   END IF;

   --Filtros incluidos na rotina 111

   IF P_FILTROCODGERENTE IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     ELSE
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     END IF;
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
     ELSE
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODSUPERVMOV IN (' || P_FILTROCODSUPERVISOR || ')';
     END IF;
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODUSUR IN (' || P_FILTROCODUSUR || ')';
     ELSE
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODUSURMOV IN (' || P_FILTROCODUSUR || ')';
     END IF;
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODFORNEC IN (' || P_FILTROCODFORNEC || ')';
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODFORNECPRINC  IN (' || P_FILTROCODFORNECPRINC || ')';
   END IF;

   -- Fim dos filtros


   IF P_CODGERENTE <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     ELSE
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     END IF;
   END IF;

   IF P_CODSUPERVISOR <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODSUPERVISOR = ' || P_CODSUPERVISOR;
     ELSE
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODSUPERVMOV = ' || P_CODSUPERVISOR;
     END IF;
   END IF;

   IF P_CODRCA <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODUSUR = ' || P_CODRCA;
     ELSE
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODUSURMOV = ' || P_CODRCA;
     END IF;
   END IF;

   IF P_CODFORNEC <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL3 := V_SQL3 || ' AND VENDAS.CODFORNEC = ' || P_CODFORNEC;
     ELSE
       V_SQL3 := V_SQL3 || ' AND VENDAS.CODFORNECMOV = ' || P_CODFORNEC;
     END IF;
   END IF;

   IF P_CODFORNECPRINC <> 0 THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODFORNECPRINC = ' || P_CODFORNECPRINC;
   END IF;

   IF P_CODMARCA <> 0 THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODMARCA = ' || P_CODMARCA;
   END IF;

   IF P_CODLINHAPROD <> 0 THEN
       V_SQL3 := V_SQL3 || ' AND
                     VENDAS.CODLINHAPROD = ' || P_CODLINHAPROD;
   END IF;


   IF P_CONSIDERANOTASAPROVADAS = 1
   THEN
    V_SQL3 := V_SQL3 || ' AND VENDAS.ESPECIE = ''NF''
                        AND VENDAS.SITUACAONFE in (100, 150) ';
   END IF;

   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL3 := V_SQL3 || ' AND VENDAS.DTSAIDA BETWEEN :DATAINI2 and :DATAFIM2
    AND VENDAS.QTBONIFIC >= 0 ';
   END IF;

   IF P_TIPOVENDA10 = 0
   THEN
    V_SQL3 := V_SQL3 || ' AND NVL(VENDAS.CONDVENDA, -1) IN (1, 5, -1, 7, 9, 11, 14) ';
    V_SQL3 := V_SQL3 || ' AND VENDAS.CODFISCAL NOT IN (522, 622, 722, 532, 632, 732) ';
   ELSE
    V_SQL3 := V_SQL3 || ' AND NVL(VENDAS.CONDVENDA, -1) IN (1, 5, -1, 7, 9, 11, 14, 10)';
    V_SQL3 := V_SQL3 || ' AND VENDAS.CODFISCAL NOT IN (532, 632, 732) ';
   END IF;

   IF P_CONDVENDA IS NOT NULL
   THEN
    V_SQL3 := V_SQL3 || ' AND NVL(VENDAS.CONDVENDA, 0) IN (' || P_CONDVENDA || ') ';
   END IF;

   EXECUTE IMMEDIATE TO_CHAR(V_SQL3)
    INTO VLVENDATOT
    USING P_DATAINI
        , P_DATAFIM;

   V_SQL :=
    ' SELECT NULL CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL, NULL NUMREGIAO, NULL CODUSUR, NULL NOMEUSUR, NULL UF,
    TO_DATE(PCNFSAID.DTSAIDA, ''DD/MM/YYYY  HH24:MI:SS'') DTSAIDA, SUBSTR(PCCOB.COBRANCA, 1, 30) DESCRICAO, NULL EMBALAGEM, NULL NUMNOTA, NULL DTCANCEL, NULL CODEPTO, NULL CODSEC,NULL CODCATEGORIA, NULL CODSUBCATEGORIA,
    NULL NUMORIGINAL, PCCOB.CODCOB CODAUXILIAR, NULL PESOLIQ, NULL NUMPR, ';

    IF P_CONSIDERACOBRANCATITULOS = 0 THEN
     IF P_DESCST = 0
     THEN
      IF P_DESCIPI = 0
      THEN
       IF P_DESCVLREPASSE = 0
       THEN
        V_SQL := V_SQL || ' SUM((PCNFSAID.VLTOTGER / ' || NVL(REPLACE(TO_CHAR(VLVENDATOT), ',', '.'), 1) || ') * 100) PERCVENDA, ';
       ELSE
        V_SQL :=
         V_SQL
         || ' SUM(((PCNFSAID.VLTOTGER - (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE,
             PCMOV.QT * PCMOV.VLREPASSE), 2), 0)) FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) / '
         || NVL(REPLACE(TO_CHAR(VLVENDATOT), ',', '.'), 1)
         || ') * 100) PERCVENDA, ';
       END IF;
      ELSE
       IF P_DESCVLREPASSE = 0
       THEN
        V_SQL := V_SQL || ' SUM(((PCNFSAID.VLTOTGER - NVL(PCNFSAID.VLIPI, 0)) / ' || NVL(REPLACE(TO_CHAR(VLVENDATOT), ',', '.'), 1) || ') * 100) PERCVENDA, ';
       ELSE
        V_SQL :=
         V_SQL
         || ' SUM(((PCNFSAID.VLTOTGER - NVL(PCNFSAID.VLIPI, 0) - (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7,
             DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
             FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) / '
         || NVL(REPLACE(TO_CHAR(VLVENDATOT), ',', '.'), 1)
         || ') * 100) PERCVENDA, ';
       END IF;
      END IF;
     ELSE
      IF P_DESCIPI = 0
      THEN
       IF P_DESCVLREPASSE = 0
       THEN
        V_SQL := V_SQL || ' SUM(((PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0)) / ' || NVL(REPLACE(TO_CHAR(VLVENDATOT), ',', '.'), 1) || ') * 100) PERCVENDA, ';
       ELSE
        V_SQL :=
         V_SQL
         || ' SUM(((PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) -
             (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
             FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) / '
         || NVL(REPLACE(TO_CHAR(VLVENDATOT), ',', '.'), 1)
         || ') * 100) PERCVENDA, ';
       END IF;
      ELSE
       IF P_DESCVLREPASSE = 0
       THEN
        V_SQL := V_SQL || ' SUM(((PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0)) / ' || NVL(REPLACE(TO_CHAR(VLVENDATOT), ',', '.'), 1) || ') * 100) PERCVENDA, ';
       ELSE
        V_SQL :=
         V_SQL
         || ' SUM(((PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0) -
             (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
             FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) / '
         || NVL(REPLACE(TO_CHAR(VLVENDATOT), ',', '.'), 1)
         || ') * 100) PERCVENDA, ';
       END IF;
      END IF;
     END IF;

     V_SQL :=
      V_SQL
      || ' NULL PERCLUCRO, NULL PERCMETA, NULL VLVENDAPF, NULL VLVENDAPJ, NULL PERCVENDAPF,
           NULL PERCVENDAPJ, NULL PERCPARTTOTAL, NULL VLPESOTRANSP, NULL VLDEVOLUCAO, NULL VLDEVOLAVULSAI,
           NULL VLDEVCMVAVULSAI, NULL VLDEVOLBONIFIC, NULL VLCMVDEVOL, NULL DEVOLTAB, COUNT(DISTINCT PCNFSAID.NUMTRANSVENDA) CONTADOR,
           NULL QTCLIPOS, NULL QTMIXPRODUTO, NULL QTCLIENTE, NULL NUMDIAS, ';

     IF P_DESCST = 0
     THEN
      IF P_DESCIPI = 0
      THEN
       IF P_DESCVLREPASSE = 0
       THEN
        V_SQL := V_SQL || ' SUM(PCNFSAID.VLTOTGER) VLVENDA,
                                  -1 AS VALORTOTALNOTA, ';
       ELSE
        V_SQL :=
         V_SQL
         || ' SUM(PCNFSAID.VLTOTGER - (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7,
             DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0)) FROM PCMOV
             WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) VLVENDA,
                        -1 AS VALORTOTALNOTA, ';
       END IF;
      ELSE
       IF P_DESCVLREPASSE = 0
       THEN
        V_SQL := V_SQL || ' SUM(PCNFSAID.VLTOTGER - NVL(PCNFSAID.VLIPI, 0)) VLVENDA,
                         -1 AS VALORTOTALNOTA, ';
       ELSE
        V_SQL :=
         V_SQL
         || ' SUM(PCNFSAID.VLTOTGER - NVL(PCNFSAID.VLIPI, 0) -
             (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
             FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) VLVENDA,
                         -1 AS VALORTOTALNOTA, ';
       END IF;
      END IF;
     ELSE
      IF P_DESCIPI = 0
      THEN
       IF P_DESCVLREPASSE = 0
       THEN
        V_SQL := V_SQL || ' SUM(PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0)) VLVENDA,
                        -1 AS VALORTOTALNOTA, ';
       ELSE
        V_SQL :=
         V_SQL
         || ' SUM(PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) -
             (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
             FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) VLVENDA,
                         -1 AS VALORTOTALNOTA, ';
       END IF;
      ELSE
       IF P_DESCVLREPASSE = 0
       THEN
        V_SQL := V_SQL || ' SUM(PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0)) VLVENDA,
                         -1 AS VALORTOTALNOTA, ';
       ELSE
        V_SQL :=
         V_SQL
         || ' SUM(PCNFSAID.VLTOTGER - NVL(PCNFSAID.ICMSRETIDO, 0) - NVL(PCNFSAID.VLIPI, 0) -
             (SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
             FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) VLVENDA,
                         -1 AS VALORTOTALNOTA, ';
       END IF;
      END IF;
     END IF;

     V_SQL := V_SQL ||
                   '
                                 NULL QTVENDA, NULL VLATEND, NULL VLCUSTOFIN,
           NULL CUSTOFINEST, NULL VLCUSTOREAL, NULL VLESTDISP, NULL CUSTOMEDFIN, NULL CUSTOMEDREAL, NULL VLTABELA,
           NULL PESOBRUTO, NULL VLBONIFIC, NULL VLOUTRASDESP, NULL VLMEDBONIFIC, NULL QTBONIFIC, NULL PERCDESC, NULL VALORDESC,
           NULL VLLIQUIDO, NULL VLMETA, NULL VLFLEX, NULL VLLUCRO,
           DECODE(SUM(PCNFSAID.VLTOTGER),
                               0,
                               0,
                               SUM(PCNFSAID.PRAZOMEDIO * PCNFSAID.VLTOTGER) / SUM(PCNFSAID.VLTOTGER)) PRAZOMEDIO,
            NULL PRAZOADICIONAL, NULL VLMEDIOKG, NULL CODCLIPRINC,
           NULL CLIENTEPRINC, NULL QTDEVOLUCAO, NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS, NULL SERIE,
           NULL CNPJ, NULL INSC, NULL CIDADE, NULL DESCSECAO, NULL DESCDEPTO,
           MAX((SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
           FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) VLREPASSE, 0 VLCMVDEVOLBONIF,
           NULL VLCMVANTESAPLVERBA, NULL VLLUCROANTESAPLVERBA, NULL PERCLUCROANTESAPLVERBA
           FROM PCNFSAID, PCCOB
           WHERE PCNFSAID.CODCOB = PCCOB.CODCOB(+) AND PCNFSAID.DTCANCEL IS NULL
           AND PCNFSAID.CODCOB NOT IN (''BNF'', ''BNFT'', ''BNFR'', ''BNFN'', ''BNTR'', ''BNRP'', ''DEVT'', ''DEVP'', ''DESD'') ';

   ELSE
      V_SQL := V_SQL || ' SUM(PCPREST.VALOR) / ' ||  REPLACE(TO_CHAR(VLVENDATOT), ',', '.') || ' * 100 PERCVENDA,
             NULL PERCLUCRO, NULL PERCMETA, NULL VLVENDAPF, NULL VLVENDAPJ, NULL PERCVENDAPF,
           NULL PERCVENDAPJ, NULL PERCPARTTOTAL, NULL VLPESOTRANSP, NULL VLDEVOLUCAO, NULL VLDEVOLAVULSAI,
           NULL VLDEVCMVAVULSAI, NULL VLDEVOLBONIFIC, NULL VLCMVDEVOL, NULL DEVOLTAB, COUNT(DISTINCT PCNFSAID.NUMTRANSVENDA) CONTADOR,
           NULL QTCLIPOS, NULL QTMIXPRODUTO, NULL QTCLIENTE, NULL NUMDIAS,
             SUM(PCPREST.VALOR) VLVENDA,
            -1 AS VALORTOTALNOTA,

            NULL QTVENDA, NULL VLATEND, NULL VLCUSTOFIN,
           NULL CUSTOFINEST, NULL VLCUSTOREAL, NULL VLESTDISP, NULL CUSTOMEDFIN, NULL CUSTOMEDREAL, NULL VLTABELA,
           NULL PESOBRUTO, NULL VLBONIFIC, NULL VLOUTRASDESP, NULL VLMEDBONIFIC, NULL QTBONIFIC, NULL PERCDESC, NULL VALORDESC,
           NULL VLLIQUIDO, NULL VLMETA, NULL VLFLEX, NULL VLLUCRO,
           DECODE(SUM(PCPREST.VALOR)
             ,0
             ,0
             ,SUM(PCPREST.VALOR * PCNFSAID.VLTOTGER) /
              SUM(PCPREST.VALOR)) PRAZOMEDIO,
            NULL PRAZOADICIONAL, NULL VLMEDIOKG, NULL CODCLIPRINC,
           NULL CLIENTEPRINC, NULL QTDEVOLUCAO, NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS, NULL SERIE,
           NULL CNPJ, NULL INSC, NULL CIDADE, NULL DESCSECAO, NULL DESCDEPTO,
           MAX((SELECT SUM(NVL(ROUND(DECODE(PCNFSAID.CONDVENDA, 7, DECODE(NVL(PCMOV.TIPOITEM,''C''),''C'',PCMOV.QT,PCMOV.QTCONT)  * PCMOV.VLREPASSE, PCMOV.QT * PCMOV.VLREPASSE), 2), 0))
           FROM PCMOV WHERE PCNFSAID.NUMTRANSVENDA = PCMOV.NUMTRANSVENDA)) VLREPASSE, 0 VLCMVDEVOLBONIF,
           NULL VLCMVANTESAPLVERBA, NULL VLLUCROANTESAPLVERBA, NULL PERCLUCROANTESAPLVERBA
           FROM PCNFSAID, PCCOB, PCPREST
           WHERE PCPREST.CODCOB = PCCOB.CODCOB(+)
           AND PCNFSAID.DTCANCEL IS NULL
           AND PCPREST.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA';

          IF (V_DESDCARTAOFECHCARGA = 'N') AND (P_CODEMITENTE IS NULL) AND P_CONSIDERACOBRANCATITULOS = 1 THEN
            V_SQL := V_SQL || ' AND CASE WHEN PCCOB.CARTAO = ''S'' AND PCPREST.VPAGO = 0 THEN ''DESD'' ELSE PCPREST.CODCOB END NOT IN (''BNF'', ''BNFT'', ''BNFR'', ''BNFN'', ''BNTR'',''BNRP'', ''DEVT'', ''DEVP'', ''DESD'') ';
          ELSE
            V_SQL := V_SQL || ' AND PCPREST.CODCOB NOT IN (''BNF'', ''BNFT'', ''BNFR'', ''BNFN'', ''BNTR'', ''BNRP'', ''DEVT'', ''DEVP'', ''DESD'') ';
          END IF;


   END IF;


   IF P_CODFILIAL IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.CODFILIAL IN (' || P_CODFILIAL || ') ';
   END IF;

   --Filtros incluidos na rotina 111

   IF P_FILTROCODGERENTE IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCNFSAID.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCNFSAID.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     PCNFSAID.CODUSUR IN (' || P_FILTROCODUSUR || ')';
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     EXISTS(SELECT PCMOV.CODPROD FROM PCMOV, PCPRODUT WHERE PCMOV.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA
                              AND  PCMOV.CODPROD = PCPRODUT.CODPROD AND PCPRODUT.CODFORNEC IN (' || P_FILTROCODFORNEC || ') )';
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     EXISTS(SELECT PCMOV.CODPROD FROM PCMOV, PCPRODUT WHERE PCMOV.NUMTRANSVENDA = PCNFSAID.NUMTRANSVENDA
                               AND PCMOV.CODPROD = PCPRODUT.CODPROD
                               AND PCPRODUT.CODFORNEC IN ( SELECT PCFORNEC.CODFORNEC FROM PCFORNEC
                                                            WHERE NVL(PCFORNEC.CODFORNECPRINC, PCFORNEC.CODFORNEC) IN (' || P_FILTROCODFORNECPRINC || ') ) )';
   END IF;

   -- Fim dos filtros

   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.DTSAIDA BETWEEN :DATAINI and :DATAFIM
           AND NVL(PCNFSAID.TIPOVENDA, ''X'') NOT IN (''SR'', ''DF'')
           AND PCNFSAID.CODFISCAL <> 0   ';
   END IF;

   IF P_TIPOVENDA10 = 0
   THEN
    V_SQL := V_SQL || ' AND NVL(PCNFSAID.CONDVENDA, 0) NOT IN (4, 8, 10, 13, 20, 98, 99)
         AND PCNFSAID.CODFISCAL NOT IN (522, 622, 722, 532, 632, 732) ';
   ELSE
    V_SQL := V_SQL || ' AND NVL(PCNFSAID.CONDVENDA, 0) NOT IN (4, 8, 13, 20, 98, 99)
         AND PCNFSAID.CODFISCAL NOT IN (532, 632, 732) ';
   END IF;

   IF P_CONSIDERANOTASAPROVADAS = 1
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.ESPECIE = ''NF''
                        AND PCNFSAID.SITUACAONFE in (100, 150)  ';
   END IF;

   IF P_CONDVENDA IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND PCNFSAID.CONDVENDA IN (' || P_CONDVENDA || ') ';
   END IF;
   V_SQL := V_SQL || ' GROUP BY TO_DATE(PCNFSAID.DTSAIDA, ''DD/MM/YYYY  HH24:MI:SS''), PCCOB.CODCOB, PCCOB.COBRANCA';

   VALOR_VENDA := (NVL(VLVENDATOT,0) - NVL(VLTITULO,0));

   IF ABS(VALOR_VENDA) >= 0.01 AND P_CODEMITENTE IS NULL
   THEN
    V_SQL :=
     V_SQL
     || ' UNION ALL SELECT NULL CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL,
         NULL NUMREGIAO, NULL CODUSUR, NULL NOMEUSUR, NULL UF, NULL DTSAIDA,
         ''TÍTULOS(CRÉDITOS, DESCONTOS, JUROS, DEVOLUÇÕES...)'' DESCRICAO,
         NULL EMBALAGEM, NULL NUMNOTA, NULL DTCANCEL, NULL CODEPTO, NULL CODSEC,NULL CODCATEGORIA, NULL CODSUBCATEGORIA,
         NULL NUMORIGINAL, ''Dif'' CODAUXILIAR, NULL PESOLIQ, NULL NUMPR,(:VLVENDA / '
     || NVL(REPLACE(REPLACE(TO_CHAR(VLVENDATOT), ',', '.'), ',', '.'), 1)
     || ') * 100 PERCVENDA, NULL PERCLUCRO, NULL PERCMETA, NULL VLVENDAPF,
         NULL VLVENDAPJ, NULL PERCVENDAPF, NULL PERCVENDAPJ, NULL PERCPARTTOTAL,
         NULL VLPESOTRANSP, NULL VLDEVOLUCAO, NULL VLDEVOLAVULSAI, NULL VLDEVCMVAVULSAI,
         NULL VLDEVOLBONIFIC, NULL VLCMVDEVOL, NULL DEVOLTAB, NULL CONTADOR, NULL QTCLIPOS, NULL QTMIXPRODUTO,
         NULL QTCLIENTE, NULL NUMDIAS, :VLVENDA VLVENDA, -1 VALORTOTALNOTA,
          NULL QTVENDA, NULL VLATEND, NULL VLCUSTOFIN, NULL CUSTOFINEST,
         NULL VLCUSTOREAL, NULL VLESTDISP, NULL CUSTOMEDFIN, NULL CUSTOMEDREAL, NULL VLTABELA,
         NULL PESOBRUTO, NULL VLBONIFIC, NULL VLOUTRASDESP, NULL VLMEDBONIFIC, NULL QTBONIFIC,
         NULL PERCDESC, NULL VALORDESC, NULL VLLIQUIDO, NULL VLMETA, NULL VLFLEX, NULL VLLUCRO, NULL PRAZOMEDIO, NULL PRAZOADICIONAL,
         NULL VLMEDIOKG, NULL CODCLIPRINC, NULL CLIENTEPRINC, NULL QTDEVOLUCAO, NULL NUMTRANSVENDA,
         NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS, NULL SERIE, NULL CNPJ, NULL INSC, NULL CIDADE,
         NULL DESCSECAO, NULL DESCDEPTO, 0 VLREPASSE, 0 VLCMVDEVOLBONIF,
         NULL VLCMVANTESAPLVERBA, NULL VLLUCROANTESAPLVERBA, NULL PERCLUCROANTESAPLVERBA FROM DUAL ORDER BY DTSAIDA, VLVENDA DESC ';


   END IF;

  WHEN P_TIPOPESQUISA = 30
  THEN
   -- Consulta por Comprador
   V_SQL :=
    ' SELECT TOTAL.CODCOMPRADOR CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL, NULL NUMREGIAO,
    NULL CODUSUR, NULL NOMEUSUR, NULL UF, NULL DTSAIDA, SUBSTR(PCEMPR.NOME, 1, 40) DESCRICAO, NULL EMBALAGEM,
    NULL NUMNOTA, NULL DTCANCEL, NULL CODEPTO, NULL CODSEC,NULL CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL, NULL CODAUXILIAR, NULL PESOLIQ,
    NULL NUMPR, NULL PERCVENDA, NULL PERCLUCRO, NULL PERCMETA, NULL VLVENDAPF, NULL VLVENDAPJ, NULL PERCVENDAPF,
    NULL PERCVENDAPJ, NULL PERCPARTTOTAL,(DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
    SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO))) VLPESOTRANSP, SUM(TOTAL.VLDEVOLUCAO) VLDEVOLUCAO,
    NULL VLDEVOLAVULSAI, NULL VLDEVCMVAVULSAI, SUM(TOTAL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, SUM(TOTAL.VLCMVDEVOL) VLCMVDEVOL,
    SUM(TOTAL.DEVOLTAB) DEVOLTAB, NVL(COUNT(DISTINCT TOTAL.CONTADOR), 0) CONTADOR ,NVL(COUNT(DISTINCT TOTAL.QTCLIPOS), 0) QTCLIPOS,
    COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO, NULL QTCLIENTE,
    DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) NUMDIAS, SUM(TOTAL.VLVENDA) VLVENDA, SUM(DISTINCT TOTAL.VALORTOTALNOTA) VALORTOTALNOTA,
    SUM(TOTAL.QTVENDA) QTVENDA, SUM(TOTAL.VLATEND) VLATEND, SUM(TOTAL.VLCUSTOFIN) VLCUSTOFIN, NULL CUSTOFINEST,
    SUM(TOTAL.VLCUSTOREAL) VLCUSTOREAL, SUM(TOTAL.VLESTDISP) VLESTDISP, AVG(TOTAL.CUSTOMEDFIN) CUSTOMEDFIN,
    AVG(TOTAL.CUSTOMEDREAL) CUSTOMEDREAL, SUM(TOTAL.VLTABELA) VLTABELA, SUM(TOTAL.PESOBRUTO) PESOBRUTO,
    SUM(TOTAL.VLBONIFIC) VLBONIFIC, NULL VLOUTRASDESP, SUM(DECODE(TOTAL.QTBONIFIC, 0, 0, TOTAL.VLBONIFIC / TOTAL.QTBONIFIC)) VLMEDBONIFIC,
    SUM(TOTAL.QTBONIFIC) QTBONIFIC, DECODE(SUM(TOTAL.VLTABELA), 0, -100,
    ((SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100) PERCDESC, (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) VALORDESC,
    (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO)) VLLIQUIDO,
    NULL VLMETA, SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA) VLFLEX, ';

   V_SQL := V_SQL || '(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLCUSTOFIN) - SUM(TOTAL.VLDEVOLUCAO) + SUM(TOTAL.VLCMVDEVOL)) VLLUCRO, ';

   V_SQL :=
    V_SQL
    || ' DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.PRAZOMEDIO) / SUM(TOTAL.VENDA_SEMDESCONTO)) PRAZOMEDIO, NULL PRAZOADICIONAL,
         DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO)) VLMEDIOKG,
         NULL CODCLIPRINC, NULL CLIENTEPRINC, NULL QTDEVOLUCAO, NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL,
         NULL OBS, NULL SERIE, NULL CNPJ, NULL INSC, NULL CIDADE, NULL DESCSECAO, NULL DESCDEPTO, SUM(TOTAL.VLREPASSE) VLREPASSE,
         SUM(TOTAL.VLCMVDEVOLBONIF) VLCMVDEVOLBONIF, SUM(TOTAL.VLCMVANTESAPLVERBA) VLCMVANTESAPLVERBA,
         (SUM(TOTAL.VLLUCROANTESAPLVERBA) - SUM(TOTAL.VLDEVOLUCAO) + SUM(TOTAL.VLCMVDEVOL)) VLLUCROANTESAPLVERBA, NULL PERCLUCROANTESAPLVERBA
         FROM(SELECT VENDAS.CODCOMPRADOR, VENDAS.NUMTRANSVENDA CONTADOR,
         VENDAS.CODCLI QTCLIPOS, VENDAS.CODPROD QTMIXPRODUTO, 0 VLDEVOLUCAO, 0 VLDEVOLBONIFIC, 0 VLCMVDEVOL, 0 DEVOLTAB,
         ROUND(DECODE(SUM(VENDAS.VLVENDA), 0, 0, SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA) / SUM(VENDAS.VLVENDA)), 2) NUMDIAS,
         DECODE(SUM(VENDAS.VLVENDA), 0, 0, SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA)) PRAZOMEDIO, SUM(VENDAS.VLVENDA) AS VENDA_SEMDESCONTO, ';

   IF P_DESCST = 0
   THEN
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND) VLATEND, SUM(VENDAS.VLCUSTOREAL) VLCUSTOREAL, SUM(VENDAS.VLTABELA) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2) VLBONIFIC, ';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND - VENDAS.VLREPASSE) VLATEND, SUM(VENDAS.VLCUSTOREAL - VENDAS.VLREPASSE) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - VENDAS.VLREPASSE) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2 - VENDAS.VLREPASSE) VLBONIFIC, ';
      END IF;
     END IF;
    ELSIF P_DESCIPI = 1
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC)) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND - VENDAS.VLIPI) VLATEND, SUM(VENDAS.VLCUSTOREAL - VENDAS.VLIPI) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.VLIPI) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - (VENDAS.VLIPIBONIFIC)) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2 - (VENDAS.VLIPIBONIFIC)) VLBONIFIC, ';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLIPI - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND - VENDAS.VLIPI - VENDAS.VLREPASSE) VLATEND,
           SUM(VENDAS.VLCUSTOREAL - VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.VLIPI - VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - (VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2 - (VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLBONIFIC, ';
      END IF;
     END IF;
    END IF;
   ELSE
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC)) VLCUSTOFIN, ';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND - VENDAS.ICMSRETIDO) VLATEND,
           SUM(VENDAS.VLCUSTOREAL - VENDAS.ICMSRETIDO) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.ICMSRETIDO) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(DECODE(VENDAS.VLBONIFIC, 0, VENDAS.VLBONIFIC, VENDAS.VLBONIFIC -
             (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC))) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(DECODE(VENDAS.VLBONIFIC2, 0, VENDAS.VLBONIFIC2, VENDAS.VLBONIFIC2 -
             (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC))) VLBONIFIC, ';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLATEND,
           SUM(VENDAS.VLCUSTOREAL - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.ICMSRETIDO - VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(DECODE(VENDAS.VLBONIFIC, 0, VENDAS.VLBONIFIC, VENDAS.VLBONIFIC -
             (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - VENDAS.VLREPASSE)) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(DECODE(VENDAS.VLBONIFIC2, 0, VENDAS.VLBONIFIC2, VENDAS.VLBONIFIC2 -
             (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - VENDAS.VLREPASSE)) VLBONIFIC, ';
      END IF;
     END IF;
    ELSIF P_DESCIPI = 1
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.ICMSRETIDO - VENDAS.VLIPI) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC)) VLCUSTOFIN, ';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND - VENDAS.ICMSRETIDO - VENDAS.VLIPI) VLATEND,
           SUM(VENDAS.VLCUSTOREAL - VENDAS.ICMSRETIDO - VENDAS.VLIPI) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.ICMSRETIDO - VENDAS.VLIPI) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL :=
        V_SQL
        || ' SUM(DECODE(VENDAS.VLBONIFIC, 0, VENDAS.VLBONIFIC, VENDAS.VLBONIFIC -
             (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC))) VLBONIFIC, ';
      ELSE
       V_SQL :=
        V_SQL
        || ' SUM(DECODE(VENDAS.VLBONIFIC2, 0, VENDAS.VLBONIFIC2, VENDAS.VLBONIFIC2 -
             (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC))) VLBONIFIC, ';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

