                           ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                           SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                           ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA';
    END IF;

   V_SQL := V_SQL || ' FROM((' || V_SQL_GERAL ||')) VENDAS WHERE 1 = 1 ';

