   V_SQL :=
    V_SQL
    || ') TOTAL, PCCLIENT, PCUSUARI, PCPLPAG, PCNFENT WHERE TOTAL.NUMTRANSENT = PCNFENT.NUMTRANSENT
         AND TOTAL.CODCLI = PCCLIENT.CODCLI(+) AND TOTAL.CODUSUR = PCUSUARI.CODUSUR(+)
