  -------------------------------------------------------INICIO CONSULTA POR GERENTE
  WHEN P_TIPOPESQUISA = 33
  THEN
   -- Consulta por Gerente
   V_SQL :=
    ' SELECT NVL(PCGERENTE.CODGERENTE, 0) CODIGO, NULL CODIGO2, NULL CONDVENDA,
    NULL CODFILIAL, NULL NUMREGIAO, NULL CODUSUR, NULL NOMEUSUR, NULL UF, NULL DTSAIDA,
    CASE WHEN NVL(PCGERENTE.CODGERENTE, 0) = 0 THEN ''* NAO VINCULADOS *'' ELSE
    SUBSTR(PCGERENTE.NOMEGERENTE, 1, 40) END DESCRICAO, NULL EMBALAGEM, NULL NUMNOTA,
    NULL DTCANCEL, NULL CODEPTO, NULL CODSEC,NULL CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL, NULL CODAUXILIAR,
    NULL PESOLIQ, NULL NUMPR, NULL PERCVENDA, NULL PERCLUCRO, NULL PERCMETA, NULL VLVENDAPF,
    NULL VLVENDAPJ, NULL PERCVENDAPF, NULL PERCVENDAPJ, NULL PERCPARTTOTAL,
    (DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(TOTAL.VLDEVOLAVULSAI)) /
    SUM(TOTAL.PESOBRUTO))) VLPESOTRANSP, SUM(TOTAL.VLDEVOLUCAO) VLDEVOLUCAO, SUM(TOTAL.VLDEVOLAVULSAI) VLDEVOLAVULSAI,
    SUM(TOTAL.VLDEVCMVAVULSAI) VLDEVCMVAVULSAI, SUM(TOTAL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, SUM(TOTAL.VLCMVDEVOL) VLCMVDEVOL,
    SUM(TOTAL.DEVOLTAB) DEVOLTAB, NVL(COUNT(DISTINCT TOTAL.CONTADOR), 0) CONTADOR ,NVL(COUNT(DISTINCT TOTAL.QTCLIPOS), 0) QTCLIPOS, COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO, SUM(TOTAL.QTCLIENTE) QTCLIENTE,
    DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) NUMDIAS, SUM(TOTAL.VLVENDA) VLVENDA, SUM(DISTINCT TOTAL.VALORTOTALNOTA) VALORTOTALNOTA,
    SUM(TOTAL.QTVENDA) QTVENDA, SUM(TOTAL.VLATEND) VLATEND, SUM(TOTAL.VLCUSTOFIN) VLCUSTOFIN, NULL CUSTOFINEST,
    SUM(TOTAL.VLCUSTOREAL) VLCUSTOREAL, SUM(TOTAL.VLESTDISP) VLESTDISP, AVG(TOTAL.CUSTOMEDFIN) CUSTOMEDFIN,
    AVG(TOTAL.CUSTOMEDREAL) CUSTOMEDREAL, SUM(TOTAL.VLTABELA) VLTABELA, SUM(TOTAL.PESOBRUTO) PESOBRUTO,
    SUM(TOTAL.VLBONIFIC) VLBONIFIC, NULL VLOUTRASDESP, NULL VLMEDBONIFIC, NULL QTBONIFIC,
    DECODE(SUM(TOTAL.VLTABELA), 0, 0,((SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100) PERCDESC,
    (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) VALORDESC,
    (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO) - SUM(VLDEVOLAVULSAI)) VLLIQUIDO, MAX(NVL((SELECT SUM(NVL(PCMETASUP.VLVENDAPREV, 0))
    FROM PCMETASUP, PCSUPERV WHERE PCMETASUP.CODSUPERVISOR = PCSUPERV.CODSUPERVISOR AND PCSUPERV.CODGERENTE = PCGERENTE.CODGERENTE ';

