       V_SQL || ' AND ((DEVOL.CONDVENDA NOT IN (4, 8, 10, 13, 20, 98, 99) AND
           (TEMVENDATV8 IS NOT NULL)) OR (DEVOL.CONDVENDA NOT IN (4, 10, 13, 20, 98, 99) AND (TEMVENDATV8 IS NULL))) ';
