    V_SQL := V_SQL || ' UNION ALL';

    IF P_SUPERVMOV = 0 THEN
      V_SQL := V_SQL || ' SELECT AVULSA.CODSUPERVISOR,';
    ELSE
      V_SQL := V_SQL || ' SELECT AVULSA.CODSUPERVMOV,';
    END IF;

    IF P_DESCST = 0
    THEN
     IF P_DESCIPI = 0
