         GROUP BY PCGERENTE.CODGERENTE, PCGERENTE.NOMEGERENTE ORDER BY VLVENDA DESC ';
  -----------------------------------------------------------------FIM CONSULTA POR GERENTE

  ----------------------------------------------------------------------INICIO CONSULTA POR CATEGORIA
  WHEN P_TIPOPESQUISA = 34
  THEN
   -- Consulta por categoria
   V_SQL :=
    ' SELECT NVL(PCCATEGORIA.CODCATEGORIA,0) CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL, NULL NUMREGIAO,
    NULL CODUSUR, NULL NOMEUSUR, NULL UF, NULL DTSAIDA, CASE WHEN NVL(PCCATEGORIA.CODCATEGORIA, 0) = 0 THEN ''* NAO VINCULADOS *''  ELSE SUBSTR(PCCATEGORIA.CATEGORIA, 1, 40) END DESCRICAO,
    NULL EMBALAGEM, NULL NUMNOTA, NULL DTCANCEL, NULL CODEPTO, TOTAL.CODSEC, NVL(PCCATEGORIA.CODCATEGORIA,0) CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL, NULL CODAUXILIAR,
    NULL PESOLIQ, NULL NUMPR, NULL PERCVENDA, NULL PERCLUCRO, NULL PERCMETA, NULL VLVENDAPF, NULL VLVENDAPJ,
    NULL PERCVENDAPF, NULL PERCVENDAPJ, NULL PERCPARTTOTAL,(DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
    SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO))) VLPESOTRANSP, SUM(TOTAL.VLDEVOLUCAO) VLDEVOLUCAO, NULL VLDEVOLAVULSAI,
    NULL VLDEVCMVAVULSAI, SUM(TOTAL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, SUM(TOTAL.VLCMVDEVOL) VLCMVDEVOL, SUM(TOTAL.DEVOLTAB) DEVOLTAB,
    NVL(COUNT(DISTINCT TOTAL.CONTADOR), 0) CONTADOR ,NVL(COUNT(DISTINCT TOTAL.QTCLIPOS), 0) QTCLIPOS, COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO, SUM(TOTAL.QTCLIENTE) QTCLIENTE, DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) NUMDIAS,
    SUM(TOTAL.VLVENDA) VLVENDA, SUM(DISTINCT TOTAL.VALORTOTALNOTA) VALORTOTALNOTA, SUM(TOTAL.QTVENDA) QTVENDA,
    SUM(TOTAL.VLATEND) VLATEND, SUM(TOTAL.VLCUSTOFIN) VLCUSTOFIN, NULL CUSTOFINEST, SUM(TOTAL.VLCUSTOREAL) VLCUSTOREAL,
    SUM(TOTAL.VLESTDISP) VLESTDISP, AVG(TOTAL.CUSTOMEDFIN) CUSTOMEDFIN, AVG(TOTAL.CUSTOMEDREAL) CUSTOMEDREAL,
    SUM(TOTAL.VLTABELA) VLTABELA, SUM(TOTAL.PESOBRUTO) PESOBRUTO, SUM(TOTAL.VLBONIFIC) VLBONIFIC, NULL VLOUTRASDESP,
    SUM(DECODE(TOTAL.QTBONIFIC, 0, 0, TOTAL.VLBONIFIC / TOTAL.QTBONIFIC)) VLMEDBONIFIC, SUM(TOTAL.QTBONIFIC) QTBONIFIC,
    DECODE(SUM(TOTAL.VLTABELA), 0, -100,((SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100) PERCDESC,
    (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) VALORDESC,
    (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO)) VLLIQUIDO, NULL VLMETA, SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA) VLFLEX, ';

   V_SQL := V_SQL || '(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLCUSTOFIN) - SUM(TOTAL.VLDEVOLUCAO) + SUM(TOTAL.VLCMVDEVOL)) VLLUCRO, ';

   V_SQL :=
    V_SQL
    || ' DECODE(SUM(TOTAL.VLVENDA), 0, 0, SUM(TOTAL.NUMDIAS) / SUM(TOTAL.VLVENDA)) PRAZOMEDIO, NULL PRAZOADICIONAL,
         DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO)) VLMEDIOKG,
         NULL CODCLIPRINC, NULL CLIENTEPRINC, NULL QTDEVOLUCAO, NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS,
         NULL SERIE, NULL CNPJ, NULL INSC, NULL CIDADE, NULL DESCSECAO, NULL DESCDEPTO, SUM(TOTAL.VLREPASSE) VLREPASSE,
         SUM(TOTAL.VLCMVDEVOLBONIF) VLCMVDEVOLBONIF, SUM(TOTAL.VLCMVANTESAPLVERBA) VLCMVANTESAPLVERBA,
         (SUM(TOTAL.VLLUCROANTESAPLVERBA) - SUM(TOTAL.VLDEVOLUCAO) + SUM(TOTAL.VLCMVDEVOL)) VLLUCROANTESAPLVERBA,
         NULL PERCLUCROANTESAPLVERBA FROM(SELECT VENDAS.CODSEC, VENDAS.CODCATEGORIA, VENDAS.NUMTRANSVENDA CONTADOR,
          VENDAS.CODCLI QTCLIPOS, VENDAS.CODPROD QTMIXPRODUTO, 0 VLDEVOLUCAO, 0 VLDEVOLBONIFIC, 0 VLCMVDEVOL, 0 DEVOLTAB,
         ROUND(DECODE(SUM(VENDAS.VLVENDA), 0, 0, SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA) / SUM(VENDAS.VLVENDA)), 2) NUMDIAS, ';

   IF P_DESCST = 0
   THEN
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND) VLATEND, SUM(VENDAS.VLCUSTOREAL) VLCUSTOREAL, SUM(VENDAS.VLTABELA) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
