       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - (VENDAS.ICMSRETIDO + VENDAS.ICMSRETIDOBONIFIC) - (VENDAS.VLIPI + VENDAS.VLIPIBONIFIC) - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL :=
       V_SQL
       || ' SUM(VENDAS.VLATEND - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE) VLATEND,
           SUM(VENDAS.VLCUSTOREAL - VENDAS.ICMSRETIDO - VENDAS.VLIPI - VENDAS.VLREPASSE) VLCUSTOREAL,
