   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODFORNECPRINC  IN (' || P_FILTROCODFORNECPRINC || ')';
   END IF;

   -- Fim dos filtros


   IF P_CODGERENTE <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     ELSE
       V_SQL := V_SQL || ' AND
                     VENDAS.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     END IF;
   END IF;

   IF P_CODSUPERVISOR <> 0 THEN
