   END IF;

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' GROUP BY VENDAS.CODFORNECPRINC, VENDAS.FORNECPRINC, VENDAS.NUMTRANSVENDA, VENDAS.CODCLI, VENDAS.CODPROD ';
   ELSE
    V_SQL := V_SQL || ' GROUP BY VENDAS.CODFORNECPRINC, VENDAS.FORNECPRINC, VENDAS.NUMTRANSVENDA, VENDAS.CODCLI, VENDAS.CODPROD ';
   END IF;

   IF P_DEVOLUCAO = 1
   THEN
    V_SQL := V_SQL || ' UNION ALL ';


    V_SQL := V_SQL || ' SELECT DEVOL.CODFORNECPRINC, ';

    V_SQL := V_SQL || ' NULL CONTADOR, NULL QTCLIPOS, NULL QTMIXPRODUTO, DEVOL.FORNECPRINC, ';

    IF P_DESCST = 0
    THEN
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL) VLCMVDEVOL, ';
       ELSE
