       V_SQL := V_SQL || ' AND VENDAS.CODFORNEC = ' || P_CODFORNEC;
     ELSE
       V_SQL := V_SQL || ' AND VENDAS.CODFORNECMOV = ' || P_CODFORNEC;
     END IF;
   END IF;

   IF P_CODFORNECPRINC <> 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODFORNECPRINC = ' || P_CODFORNECPRINC;
   END IF;

   IF P_CODMARCA <> 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODMARCA = ' || P_CODMARCA;
   END IF;

   IF P_CODLINHAPROD <> 0 THEN
       V_SQL := V_SQL || ' AND
                     VENDAS.CODLINHAPROD = ' || P_CODLINHAPROD;
   END IF;


   IF P_DATAINI IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND VENDAS.DTSAIDA BETWEEN :DATAINI2 and :DATAFIM2
    AND VENDAS.QTBONIFIC >= 0 ';
   END IF;

   IF P_TIPOVENDA10 = 0
   THEN
    V_SQL := V_SQL || ' AND NVL(VENDAS.CONDVENDA, -1) IN (1, 5, -1, 7, 9, 11, 14) ';
    V_SQL := V_SQL || ' AND VENDAS.CODFISCAL NOT IN (522, 622, 722, 532, 632, 732) ';
   ELSE
    V_SQL := V_SQL || ' AND NVL(VENDAS.CONDVENDA, -1) IN (1, 5, -1, 7, 9, 11, 14, 10) ';
    V_SQL := V_SQL || ' AND VENDAS.CODFISCAL NOT IN (532, 632, 732) ';
   END IF;

   IF P_CONDVENDA IS NOT NULL
   THEN
    V_SQL := V_SQL || ' AND NVL(VENDAS.CONDVENDA, 0) IN (' || P_CONDVENDA || ') ';
   END IF;

   IF P_CODRCA > 0
   THEN
    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' AND VENDAS.CODUSUR = ' || P_CODRCA;
    ELSE
     V_SQL := V_SQL || ' AND VENDAS.CODUSURMOV = ' || P_CODRCA;
    END IF;
   END IF;

   IF P_ORIGEMPED IS NOT NULL AND P_UF IS NOT NULL
   THEN
    IF P_ORIGEMPED = 'B'
    THEN
     V_SQL := V_SQL || ' AND VENDAS.ORIGEMPED = ''B''';
    ELSE
     V_SQL := V_SQL || ' AND NVL(VENDAS.ORIGEMPED,''X'') <> ''B''';
    END IF;
   ELSIF P_ORIGEMPED IS NOT NULL AND P_UF IS NULL
   THEN
    V_SQL := V_SQL || ' AND VENDAS.ORIGEMPED = ''' || P_ORIGEMPED || '''';
   END IF;

   IF P_UF IS NOT NULL
   THEN
    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' AND VENDAS.UF = ''' || P_UF || '''';
    ELSE
     V_SQL := V_SQL || ' AND VENDAS.UFMOV = ''' || P_UF || '''';
    END IF;
   END IF;

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' GROUP BY VENDAS.CODMARCA, VENDAS.NUMTRANSVENDA, VENDAS.CODCLI, VENDAS.QTCLIENTE, VENDAS.CODPROD ';
   ELSE
    V_SQL := V_SQL || ' GROUP BY VENDAS.CODMARCA , VENDAS.NUMTRANSVENDA, VENDAS.CODCLI, VENDAS.QTCLIENTE, VENDAS.CODPRODMOV ';
   END IF;

   IF P_DEVOLUCAO = 1
   THEN
    V_SQL := V_SQL || ' UNION ALL ';

    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' SELECT DEVOL.CODMARCA, ';
    ELSE
     V_SQL := V_SQL || ' SELECT DEVOL.CODMARCA, ';
    END IF;

    V_SQL := V_SQL || ' NULL CONTADOR, NULL QTCLIPOS, NULL QTMIXPRODUTO, ';

    IF P_DESCST = 0
    THEN
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB) DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLREPASSE) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - DEVOL.VLREPASSE) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLREPASSE) DEVOLTAB, ';
      END IF;
     ELSIF P_DESCIPI = 1
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLIPI) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLIPI) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLIPI) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLIPI) DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLIPI - ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'DEVOL.VLREPASSE) VLDEVOLUCAO, SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'DEVOL.VLREPASSE) VLDEVOL2UCAO, SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE - VLIPI_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLIPI - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLIPI - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLIPI - DEVOL.VLREPASSE) DEVOLTAB, ';
      END IF;
     END IF;
    ELSE
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLST) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLST) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLST) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLST) DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLST - DEVOL.VLREPASSE) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - DEVOL.VLREPASSE - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLST - DEVOL.VLREPASSE) DEVOLTAB, ';
      END IF;
     ELSIF P_DESCIPI = 1
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLST - DEVOL.VLIPI) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - VLIPI_BONIF - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - VLIPI_BONIF - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLIPI) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLIPI) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLST - DEVOL.VLIPI) DEVOLTAB, ';
      ELSE
       V_SQL :=
        V_SQL
        || ' SUM(DEVOL.VLDEVOLUCAO - DEVOL.VLST - DEVOL.VLIPI - DEVOL.VLREPASSE) VLDEVOLUCAO, ';

        IF P_DESCVLTABELA = 0
        THEN
         V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC - DEVOL.VLREPASSE - VLIPI_BONIF - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
        ELSE
         V_SQL := V_SQL || 'SUM(DEVOL.VLDEVOLBONIFIC2 - DEVOL.VLREPASSE - VLIPI_BONIF - ICMSRETIDO_BONIF) VLDEVOLBONIFIC, ';
        END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLIPI - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(DEVOL.VLCMVDEVOLBONIF + DEVOL.VLCMVDEVOL - DEVOL.VLST - DEVOL.VLIPI - DEVOL.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(DEVOL.DEVOLTAB - DEVOL.VLST - DEVOL.VLIPI - DEVOL.VLREPASSE) DEVOLTAB, ';
      END IF;
     END IF;
    END IF;

    V_SQL := V_SQL || ' 0 NUMDIAS, 0 PRAZOMEDIO, 0 AS VENDA_SEMDESCONTO, 0 VLVENDA, -1 VALORTOTALNOTA, 0 VLCUSTOFIN, 0 VLATEND,
         0 VLCUSTOREAL, 0 VLTABELA, 0 VLBONIFIC, ';

    IF P_UF IS NOT NULL
    THEN
     V_SQL := V_SQL || ' 0 VLVENDAPF, ';
    END IF;

    V_SQL := V_SQL || ' 0 VLCMVANTESAPLVERBA, 0 VLLUCROANTESAPLVERBA, 0 QTVENDA, 0 QTCLIENTE, 0 VLESTDISP, 0 CUSTOMEDFIN, 0 CUSTOMEDREAL, ';

    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' SUM(DEVOL.TOTPESO) * -1 PESOBRUTO, ';
    ELSE
     V_SQL := V_SQL || ' SUM(DEVOL.TOTPESOMOV) * -1 PESOBRUTO, ';
    END IF;

    V_SQL := V_SQL || ' 0 QTBONIFIC, SUM(DEVOL.VLREPASSE) VLREPASSE, SUM(VLCMVDEVOLBONIF) VLCMVDEVOLBONIF

                         FROM ( '||V_SQL_VIEW_DEVOL||' ) DEVOL WHERE 1 = 1 ';

    IF P_CODFILIAL IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND DEVOL.CODFILIAL IN (' || P_CODFILIAL || ') ';
    END IF;

   --Filtros incluidos na rotina 111 - devolucao de vendas

   IF P_FILTROCODGERENTE IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     END IF;
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVMOV IN (' || P_FILTROCODSUPERVISOR || ')';
     END IF;
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODUSUR IN (' || P_FILTROCODUSUR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODUSURMOV IN (' || P_FILTROCODUSUR || ')';
     END IF;
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODFORNEC IN (' || P_FILTROCODFORNEC || ')';
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODFORNECPRINC  IN (' || P_FILTROCODFORNECPRINC || ')';
   END IF;

   -- Fim dos filtros


    IF P_CODGERENTE <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     END IF;
    END IF;

    IF P_CODSUPERVISOR <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVISOR = ' || P_CODSUPERVISOR;
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODSUPERVMOV = ' || P_CODSUPERVISOR;
     END IF;
    END IF;

    IF P_CODRCA <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODUSUR = ' || P_CODRCA;
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODUSURMOV = ' || P_CODRCA;
     END IF;
    END IF;

    IF P_CODFORNEC <> 0 THEN
      IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND DEVOL.CODFORNEC = ' || P_CODFORNEC;
      ELSE
        V_SQL := V_SQL || ' AND DEVOL.CODFORNECMOV = ' || P_CODFORNEC;
      END IF;
    END IF;

    IF P_CODFORNECPRINC <> 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODFORNECPRINC = ' || P_CODFORNECPRINC;
    END IF;

    IF P_CODMARCA <> 0 THEN
       V_SQL := V_SQL || ' AND
                      DEVOL.CODMARCA = ' || P_CODMARCA;
    END IF;

    IF P_CODLINHAPROD <> 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODLINHAPROD = ' || P_CODLINHAPROD;
    END IF;

    IF P_DATAINI IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND DEVOL.DTENT BETWEEN :DATAINI3 and :DATAFIM3 ';
    END IF;
  IF P_CONSIDERANOTASAPROVADAS = 1 THEN
        V_SQL := V_SQL || ' AND DEVOL.ESPECIE = ''NF''
                        AND DEVOL.SITUACAONFE in (100, 150)  ';
  END IF;

    IF P_TIPOVENDA10 = 0
    THEN
     IF P_CONSIDERARDEVOLTV8 = 0
     THEN
      --P_CONSIDERARDEVOLTV8 = 0 NÃ¿O RETORNA AS DEVOLUCOES TV8, QUANDO FOR 1 RETORNA TV8
      V_SQL := V_SQL || ' AND DEVOL.CONDVENDA NOT IN (4, 8, 10, 13, 20, 98, 99) ';
     ELSE
      V_SQL :=
       V_SQL || ' AND ((DEVOL.CONDVENDA NOT IN (4, 8, 10, 13, 20, 98, 99) AND (TEMVENDATV8 IS NOT NULL))
           OR (DEVOL.CONDVENDA NOT IN (4, 10, 13, 20, 98, 99) AND (TEMVENDATV8 IS NULL))) ';
     END IF;
    ELSE
     IF P_CONSIDERARDEVOLTV8 = 0
     THEN
      V_SQL := V_SQL || ' AND DEVOL.CONDVENDA NOT IN (4, 8, 13, 20, 98, 99) ';
     ELSE
      V_SQL := V_SQL || ' AND ((DEVOL.CONDVENDA NOT IN (4, 8, 13, 20, 98, 99) AND (TEMVENDATV8 IS NOT NULL))
           OR (DEVOL.CONDVENDA NOT IN (4, 13, 20, 98, 99) AND (TEMVENDATV8 IS NULL))) ';
     END IF;
    END IF;

    IF P_CONDVENDA IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND DEVOL.CONDVENDA IN (' || P_CONDVENDA || ') ';
    END IF;

    IF P_CODRCA <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     DEVOL.CODUSUR = ' || P_CODRCA;
     ELSE
       V_SQL := V_SQL || ' AND
                     DEVOL.CODUSURMOV = ' || P_CODRCA;
     END IF;
    END IF;

    IF P_ORIGEMPED IS NOT NULL AND P_UF IS NOT NULL
    THEN
     IF P_ORIGEMPED = 'B'
     THEN
      V_SQL := V_SQL || ' AND DEVOL.ORIGEMPED = ''B''';
     ELSE
      V_SQL := V_SQL || ' AND NVL(DEVOL.ORIGEMPED,''X'') <> ''B''';
     END IF;
    ELSIF P_ORIGEMPED IS NOT NULL AND P_UF IS NULL
    THEN
     V_SQL := V_SQL || ' AND DEVOL.ORIGEMPED = ''' || P_ORIGEMPED || '''';
    END IF;

    IF P_UF IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND DEVOL.ESTENT = ''' || P_UF || '''';
    END IF;

    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' GROUP BY DEVOL.CODMARCA ';
    ELSE
     V_SQL := V_SQL || ' GROUP BY DEVOL.CODMARCA ';
    END IF;

    V_SQL := V_SQL || ' UNION ALL ';

    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' SELECT AVULSA.CODMARCA, ';
    ELSE
     V_SQL := V_SQL || ' SELECT AVULSA.CODMARCA, ';
    END IF;

    V_SQL := V_SQL || ' NULL CONTADOR, NULL QTCLIPOS, NULL QTMIXPRODUTO, ';

    IF P_DESCST = 0
    THEN
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(AVULSA.VLDEVOLUCAO) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || '0 VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || '0 VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(0 + AVULSA.VLDEVCMVAVULSAI) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' 0 DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(AVULSA.VLDEVOLUCAO - AVULSA.VLREPASSE) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(0 - AVULSA.VLREPASSE) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(0 - AVULSA.VLREPASSE) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(0 + AVULSA.VLDEVCMVAVULSAI - AVULSA.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(0 - 0) DEVOLTAB, ';
      END IF;
     ELSIF P_DESCIPI = 1
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(AVULSA.VLDEVOLUCAO - AVULSA.VLIPI) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'SUM(0 - 0) VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'SUM(0 - 0) VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLIPI) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(0 + AVULSA.VLDEVCMVAVULSAI - AVULSA.VLIPI) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' SUM(0 - 0) DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(AVULSA.VLDEVOLUCAO - AVULSA.VLIPI - ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || 'AVULSA.VLREPASSE) VLDEVOLUCAO, 0 VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || 'AVULSA.VLREPASSE) VLDEVOLUCAO, 0 VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLIPI - AVULSA.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(0 + AVULSA.VLDEVCMVAVULSAI - AVULSA.VLIPI - AVULSA.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' 0 DEVOLTAB, ';
      END IF;
     END IF;
    ELSE
     IF P_DESCIPI = 0
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(AVULSA.VLDEVOLUCAO - AVULSA.VLST) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || '0 VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || '0 VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' 0 DEVOLTAB, ';
      ELSE
       V_SQL := V_SQL || ' SUM(AVULSA.VLDEVOLUCAO - AVULSA.VLST - AVULSA.VLREPASSE) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || '0 VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || '0 VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' 0 DEVOLTAB, ';
      END IF;
     ELSIF P_DESCIPI = 1
     THEN
      IF P_DESCVLREPASSE = 0
      THEN
       V_SQL := V_SQL || ' SUM(AVULSA.VLDEVOLUCAO - AVULSA.VLST - AVULSA.VLIPI) VLDEVOLUCAO, ';

       IF P_DESCVLTABELA = 0
       THEN
        V_SQL := V_SQL || '0 VLDEVOLBONIFIC, ';
       ELSE
        V_SQL := V_SQL || '0 VLDEVOLBONIFIC, ';
       END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLIPI) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLIPI) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' 0 DEVOLTAB, ';
      ELSE
       V_SQL :=
        V_SQL
        || ' SUM(AVULSA.VLDEVOLUCAO - AVULSA.VLST - AVULSA.VLIPI - AVULSA.VLREPASSE) VLDEVOLUCAO, ';

        IF P_DESCVLTABELA = 0
        THEN
         V_SQL := V_SQL || '0 VLDEVOLBONIFIC, ';
        ELSE
         V_SQL := V_SQL || '0 VLDEVOLBONIFIC, ';
        END IF;

       IF P_BONIFICACAO = 0
       THEN
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLIPI - AVULSA.VLREPASSE) VLCMVDEVOL, ';
       ELSE
        V_SQL := V_SQL || ' SUM(AVULSA.VLDEVCMVAVULSAI - AVULSA.VLST - AVULSA.VLIPI - AVULSA.VLREPASSE) VLCMVDEVOL, ';
       END IF;

       V_SQL := V_SQL || ' 0 DEVOLTAB, ';
      END IF;
     END IF;
    END IF;

    V_SQL := V_SQL || ' 0 NUMDIAS, 0 PRAZOMEDIO, 0 AS VENDA_SEMDESCONTO, 0 VLVENDA, -1 VALORTOTALNOTA, 0 VLCUSTOFIN, 0 VLATEND,
         0 VLCUSTOREAL, 0 VLTABELA, 0 VLBONIFIC, ';

    IF P_UF IS NOT NULL
    THEN
     V_SQL := V_SQL || ' 0 VLVENDAPF, ';
    END IF;

    V_SQL := V_SQL || ' 0 VLCMVANTESAPLVERBA, 0 VLLUCROANTESAPLVERBA, 0 QTVENDA, 0 QTCLIENTE, 0 VLESTDISP, 0 CUSTOMEDFIN, 0 CUSTOMEDREAL, 0 PESOBRUTO, ';

    V_SQL := V_SQL || ' 0 QTBONIFIC, SUM(AVULSA.VLREPASSE) VLREPASSE, 0 VLCMVDEVOLBONIF

                         FROM ( '||V_SQL_VIEW_DEVOLAVULSA||' ) AVULSA WHERE 1 = 1 ';

    IF P_CODFILIAL IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND AVULSA.CODFILIAL IN (' || P_CODFILIAL || ') ';
    END IF;

   --Filtros incluidos na rotina 111 - devolucao de vendas

   IF P_FILTROCODGERENTE IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE IN (' || P_FILTROCODGERENTE || ')' || ' ) ';
     END IF;
   END IF;


   IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVISOR IN (' || P_FILTROCODSUPERVISOR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVMOV IN (' || P_FILTROCODSUPERVISOR || ')';
     END IF;
   END IF;

   IF P_FILTROCODUSUR IS NOT NULL THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSUR IN (' || P_FILTROCODUSUR || ')';
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSURMOV IN (' || P_FILTROCODUSUR || ')';
     END IF;
   END IF;

   IF P_FILTROCODFORNEC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODFORNEC IN (' || P_FILTROCODFORNEC || ')';
   END IF;

   IF P_FILTROCODFORNECPRINC IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODFORNECPRINC  IN (' || P_FILTROCODFORNECPRINC || ')';
   END IF;

   -- Fim dos filtros


    IF P_CODGERENTE <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVMOV IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE = ' || P_CODGERENTE || ') ';
     END IF;
    END IF;

    IF P_CODSUPERVISOR <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVISOR = ' || P_CODSUPERVISOR;
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODSUPERVMOV = ' || P_CODSUPERVISOR;
     END IF;
    END IF;

    IF P_CODRCA <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSUR = ' || P_CODRCA;
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSURMOV = ' || P_CODRCA;
     END IF;
    END IF;

    IF P_CODFORNEC <> 0 THEN
      IF P_SUPERVMOV = 0 THEN
        V_SQL := V_SQL || ' AND AVULSA.CODFORNEC = ' || P_CODFORNEC;
      ELSE
        V_SQL := V_SQL || ' AND AVULSA.CODFORNECMOV = ' || P_CODFORNEC;
      END IF;
    END IF;

    IF P_CODFORNECPRINC <> 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODFORNECPRINC = ' || P_CODFORNECPRINC;
    END IF;

    IF P_CODMARCA <> 0 THEN
       V_SQL := V_SQL || ' AND
                      AVULSA.CODMARCA = ' || P_CODMARCA;
    END IF;

    IF P_CODLINHAPROD <> 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODLINHAPROD = ' || P_CODLINHAPROD;
    END IF;

    IF P_DATAINI IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND AVULSA.DTENT BETWEEN :DATAINI3 and :DATAFIM3 ';
    END IF;
  IF P_CONSIDERANOTASAPROVADAS = 1 THEN
        V_SQL := V_SQL || ' AND AVULSA.ESPECIE = ''NF''
                        AND AVULSA.SITUACAONFE in (100, 150)  ';
  END IF;

    IF P_CODRCA <> 0 THEN
     IF P_SUPERVMOV = 0 THEN
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSUR = ' || P_CODRCA;
     ELSE
       V_SQL := V_SQL || ' AND
                     AVULSA.CODUSURMOV = ' || P_CODRCA;
     END IF;
    END IF;

    IF P_UF IS NOT NULL
    THEN
     V_SQL := V_SQL || ' AND AVULSA.ESTENT = ''' || P_UF || '''';
    END IF;

    IF P_SUPERVMOV = 0
    THEN
     V_SQL := V_SQL || ' GROUP BY AVULSA.CODMARCA ';
    ELSE
     V_SQL := V_SQL || ' GROUP BY AVULSA.CODMARCA ';
    END IF;
   END IF;

   V_SQL := V_SQL || ') TOTAL, PCMARCA WHERE PCMARCA.CODMARCA(+) = TOTAL.CODMARCA
         GROUP BY TOTAL.CODMARCA, PCMARCA.MARCA ORDER BY VLVENDA DESC ';

 --FIM MARCA

   WHEN P_TIPOPESQUISA = 38
 --LINHA DE PRODUTO
  THEN
   V_SQL :=
    ' SELECT TOTAL.CODLINHAPROD CODIGO, NULL CODIGO2, NULL CONDVENDA, NULL CODFILIAL, NULL NUMREGIAO,
    NULL CODUSUR, NULL NOMEUSUR, NULL UF, NULL DTSAIDA, SUBSTR(NVL(PCLINHAPROD.DESCRICAO, ''* NAO VINCULADO *''), 1, 25) DESCRICAO,
    NULL EMBALAGEM, NULL NUMNOTA, NULL DTCANCEL, NULL CODEPTO, NULL CODSEC,NULL CODCATEGORIA, NULL CODSUBCATEGORIA, NULL NUMORIGINAL,
    NULL CODAUXILIAR, NULL PESOLIQ, NULL NUMPR, NULL PERCVENDA, NULL PERCLUCRO, NULL PERCMETA, ';

   IF P_UF IS NULL
   THEN
    V_SQL := V_SQL || ' NULL VLVENDAPF, NULL VLVENDAPJ, NULL PERCVENDAPF, NULL PERCVENDAPJ, ';
   ELSE
    V_SQL :=
     V_SQL
     || ' SUM(TOTAL.VLVENDAPF) VLVENDAPF, SUM(TOTAL.VLVENDA) - SUM(NVL(TOTAL.VLVENDAPF, 0)) VLVENDAPJ,
         SUM(DECODE(TOTAL.VLVENDA, 0, 0,(NVL(TOTAL.VLVENDAPF, 0) / TOTAL.VLVENDA) * 100)) PERCVENDAPF,
         SUM(DECODE(TOTAL.VLVENDA, 0, 0,((TOTAL.VLVENDA - NVL(TOTAL.VLVENDAPF, 0)) / TOTAL.VLVENDA) * 100)) PERCVENDAPJ, ';
   END IF;

   V_SQL :=
    V_SQL
    || ' NULL PERCPARTTOTAL,(DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
         SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO))) VLPESOTRANSP, SUM(TOTAL.VLDEVOLUCAO) VLDEVOLUCAO,
         NULL VLDEVOLAVULSAI, NULL VLDEVCMVAVULSAI, SUM(TOTAL.VLDEVOLBONIFIC) VLDEVOLBONIFIC, SUM(TOTAL.VLCMVDEVOL) VLCMVDEVOL,
         SUM(TOTAL.DEVOLTAB) DEVOLTAB, NVL(COUNT(DISTINCT TOTAL.CONTADOR), 0) CONTADOR ,NVL(COUNT(DISTINCT TOTAL.QTCLIPOS), 0) QTCLIPOS,
         COUNT(DISTINCT TOTAL.QTMIXPRODUTO) QTMIXPRODUTO, COUNT(DISTINCT(TOTAL.QTCLIENTE)) QTCLIENTE,
         DECODE(SUM(TOTAL.VLVENDA),0,0, SUM(TOTAL.NUMDIAS * TOTAL.VLVENDA) / SUM(TOTAL.VLVENDA)) NUMDIAS, SUM(TOTAL.VLVENDA) VLVENDA, SUM(DISTINCT TOTAL.VALORTOTALNOTA) VALORTOTALNOTA,
         SUM(TOTAL.QTVENDA) QTVENDA, SUM(TOTAL.VLATEND) VLATEND, SUM(TOTAL.VLCUSTOFIN) VLCUSTOFIN, NULL CUSTOFINEST,
         SUM(TOTAL.VLCUSTOREAL) VLCUSTOREAL, SUM(TOTAL.VLESTDISP) VLESTDISP, AVG(TOTAL.CUSTOMEDFIN) CUSTOMEDFIN,
         AVG(TOTAL.CUSTOMEDREAL) CUSTOMEDREAL, SUM(TOTAL.VLTABELA) VLTABELA, SUM(TOTAL.PESOBRUTO) PESOBRUTO,
         SUM(TOTAL.VLBONIFIC) VLBONIFIC, NULL VLOUTRASDESP,
         SUM(DECODE(TOTAL.QTBONIFIC, 0, 0, TOTAL.VLBONIFIC / TOTAL.QTBONIFIC)) VLMEDBONIFIC,
         SUM(TOTAL.QTBONIFIC) QTBONIFIC, DECODE(SUM(TOTAL.VLTABELA), 0, -100,((SUM(TOTAL.VLVENDA) -
         SUM(TOTAL.VLTABELA)) / SUM(TOTAL.VLTABELA)) * 100) PERCDESC, (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA)) VALORDESC,
         (SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLDEVOLUCAO)) VLLIQUIDO,
         NULL VLMETA, SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLTABELA) VLFLEX, ';

   V_SQL := V_SQL || '(SUM(TOTAL.VLVENDA) - SUM(TOTAL.VLCUSTOFIN) - SUM(TOTAL.VLDEVOLUCAO) + SUM(TOTAL.VLCMVDEVOL)) VLLUCRO, ';

   V_SQL :=
    V_SQL
    || ' DECODE(SUM(TOTAL.PRAZOMEDIO),0,0, SUM(TOTAL.PRAZOMEDIO) / SUM(TOTAL.VENDA_SEMDESCONTO)) PRAZOMEDIO, NULL PRAZOADICIONAL, DECODE(SUM(TOTAL.PESOBRUTO), 0, 0,(SUM(TOTAL.VLVENDA) -
         SUM(TOTAL.VLDEVOLUCAO)) / SUM(TOTAL.PESOBRUTO)) VLMEDIOKG, NULL CODCLIPRINC, NULL CLIENTEPRINC, NULL QTDEVOLUCAO,
         NULL NUMTRANSVENDA, NULL ESPECIE, NULL MOTIVODEVOL, NULL OBS, NULL SERIE, NULL CNPJ, NULL INSC, NULL CIDADE,
         NULL DESCSECAO, NULL DESCDEPTO, SUM(TOTAL.VLREPASSE) VLREPASSE, SUM(TOTAL.VLCMVDEVOLBONIF) VLCMVDEVOLBONIF,
         SUM(TOTAL.VLCMVANTESAPLVERBA) VLCMVANTESAPLVERBA, SUM(TOTAL.VLLUCROANTESAPLVERBA) VLLUCROANTESAPLVERBA,
         NULL PERCLUCROANTESAPLVERBA FROM(';

   IF P_SUPERVMOV = 0
   THEN
    V_SQL := V_SQL || ' SELECT VENDAS.CODLINHAPROD, VENDAS.NUMTRANSVENDA CONTADOR,  VENDAS.CODCLI QTCLIPOS, VENDAS.CODPROD QTMIXPRODUTO, ';
   ELSE
    V_SQL := V_SQL || ' SELECT VENDAS.CODLINHAPROD, VENDAS.NUMTRANSVENDA CONTADOR,  VENDAS.CODCLI QTCLIPOS, VENDAS.CODPRODMOV QTMIXPRODUTO, ';
   END IF;

   V_SQL :=
    V_SQL
    || ' 0 VLDEVOLUCAO, 0 VLDEVOLBONIFIC, 0 VLCMVDEVOL, 0 DEVOLTAB, ROUND(DECODE(SUM(VENDAS.VLVENDA), 0, 0,
         SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA) / SUM(VENDAS.VLVENDA)), 2) NUMDIAS,
         DECODE(SUM(VENDAS.VLVENDA), 0, 0, SUM(VENDAS.PRAZOMEDIO * VENDAS.VLVENDA)) PRAZOMEDIO, SUM(VENDAS.VLVENDA) AS VENDA_SEMDESCONTO, ';

   IF P_DESCST = 0
   THEN
    IF P_DESCIPI = 0
    THEN
     IF P_DESCVLREPASSE = 0
     THEN
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND) VLATEND, SUM(VENDAS.VLCUSTOREAL) VLCUSTOREAL, SUM(VENDAS.VLTABELA) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2) VLBONIFIC, ';
      END IF;

      IF P_UF IS NOT NULL
      THEN
       IF VERIFICAPF = TRUE
       THEN
        V_SQL := V_SQL || ' SUM(DECODE((CASE ';

        IF P_CONSIDTIPOFJ = 1
        THEN
         V_SQL := V_SQL || ' WHEN(PCCLIENT.TIPOFJ = ''F'') THEN ''S''';
        END IF;

        IF P_CONSIDCONSUMIDORFINAL = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.CONSUMIDORFINAL, ''N'') = ''S'') THEN ''S''';
        END IF;

        IF P_CONSIDISENTO = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTO'') THEN ''S''';
        END IF;

        IF P_CONSIDISENTA = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTA'') THEN ''S''';
        END IF;

        V_SQL := V_SQL || ' ELSE ''N'' END), ''S'', VENDAS.VLVENDA, 0)) VLVENDAPF, ';
       ELSE
        V_SQL := V_SQL || ' 0 VLVENDAPF, ';
       END IF;
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFIN + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - (VENDAS.VLCUSTOFINB + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     ELSE
      V_SQL := V_SQL || ' SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE) VLVENDA, '
      || ' MAX((SELECT (NF.VLTOTGER) FROM PCNFSAID NF '
      || ' WHERE NF.NUMTRANSVENDA = VENDAS.NUMTRANSVENDA ' || CHR(13);

      IF P_CODFILIAL IS NOT NULL
      THEN
        V_SQL := V_SQL ||
          ' AND NF.CODFILIAL IN (' || P_CODFILIAL || ') ' || CHR(13);
      END IF;

      IF P_DATAINI IS NOT NULL
      THEN
        V_SQL := V_SQL || ' AND NF.DTSAIDA BETWEEN :DATAINI AND :DATAFIM ' || CHR(13);
      END IF;

      V_SQL := V_SQL || ' AND NF.DTSAIDA = VENDAS.DTSAIDA AND NF.CODFILIAL = VENDAS.CODFILIAL)) AS VALORTOTALNOTA, ';

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE) VLCUSTOFIN, ';
      END IF;

      V_SQL := V_SQL || ' SUM(VENDAS.VLATEND - VENDAS.VLREPASSE) VLATEND, SUM(VENDAS.VLCUSTOREAL - VENDAS.VLREPASSE) VLCUSTOREAL,
           SUM(VENDAS.VLTABELA - VENDAS.VLREPASSE) VLTABELA, ';

      IF P_DESCVLTABELA = 0
      THEN
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC - VENDAS.VLREPASSE) VLBONIFIC, ';
      ELSE
       V_SQL := V_SQL || ' SUM(VENDAS.VLBONIFIC2 - VENDAS.VLREPASSE) VLBONIFIC, ';
      END IF;

      IF P_UF IS NOT NULL
      THEN
       IF VERIFICAPF = TRUE
       THEN
        V_SQL := V_SQL || ' SUM(DECODE((CASE ';

        IF P_CONSIDTIPOFJ = 1
        THEN
         V_SQL := V_SQL || ' WHEN(PCCLIENT.TIPOFJ = ''F'') THEN ''S''';
        END IF;

        IF P_CONSIDCONSUMIDORFINAL = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.CONSUMIDORFINAL, ''N'') = ''S'') THEN ''S''';
        END IF;

        IF P_CONSIDISENTO = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTO'') THEN ''S''';
        END IF;

        IF P_CONSIDISENTA = 1
        THEN
         V_SQL := V_SQL || ' WHEN(NVL(PCCLIENT.IEENT, ''ISENTO'') = ''ISENTA'') THEN ''S''';
        END IF;

        V_SQL := V_SQL || ' ELSE ''N'' END), ''S'', VENDAS.VLVENDA - VENDAS.VLREPASSE, 0)) VLVENDAPF, ';
       ELSE
        V_SQL := V_SQL || ' 0 VLVENDAPF, ';
       END IF;
      END IF;

      IF P_BONIFICACAO = 0
      THEN
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFIN - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      ELSE
       V_SQL := V_SQL || '  SUM(VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' ) VLCMVANTESAPLVERBA,
                   SUM(VENDAS.VLVENDA - VENDAS.VLREPASSE - (VENDAS.VLCUSTOFINB - VENDAS.VLREPASSE + ' || V_VLVERBACMV || ' + ' || V_VLVERBACMVCLI || ' +
                   ' || V_SUBSELECTVERBA || ' )) VLLUCROANTESAPLVERBA,';
      END IF;
     END IF;
