    TIPO.PERCDIF := 0;
    TIPO.PERCLUCROANTESAPLVERBA := REG.PERCLUCROANTESAPLVERBA;

    VRETORNO(VN_POSICAO_EM_ALTERACAO) := TIPO;

    IF P_TIPOPESQUISA <> 28 THEN
      VLVENDALIQ := VLVENDALIQ + (REG.VLLIQUIDO);
    END IF;

    VLVENDATOT := VLVENDATOT + (REG.VLVENDA);

    IF P_TIPOPESQUISA = 14 THEN
      QTTOTCANCELADA := QTTOTCANCELADA + (REG.CONTADOR);
    END IF;
  END LOOP;

EXCEPTION
  WHEN INVALID_CURSOR THEN
    RAISE_APPLICATION_ERROR(-20001,
                            'Erro na execução do cursor. Pesquisa - ' +
                            TO_CHAR(P_TIPOPESQUISA) || ' Erro original: ' ||
                            SQLERRM);

  WHEN OTHERS THEN
    XERRO := 'Ocorreu erro ao executar o SQL de dados.' || CHR(13) ||
             '------------------------------' || CHR(13) || 'ERRO GERAL' ||
             CHR(13) || '------------------------------' || CHR(13) ||
             DBMS_UTILITY.FORMAT_ERROR_STACK || CHR(13) ||
             '------------------------------' || CHR(13) || 'DESCRIÇÃO DO ERRO' ||
             CHR(13) || '------------------------------' || CHR(13) ||
            --VS_ERRO || CHR(13) ||
             '------------------------------' || CHR(13) || 'INÍCIO DO ERRO' ||
             CHR(13) || '------------------------------' || CHR(13) ||
             DBMS_UTILITY.FORMAT_CALL_STACK || '------------------------------' ||
             CHR(13) || 'SEQUÊNCIA DE CHAMADAS' || CHR(13) ||
             '------------------------------' || CHR(13) ||
             DBMS_UTILITY.FORMAT_ERROR_BACKTRACE;
    RAISE_APPLICATION_ERROR(-20000, XERRO);
END;

BEGIN
  FOR REG IN 1 .. VRETORNO.COUNT
  LOOP

    /*Cálculo do percentual de venda */

    /*
     V_SQL := ' SELECT SUM(VENDAS.VLVENDA) VLVENDATOT FROM (' || V_SQL_GERAL ||') VENDAS
                    WHERE VENDAS.DTSAIDA BETWEEN :DATA1 AND :DATA2 ';
     IF P_TIPOVENDA10 = 0 THEN
       V_SQL := V_SQL || ' AND NVL(VENDAS.CONDVENDA, 0) IN (1, 5, 0, 7, 9, 11, 14) ';
       V_SQL := V_SQL || ' AND VENDAS.CODFISCAL NOT IN   (522, 622, 722, 532, 632, 732)
                    ';
     ELSE
       V_SQL := V_SQL || ' AND
                    NVL(VENDAS.CONDVENDA, 0) IN (1, 5, 0, 7, 9, 11, 14, 10)         ';
       V_SQL := V_SQL || ' AND VENDAS.CODFISCAL NOT IN (532, 632, 732)
                    ';
     END IF;
     IF P_CONSIDERANOTASAPROVADAS = 1 THEN
     V_SQL := V_SQL || ' AND VENDAS.ESPECIE = ''NF''
                       AND VENDAS.SITUACAONFE in (100, 150) ';
     END IF;

     IF P_CODFILIAL IS NOT NULL THEN
       V_SQL := V_SQL || ' AND
                    VENDAS.CODFILIAL IN (' || P_CODFILIAL || ')
                    ';
     END IF;
     IF P_CONDVENDA IS NOT NULL THEN
       V_SQL := V_SQL || ' AND NVL(VENDAS.CONDVENDA, 0) IN (' ||
                P_CONDVENDA || ') ';
     END IF;

    execute immediate V_SQL
     into VLVENDATOT
     USING P_DATAINI, P_DATAFIM; */

    IF P_TIPOPESQUISA <> 25 AND
       P_TIPOPESQUISA <> 29 THEN
      IF VLVENDATOT > 0 THEN
        PERC_VENDA := (VRETORNO(REG).VLVENDA / VLVENDATOT) * 100;
      ELSE
        PERC_VENDA := 0;
      END IF;
    ELSE
      PERC_VENDA := VRETORNO(REG).PERCVENDA;
    END IF;

    /*Cálculo do percentual de diferença*/
    VLTABLIQ := (VRETORNO(REG).VLTABELA + VRETORNO(REG).VLBONIFIC) - VRETORNO(REG).DEVOLTAB;

    IF VLTABLIQ > 0 THEN
      PERC_DIF := (((VRETORNO(REG).VLVENDA - VRETORNO(REG).VLDEVOLUCAO) -
                  VLTABLIQ) / VLTABLIQ) * 100;
    ELSE
      PERC_DIF := 0;
    END IF;

    /*Cálculo do percentual de bonificação */
    IF VRETORNO(REG).VLVENDA > 0 THEN
      PERC_BONIF := (VRETORNO(REG).VLBONIFIC / VRETORNO(REG).VLVENDA) * 100;
    ELSE
      PERC_BONIF := 0;
    END IF;

    /*Cálculo do percentual de venda física e jurídica*/
    IF P_TIPOPESQUISA = 5 OR
       P_TIPOPESQUISA = 6 OR
       P_TIPOPESQUISA = 7 OR
       (P_TIPOPESQUISA = 22 AND P_UF IS NOT NULL) OR
       (P_TIPOPESQUISA = 17 AND P_UF IS NOT NULL) OR
       (P_TIPOPESQUISA = 3 AND P_UF IS NOT NULL) THEN
      IF VLVENDATOT > 0 THEN
        PERC_VENDA_PF := (VRETORNO(REG).VLVENDAPF / VLVENDATOT) * 100;
        PERC_VENDA_PJ := (VRETORNO(REG).VLVENDAPJ / VLVENDATOT) * 100;
      ELSE
        PERC_VENDA_PF := 0;
        PERC_VENDA_PJ := 0;
      END IF;
    END IF;

    /*Cálculo do percentual de participação total */
    IF VLVENDATOT > 0 THEN
      PERC_PART_TOTAL := (VRETORNO(REG).VLVENDA / VLVENDATOT) * 100;
    ELSE
      PERC_PART_TOTAL := 0;
    END IF;

    /*Cálculo do percentual de lucro */
    IF P_LUCRO_LIQ = 1 THEN
      IF ROUND(VRETORNO(REG).VLLIQUIDO, 2) <> 0 THEN
        -- PERC_LUCRO := (VRETORNO(REG).VLLUCRO / VRETORNO(REG).VLLIQUIDO) * 100;
        IF ((VRETORNO(REG).VLLUCRO > 0) OR (VRETORNO(REG).VLLIQUIDO > 0)) THEN
          PERC_LUCRO := (VRETORNO(REG).VLLUCRO / VRETORNO(REG).VLLIQUIDO) * 100;
        ELSE
          PERC_LUCRO := -100;
        END IF;

        IF ((VRETORNO(REG).VLLUCROANTESAPLVERBA > 0) OR
           (VRETORNO(REG).VLLIQUIDO > 0)) THEN
          PERC_LUCROANTESAPLVERBA := (VRETORNO(REG).VLLUCROANTESAPLVERBA / VRETORNO(REG).VLLIQUIDO) * 100;
        ELSE
          PERC_LUCROANTESAPLVERBA := -100;
        END IF;
      ELSIF ROUND(VRETORNO(REG).VLLIQUIDO, 2) = 0 THEN
        PERC_LUCRO              := 0;
        PERC_LUCROANTESAPLVERBA := 0;
      ELSE
        PERC_LUCRO              := -100;
        PERC_LUCROANTESAPLVERBA := -100;
      END IF;
    ELSE
      IF ROUND(VRETORNO(REG).VLVENDA, 2) <> 0 THEN
        --PERC_LUCRO := (VRETORNO(REG).VLLUCRO / VRETORNO(REG).VLVENDA) * 100;
        IF VRETORNO(REG).VLVENDA > 0 THEN
          PERC_LUCRO := (VRETORNO(REG).VLLUCRO / VRETORNO(REG).VLVENDA) * 100;
        ELSE
          PERC_LUCRO := -100;
        END IF;

        IF VRETORNO(REG).VLVENDA > 0 THEN
          PERC_LUCROANTESAPLVERBA := (VRETORNO(REG).VLLUCROANTESAPLVERBA / VRETORNO(REG).VLVENDA) * 100;
        ELSE
          PERC_LUCROANTESAPLVERBA := -100;
        END IF;

      ELSIF ROUND(VRETORNO(REG).VLVENDA, 2) = 0 THEN
        PERC_LUCRO              := 0;
        PERC_LUCROANTESAPLVERBA := 0;
      ELSE
        PERC_LUCRO              := -100;
        PERC_LUCROANTESAPLVERBA := -100;
      END IF;

      IF VRETORNO(REG).CONDVENDA = 8 THEN
        PERC_LUCRO              := 0;
        PERC_LUCROANTESAPLVERBA := 0;
      END IF;
    END IF;

    /*Cálculo do percentual de meta */
    IF (VRETORNO(REG).VLMETA > 0) AND
       (VRETORNO(REG).VLMETA IS NOT NULL) THEN
      IF P_META = 0 THEN
        PERC_META := 100 -
                     (((VRETORNO(REG).VLMETA - VRETORNO(REG).VLVENDA) / VRETORNO(REG).VLMETA) * 100);
      ELSE
        PERC_META := 100 -
                     (((VRETORNO(REG).VLMETA -
                      (VRETORNO(REG).VLVENDA - VRETORNO(REG).VLDEVOLUCAO - VRETORNO(REG).VLDEVOLAVULSAI)) / VRETORNO(REG).VLMETA) * 100);
      END IF;
    ELSE
      PERC_META := 0;
    END IF;

    /* Cálculo Ticket MÃ©dio*/
    TKTMEDIO := 0;

    IF ((P_TIPOPESQUISA = 21) OR (P_TIPOPESQUISA = 23) OR (P_TIPOPESQUISA = 24)) AND
       VRETORNO(REG).CONTADOR > 0 THEN
      TKTMEDIO := VLVENDATOT / VRETORNO(REG).CONTADOR;
    ELSIF (P_TIPOPESQUISA = 3) AND
          (VRETORNO(REG).QTVENDA > 0) THEN
      TKTMEDIO := VRETORNO(REG).VLVENDA / VRETORNO(REG).QTVENDA;
    ELSIF (P_TIPOPESQUISA = 4) AND
          (VRETORNO(REG).CONTADOR > 0) THEN
      TKTMEDIO := VRETORNO(REG).VLVENDA / VRETORNO(REG).CONTADOR;
    END IF;

    /*Cálculo do valor de venda mÃ©dia pela qtde. de cliente*/
    IF (VRETORNO(REG).QTCLIENTE IS NOT NULL) AND
       (VRETORNO(REG).QTCLIENTE <> 0) THEN
      VLMEDIOCLI := VRETORNO(REG).VLVENDA / VRETORNO(REG).QTCLIENTE;
    ELSE
      VLMEDIOCLI := 0;
    END IF;

    IF P_TIPOPESQUISA = 21 THEN
      V_SQL4 := ' SELECT COUNT(USUARI.CODCLI) TOTCLIATIVOS FROM((SELECT PCCLIENT.CODCLI
       FROM PCCLIENT, PCUSUARI WHERE PCUSUARI.CODUSUR = PCCLIENT.CODUSUR1 ';

      IF P_CODFILIAL IS NOT NULL THEN
        V_SQL4 := V_SQL4 || ' AND NVL(PCUSUARI.CODFILIAL,''99'') IN (TO_CHAR(99), ' ||
                  P_CODFILIAL || ') ';
      END IF;

      --Filtros incluidos na rotina 111

      IF P_FILTROCODGERENTE IS NOT NULL THEN
        V_SQL4 := V_SQL4 ||
                  ' AND PCUSUARI.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR
                                                                FROM PCSUPERV
                                                               WHERE PCSUPERV.CODGERENTE  IN (' ||
                  P_FILTROCODGERENTE || ')' || ' ) ';
      END IF;

      IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
        V_SQL4 := V_SQL4 || ' AND PCUSUARI.CODSUPERVISOR IN (' ||
                  P_FILTROCODSUPERVISOR || ')';
      END IF;

      IF P_FILTROCODUSUR IS NOT NULL THEN
        V_SQL4 := V_SQL4 || ' AND PCUSUARI.CODUSUR IN (' || P_FILTROCODUSUR || ')';
      END IF;

      -- Fim dos filtros

      V_SQL4 := V_SQL4 ||
                ' AND PCCLIENT.DTEXCLUSAO IS NULL AND (SELECT TRUNC(SYSDATE) -
         NUMDIASCLIINATIV FROM PCCONSUM) <= PCCLIENT.DTULTCOMP) UNION
         (SELECT PCCLIENT.CODCLI FROM PCCLIENT, PCUSUARI WHERE PCUSUARI.CODUSUR = PCCLIENT.CODUSUR2 ';

      IF P_CODFILIAL IS NOT NULL THEN
        V_SQL4 := V_SQL4 || ' AND NVL(PCUSUARI.CODFILIAL,''99'') IN (TO_CHAR(99), ' ||
                  P_CODFILIAL || ') ';
      END IF;

      --Filtros incluidos na rotina 111

      IF P_FILTROCODGERENTE IS NOT NULL THEN
        V_SQL4 := V_SQL4 ||
                  ' AND
                       PCUSUARI.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' ||
                  P_FILTROCODGERENTE || ')' || ' ) ';
      END IF;

      IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
        V_SQL4 := V_SQL4 || ' AND PCUSUARI.CODSUPERVISOR IN (' ||
                  P_FILTROCODSUPERVISOR || ')';
      END IF;

      IF P_FILTROCODUSUR IS NOT NULL THEN
        V_SQL4 := V_SQL4 || ' AND PCUSUARI.CODUSUR IN (' || P_FILTROCODUSUR || ')';
      END IF;

      --fim filtros rotina 111

      V_SQL4 := V_SQL4 || ' AND PCCLIENT.DTEXCLUSAO IS NULL AND (SELECT TRUNC(SYSDATE) -
         NUMDIASCLIINATIV FROM PCCONSUM) <= PCCLIENT.DTULTCOMP) UNION
         (SELECT PCCLIENT.CODCLI FROM PCUSURCLI, PCCLIENT, PCUSUARI WHERE PCUSURCLI.CODUSUR = PCUSUARI.CODUSUR
         AND PCUSURCLI.CODCLI = PCCLIENT.CODCLI ';

      IF P_CODFILIAL IS NOT NULL THEN
        V_SQL4 := V_SQL4 || ' AND NVL(PCUSUARI.CODFILIAL,''99'') IN (TO_CHAR(99), ' ||
                  P_CODFILIAL || ') ';
      END IF;

      --Filtros incluidos na rotina 111

      IF P_FILTROCODGERENTE IS NOT NULL THEN
        V_SQL4 := V_SQL4 || ' AND PCUSUARI.CODSUPERVISOR IN ( SELECT PCSUPERV.CODSUPERVISOR FROM
          PCSUPERV WHERE PCSUPERV.CODGERENTE  IN (' ||
                  P_FILTROCODGERENTE || ')' || ' ) ';
      END IF;

      IF P_FILTROCODSUPERVISOR IS NOT NULL THEN
        V_SQL4 := V_SQL4 || ' AND PCUSUARI.CODSUPERVISOR IN (' ||
                  P_FILTROCODSUPERVISOR || ')';
      END IF;

      IF P_FILTROCODUSUR IS NOT NULL THEN
        V_SQL4 := V_SQL4 || ' AND PCUSUARI.CODUSUR IN (' || P_FILTROCODUSUR || ')';
      END IF;

      --fim filtros rotina 111

      V_SQL4 := V_SQL4 ||
                ' AND PCCLIENT.DTEXCLUSAO IS NULL AND (SELECT TRUNC(SYSDATE) -
        NUMDIASCLIINATIV FROM PCCONSUM) <= PCCLIENT.DTULTCOMP)) USUARI ';

      OPEN L_CURSOR_CLIENT FOR TO_CHAR(V_SQL4);

      LOOP
        FETCH L_CURSOR_CLIENT
          INTO CLI;

        EXIT WHEN L_CURSOR_CLIENT%NOTFOUND;
        TOTCLIATIVOS := CLI.TOTCLIENTESATIVOS;
      END LOOP;

      CLOSE L_CURSOR_CLIENT;

      COBERTURACLI := (VRETORNO(REG).QTCLIPOS / VRETORNO(REG).QTCLIENTE) * 100;
    ELSE
      COBERTURACLI := 0;
      TOTCLIATIVOS := 0;
    END IF;

    VALOR_NOTAS := 0;

    /*      V_SQL := ' SELECT SUM(VENDAS.VLVENDA) VALOR_NOTAS FROM (' || V_SQL_GERAL ||') VENDAS
    WHERE VENDAS.NUMTRANSVENDA IN (' || TRIM(NVL(VRETORNO(REG).LISTA_NUMTRANSVENDA,'-1')) || ')';*/

    /*   EXECUTE IMMEDIATE V_SQL
    INTO VALOR_NOTAS;*/

    VRETORNO(REG).VLDEVOLAVULSA := VLDEVOLAVULSA;
    VRETORNO(REG).PERCVENDA := PERC_VENDA;
    VRETORNO(REG).PERCLUCRO := PERC_LUCRO;
    VRETORNO(REG).PERCMETA := PERC_META;
    VRETORNO(REG).PERCVENDAPF := PERC_VENDA_PF;
    VRETORNO(REG).PERCVENDAPJ := PERC_VENDA_PJ;
    VRETORNO(REG).PERCPARTTOTAL := PERC_PART_TOTAL;
    VRETORNO(REG).TKTMEDIO := TKTMEDIO;
    VRETORNO(REG).VLMEDIOCLI := VLMEDIOCLI;
    VRETORNO(REG).TOTCLIATIVOS := TOTCLIATIVOS;
    VRETORNO(REG).COBERTURACLI := COBERTURACLI;
    VRETORNO(REG).QTTOTCANCELADA := QTTOTCANCELADA;
    VRETORNO(REG).PERCBONIFIC := PERC_BONIF;
    VRETORNO(REG).PERCDIF := PERC_DIF;
    VRETORNO(REG).PERCLUCROANTESAPLVERBA := PERC_LUCROANTESAPLVERBA;

  END LOOP;
EXCEPTION
  WHEN INVALID_CURSOR THEN
    RAISE_APPLICATION_ERROR(-20002,
                            ' Erro na execução do cursor. Pesquisa - ' +
                            TO_CHAR(P_TIPOPESQUISA));
  WHEN OTHERS THEN
    RAISE_APPLICATION_ERROR(-20002,
                            ' Erro. Pesquisa - ' + TO_CHAR(P_TIPOPESQUISA));
END;

CLOSE L_CURSOR;

RETURN VRETORNO;
END;
